-- Poems batch 87
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('a9887f60-e00c-46f6-8c0a-cb97e486b4c0','送蘇判院赴江東辟','朱翌','宋','宋诗','song-poetry','','[]','春風桃李正開花，客路江山亦可嘉。',64,'全唐诗/poet.song.108000.json','["春風桃李正開花，客路江山亦可嘉。", "白鷺洲前浪山起，烏衣巷口夕陽斜。", "一星終矣君重往，四壁蕭然我獨嗟。", "元祐子孫今用盡，如公豈合在天涯。"]'),
('1b126cab-3a51-4e87-958e-bc69d72342ad','端午登郡城得白菊一枝','朱翌','宋','宋诗','song-poetry','','[]','天外飛雲結晚陰，城頭清吹度虛襟。',64,'全唐诗/poet.song.108000.json','["天外飛雲結晚陰，城頭清吹度虛襟。", "江山已定南居計，魚鳥休撩北去心。", "菊早有花千葉嫩，薄香釀酒十分斟。", "歸來卧聽黄昏雨，與我尤親一布衾。"]'),
('b8136b12-e9af-4ace-b0d1-27a18efbccef','寄賀子忱','朱翌','宋','宋诗','song-poetry','','[]','昔歲裁詩遠送君，知君未可作閑人。',64,'全唐诗/poet.song.108000.json','["昔歲裁詩遠送君，知君未可作閑人。", "那知半紀重相見，全似當時只話貧。", "推轂向來誰盡力，彈冠從此不謀身。", "想當六月苕溪上，萬頃荷花一幅巾。"]'),
('264f159c-670a-40d2-a60c-4d1984959114','寄婺州歐卿德孺','朱翌','宋','宋诗','song-poetry','','[]','醉翁遺迹遍江湖，何事東遊不到吳。',64,'全唐诗/poet.song.108000.json','["醉翁遺迹遍江湖，何事東遊不到吳。", "遂使山川有遺恨，却看孫子步清塗。", "沈郎带減傳千古，婺女星高近六符。", "簪筆便當歸從上，蓋藍鞍錦照天衢。"]'),
('73669a73-b6ab-477f-be7f-f1863d7a868e','與林大夫謝靈壽杖','朱翌','宋','宋诗','song-poetry','','[]','萬木山中美木成，古今靈壽得嘉名。',64,'全唐诗/poet.song.108000.json','["萬木山中美木成，古今靈壽得嘉名。", "龍鱗未測他年化，蝸角先從每節生。", "禪擬問來須便打，醉思吟後不妨行。", "使君有惠憐衰薾，欲報慚非藻思清。"]'),
('9fba0d53-eb7c-4477-98f7-00f18c12051f','以靈壽杖寄汪內翰','朱翌','宋','宋诗','song-poetry','','["\u8861\u5c71"]','一枝靈木堅多節，千里逢人寄永州。',64,'全唐诗/poet.song.108000.json','["一枝靈木堅多節，千里逢人寄永州。", "賜出漢宮尊子夏，封當大縣慶邳侯。", "衡山雲散迎歸騎，湘浦春晴更順流。", "欲往從公無羽翼，請携上座別愚丘。"]'),
('53c7c166-b1c9-4724-9d77-ce5e2b9ebc26','喜見白髮詩','朱翌','宋','宋诗','song-poetry','','[]','種種年來漸滿簪，兒童環視語相驚。',64,'全唐诗/poet.song.108000.json','["種種年來漸滿簪，兒童環視語相驚。", "故人大半黑頭死，老子何妨白髮生。", "彈鑷不須誇手熟，著冠猶喜覺頭輕。", "元無粉黛居閒屋，任爾星星易數莖。"]'),
('07c1d874-dfa9-4675-a398-91b225343f49','寄方立義方曾在詩','朱翌','宋','宋诗','song-poetry','','[]','西南一柱力擎天，笞鳳鞭鸞下散仙。',64,'全唐诗/poet.song.108000.json','["西南一柱力擎天，笞鳳鞭鸞下散仙。", "不憤狐狸成窟穴，亦知滄海變桑田。", "夢歸丁令鶴飛去，念舊徐公榻尚懸。", "我是鄉人君是客，興言及此淚如濺。"]'),
('f1d12e15-e58b-4fb4-ad34-cf6db37da491','寄向伯恭','朱翌','宋','宋诗','song-poetry','','[]','天竺山前昔據鞍，帽峩高屋古袍寬。',64,'全唐诗/poet.song.108000.json','["天竺山前昔據鞍，帽峩高屋古袍寬。", "髮雖比舊十分白，心有憂時一寸丹。", "雲路正看鳴劍履，君門可早掛衣冠。", "爲公試草薌林傳，歸日來紉九畹蘭。"]'),
('e66a7ffc-e5a5-45d7-a27c-0e1ab4c3bfed','次韻江子我病起','朱翌','宋','宋诗','song-poetry','','[]','食不下咽當奈何，千金不惜聘秦和。',64,'全唐诗/poet.song.108000.json','["食不下咽當奈何，千金不惜聘秦和。", "則知有我聊示病，旁若無人正浩歌。", "薄雨過牆醒檻竹，西風吹暑下庭柯。", "但令一局消長日，且樂眼前休問他。"]'),
('3b36c833-d01c-4a6f-a811-b144340b2763','淵明以正月五日遊斜川時年五十予以正月二日遊曹源菴年五十有二矣慨然書示同行','朱翌','宋','宋诗','song-poetry','','[]','城裏喧呼子不貪，乃能從我就僧談。',64,'全唐诗/poet.song.108000.json','["城裏喧呼子不貪，乃能從我就僧談。", "平明且喜風收潤，仰視只愁雲向南。", "靖節使年慚過二，斜川推日在前三。", "吾生大似僧行脚，好問真空覓住庵。"]'),
('4dd62967-faca-4288-beec-1575ac217b1b','寄方允迪','朱翌','宋','宋诗','song-poetry','','[]','山陰興盡晚船催，猿鶴歡迎入翠微。',64,'全唐诗/poet.song.108000.json','["山陰興盡晚船催，猿鶴歡迎入翠微。", "爲信在山名遠志，便令滿篋寄當歸。", "一牀獨設空諸有，三徑就荒知昨非。", "更頼仲容賢莫敵，竹林從此倍光輝。"]'),
('ce5d0e60-a9b7-481a-8dab-4911263b82c3','雨止讀陶詩有感','朱翌','宋','宋诗','song-poetry','','[]','涓涓泉溜木欣欣，便覺居閑思不羣。',64,'全唐诗/poet.song.108000.json','["涓涓泉溜木欣欣，便覺居閑思不羣。", "快覩朝霞開宿霧，少休時雨靄停雲。", "無弦琴上宮商足，有酒篇中醉醒分。", "誰是知音誰可酌，置琴罷酒對爐熏。"]'),
('3179f92c-0a92-4ad7-86c5-82a1c4e13fa3','頃種柏假山中黄憲相訪見之後八年黄憲復持節來柏已長大','朱翌','宋','宋诗','song-poetry','','[]','兩石之間一寸栽，與君坐看斸莓苔。',64,'全唐诗/poet.song.108000.json','["兩石之間一寸栽，與君坐看斸莓苔。", "蒼官閲世猶如此，歡伯喚人歸去來。", "飄放又瞻新斧繡，光華重照舊池臺。", "他時左紐紋生後，更望西遊老子回。"]'),
('e6ae37e2-afee-4b15-8c32-5e7db26261e9','與羅教授飯園中種梔子','朱翌','宋','宋诗','song-poetry','','[]','園木交陰正可觀，壺觴隨分却成歡。',64,'全唐诗/poet.song.108000.json','["園木交陰正可觀，壺觴隨分却成歡。", "綠錢流地雨當足，飛絮暖空春不寒。", "雪綴酴醾緣屋角，香移薝蔔近欄干。", "與君細說爐亭話，强對檳榔蔞菜槃。"]'),
('db198902-a19a-402d-adcd-f1146e664e6e','與郭侯飲園中','朱翌','宋','宋诗','song-poetry','','[]','穠李晨興著縞裙，酴醾首出上瑶簪。',64,'全唐诗/poet.song.108000.json','["穠李晨興著縞裙，酴醾首出上瑶簪。", "此時老子興不淺，旦日將軍幸早臨。", "敵手對棋消晝永，中心聞射隔牆陰。", "春生夜甕蓬萊綠，酌我無多勸客深。"]'),
('2919878e-6620-42b5-af59-9dc748f783e7','華幹携茶入園晚坐柔桑下','朱翌','宋','宋诗','song-poetry','','[]','光穿兩脚間彤霞，聲急城頭集暮鴉。',64,'全唐诗/poet.song.108000.json','["光穿兩脚間彤霞，聲急城頭集暮鴉。", "且與鳳雛桑下坐，共烹龍焙雨前茶。", "的中薏嫩蓮新採，筍上竿成竹已斜。", "讀得齊民書熟爛，把鋤今作老生涯。"]'),
('2c92ca1a-4137-4ca3-9bd8-4d968a33ae3a','喜雨欲行園','朱翌','宋','宋诗','song-poetry','','[]','南風轉北遂爲霖，倒掩書帷坐累茵。',64,'全唐诗/poet.song.108000.json','["南風轉北遂爲霖，倒掩書帷坐累茵。", "洗沐江山三尺雨，莊嚴天地十分春。", "猿吟鶴舞圖雙引，酒社詩壇待五申。", "說我小園增秀潤，便思徐步轉城闉。"]'),
('8cb8d9e6-7c49-4f16-9e98-94524a8b8f6e','園中示客','朱翌','宋','宋诗','song-poetry','','[]','風急梳松墮碧釵，雨多及榻長青苔。',64,'全唐诗/poet.song.108000.json','["風急梳松墮碧釵，雨多及榻長青苔。", "趁虛阿段阿稽去，挾冊宗文宗武來。", "不用張羅知寂寞，恐妨飛鳥樂徘徊。", "侵尋老矣成何事，一日華嚴一卷開。"]'),
('25689db0-9c1a-432c-bcc7-653da7743893','園中即事','朱翌','宋','宋诗','song-poetry','','[]','出山道士在家僧，晚誦儒書早佛經。',64,'全唐诗/poet.song.108000.json','["出山道士在家僧，晚誦儒書早佛經。", "灰盡此心猶木偶，掃除往事送芻靈。", "花邊過客蜂旁午，溪上良時鷺適丁。", "一到菊坡分品目，玉盤盂可次金鈴。"]'),
('afc83c4d-ec86-4851-8253-dc913ef242c8','至後飯客','朱翌','宋','宋诗','song-poetry','','[]','新陽爲我解憂端，梅破南枝雪造寒。',64,'全唐诗/poet.song.108000.json','["新陽爲我解憂端，梅破南枝雪造寒。", "繡刺五紋添日刻，餠炊十字薦春盤。", "遣排百念有時盡，邂逅一尊無限歡。", "更待小晴拏小艇，蘭漿重酹子陵灘。"]'),
('03323232-3e35-42b9-a20c-bc603ebc87e9','送羅巨濟北歸','朱翌','宋','宋诗','song-poetry','','[]','君才可從六龍飛，便合超騰向日畿。',64,'全唐诗/poet.song.108000.json','["君才可從六龍飛，便合超騰向日畿。", "曾使諸生館下立，又騎一馬醉中歸。", "江山得助雲蒸筆，桃李不言春上機。", "歸去來園花似海，子行吾且閉柴扉。"]'),
('79f327f2-9f86-4f01-819d-4756ff31bc6a','寄仲彌性祝子權','朱翌','宋','宋诗','song-poetry','','[]','博士曾瞻穆穆光，賢良猶抱漢文章。',64,'全唐诗/poet.song.108000.json','["博士曾瞻穆穆光，賢良猶抱漢文章。", "江山不隔夢千里，鴻雁欲歸書數行。", "蠅變豈能分白黑，木災初未有青黄。", "逡巡歲晚成何事，捧腹看儺驅不祥。"]'),
('a3b903ef-17ce-4e4f-b61a-825504a8241d','遊江醫園江避賊歸四年花木皆再種已開花著子矣','朱翌','宋','宋诗','song-poetry','','[]','避地歸來四閲春，春來草木盡青青。',64,'全唐诗/poet.song.108000.json','["避地歸來四閲春，春來草木盡青青。", "桃花暖逐桃花水，竹葉光臨竹葉瓶。", "閉戶自求安樂法，活人時說衛生經。", "移床却就溪邊坐，照我新生白髮星。"]'),
('b0710ad7-6473-4d8f-a66b-2640542fa166','遣興','朱翌','宋','宋诗','song-poetry','','[]','衡門秋到總堪悲，荷折蒲荒不整齊。',64,'全唐诗/poet.song.108000.json','["衡門秋到總堪悲，荷折蒲荒不整齊。", "但喜風前無立豹，亦知砌下有蹲鴟。", "吾徒老矣成何事，生理茫然更久稽。", "清凈無風天雨已，山前山後且扶藜。"]'),
('94f87944-1927-4324-b27d-c0a70fa27096','雨後告春亭飯客亭下荷花皆爲釀家入麴久雨頹垣方議栽竹代之','朱翌','宋','宋诗','song-poetry','','[]','半夜簷聲挾北風，平明賀雨走諸翁。',64,'全唐诗/poet.song.108000.json','["半夜簷聲挾北風，平明賀雨走諸翁。", "山人起向水亭坐，野膳不求行帳豐。", "麴糵有香蓮不死，藩籬無闕竹成功。", "閑中自有閑生理，促辦牛衣戴此公。"]'),
('3e566751-ba86-4393-8b38-c4e42081852e','有惠益母粉及當歸者','朱翌','宋','宋诗','song-poetry','','[]','多病年來歎早衰，試憑草木爲扶微。',64,'全唐诗/poet.song.108000.json','["多病年來歎早衰，試憑草木爲扶微。", "關心藥裹知多少，繫肘方書識是非。", "曾子定應憐益母，曹公端解寄當歸。", "從今洗面饒光澤，血氣仍充舊带圍。"]'),
('9d1eac83-dbe6-489d-9faa-7223e9191724','送崔若礪令河源','朱翌','宋','宋诗','song-poetry','','[]','雙鳬飛出九重關，带得中原氣象還。',64,'全唐诗/poet.song.108000.json','["雙鳬飛出九重關，带得中原氣象還。", "抵死欲留之子住，吹笙要伴老夫閑。", "草荒白鶴峰前宅，雲散黄龍洞口山。", "茉莉素馨聞已熟，妙香從此賸熏班。"]'),
('b1917332-7624-4eea-865c-8063029668c8','靜坐','朱翌','宋','宋诗','song-poetry','','[]','年來豈復爲秋悲，靜裏端能閲化機。',64,'全唐诗/poet.song.108000.json','["年來豈復爲秋悲，靜裏端能閲化機。", "風引饑烏將子下，雨催羣蟻運糧歸。", "畧無車馬閑尤好，粗有詩書家亦肥。", "更得干戈漸衰息，不辭長採首山薇。"]'),
('785493ce-5955-474c-9cab-e39c5f8f1e85','送胡德輝','朱翌','宋','宋诗','song-poetry','','[]','抗章乞得清凉國，已是無心瑞錦窠。',64,'全唐诗/poet.song.108000.json','["抗章乞得清凉國，已是無心瑞錦窠。", "誰去自追戲下信，時來寧免禁中頗。", "三吳春盡天連海，四月梅黄雨壓蓑。", "倘有新詩求共和，莫辭一騎送羊何。"]'),
('8e8d810e-34f6-449c-ab68-4f59c7bcb7e5','送果州邵公濟分韻得其字','朱翌','宋','宋诗','song-poetry','','[]','蓬萊清暑按行歸，却向西南萬里馳。',64,'全唐诗/poet.song.108000.json','["蓬萊清暑按行歸，却向西南萬里馳。", "郡繼尊君家有法，學傳乃祖世無師。", "曹劉牆短自今日，班馬香濃如昔時。", "青士在旁知別語，夕陽回首更凄其。"]'),
('83eb16fe-c01f-4939-9713-75b4a36ec7fc','東津送方務德','朱翌','宋','宋诗','song-poetry','','[]','一年癡雨令人瘦，三日佳晴送子回。',64,'全唐诗/poet.song.108000.json','["一年癡雨令人瘦，三日佳晴送子回。", "何以贈之青玉案，我姑酌彼黄金罍。", "尋春出郭非聊爾，下水行舟亦快哉。", "小試平生釣魚手，老夫合住子陵臺。"]'),
('7860c172-57fc-4335-9836-add78eb728c5','寄鸕鷀源方允迪江子我','朱翌','宋','宋诗','song-poetry','','[]','世間豺虎正爭岐，隠去何妨九曲迷。',64,'全唐诗/poet.song.108000.json','["世間豺虎正爭岐，隠去何妨九曲迷。", "懷人夢到北山北，卜鄰意欲西枝西。", "麥雲已有飽氣象，梅雨又煩詩品題。", "他日籃輿入源去，尚期趺坐對青藜。"]'),
('11aa4a92-eb80-499a-bd1b-640bc3c0c30c','喜雪  其一','朱翌','宋','宋诗','song-poetry','','[]','待雪多年久未逢，茲辰如望故人風。',64,'全唐诗/poet.song.108000.json','["待雪多年久未逢，茲辰如望故人風。", "稍添松頂三分白，獨露蕉心一寸紅。", "泥尾可能留雁使，豚蹄何敢謝龍工。", "不如借取公家氅，著向飛樓縹緲中。"]'),
('8002b12d-3954-4b05-a99c-1381d39c952e','喜雪  其二','朱翌','宋','宋诗','song-poetry','','[]','今年吉利好人逢，萬玉妃來各馭風。',64,'全唐诗/poet.song.108000.json','["今年吉利好人逢，萬玉妃來各馭風。", "客坐暖浮茶乳白，夜堂春動燭花紅。", "心存帝所元非夢，化出天城不用工。", "却怪浩歌韓吏部，巧分垤處與㘭中。"]'),
('2bb3ded2-141e-4822-a9a4-e354a93b14fd','喜雪  其三','朱翌','宋','宋诗','song-poetry','','[]','嘉瑞真成一旦逢，寄箋天下託鵬風。',64,'全唐诗/poet.song.108000.json','["嘉瑞真成一旦逢，寄箋天下託鵬風。", "分無侑坐歌眉綠，但有挑蔬凍指紅。", "畫史莫傳飛舞勢，詩人俱盡琢磨工。", "此間不見乾坤妙，妙在竹扉山崦中。"]'),
('337d25f0-c519-4d83-a5af-8290d02a22e7','分水縣舍夜遇大雪','朱翌','宋','宋诗','song-poetry','','[]','揮扇解衣真早計，果然一夕變春陰。',64,'全唐诗/poet.song.108000.json','["揮扇解衣真早計，果然一夕變春陰。", "屋頭瓦裂風掀戶，媿上珠跳雪滿衾。", "我自不妨高枕卧，人今更有惜花心。", "此行特地非乘興，明日扁舟興亦深。"]'),
('32a49810-91fd-4b5e-bd4f-2bf53678781b','元日會凌季文家','朱翌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','柏葉椒盤巧試新，大呼珠履集華茵。',64,'全唐诗/poet.song.108000.json','["柏葉椒盤巧試新，大呼珠履集華茵。", "香醪滿勸橘爲盞，紅燭未消梅寫真。", "荔子雙頭歸有遺，天花六出靜無塵。", "稍晴便合西湖去，尋遍山房洞戶春。"]'),
('98db9bee-8dd6-4691-ae7e-23fa7ec102c3','春遊','朱翌','宋','宋诗','song-poetry','','[]','久不出門心已灰，佳晴作意苦相催。',64,'全唐诗/poet.song.108000.json','["久不出門心已灰，佳晴作意苦相催。", "鶑花世界共遊戲，竹石弟兄仍往來。", "心有所之無遠近，興雖已盡更徘徊。", "江邊漁父傷時切，得遇郎君笑口開。"]'),
('730d12c5-b472-46b6-9e08-46b4782e7ebe','示同會','朱翌','宋','宋诗','song-poetry','','[]','無奈春寒老不禁，喜看晴日上窗櫺。',64,'全唐诗/poet.song.108000.json','["無奈春寒老不禁，喜看晴日上窗櫺。", "羣花半露乾坤巧，百刻平分晝夜停。", "拄杖有時挑菜甲，桔槔無復問畦丁。", "逢春不出何爲者，衆醉誰知可獨醒。"]'),
('867aeba2-ca01-46f0-ba96-e923d60f9822','簡范信中','朱翌','宋','宋诗','song-poetry','','[]','天下皆聞公子賢，輕裾長袖更爭妍。',64,'全唐诗/poet.song.108000.json','["天下皆聞公子賢，輕裾長袖更爭妍。", "青春自向東山好，下客空懷代舍遷。", "生活不甘詩冷淡，年光專用酒留連。", "直須萬里騎黄鵠，俯仰安能在一椽。"]'),
('d2220175-e434-4704-8a1c-0794048a196b','正月十四日西湖留別同舍','朱翌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','背淮轅楚過三吳，鐵軸膏輪每疾驅。',64,'全唐诗/poet.song.108000.json','["背淮轅楚過三吳，鐵軸膏輪每疾驅。", "千里未能歸北客，一觴來此別西湖。", "門門燈火動今夜，步步溪山迎故吾。", "明日歸潮君看取，浪花堆裏嘯檣烏。"]'),
('70384d06-cf2b-4dc8-a61b-2965bd8b2ad4','正月二十日過江氏園','朱翌','宋','宋诗','song-poetry','','[]','宛宛橋虹卧碧漣，深深古屋背長川。',64,'全唐诗/poet.song.108000.json','["宛宛橋虹卧碧漣，深深古屋背長川。", "園官送菜無虛日，溪友留魚不問錢。", "歷數舊交俱老矣，及時行樂且欣然。", "梅花更有黄千葉，携取一杯花下傳。"]'),
('0c269742-4483-4d11-a7be-1727e00cf65b','三月五日游劉光世園','朱翌','宋','宋诗','song-poetry','','[]','南高峰下訪餘春，霽草浮光暖更薰。',64,'全唐诗/poet.song.108000.json','["南高峰下訪餘春，霽草浮光暖更薰。", "日轉暮山添著色，風旋湖水作回紋。", "飄零大士天花雨，驚顧將軍畫棟雲。", "興盡不須呼麴友，他時來飯一甌芹。"]'),
('5a314145-8779-4885-81f5-3e1745edbbec','閏月四日大風出靈鷲捕魚具鱠且約冬間再集','朱翌','宋','宋诗','song-poetry','','[]','西北雲收廓太虛，東南風急放船初。',64,'全唐诗/poet.song.108000.json','["西北雲收廓太虛，東南風急放船初。", "冬深更許侯設鱠，地遠不譏公矢魚。", "白小未容登燕俎，紅鮮忽已間嘉蔬。", "重生鱗鬣浮江去，盡是先生所棄餘。"]'),
('e532b7b6-eb25-46ca-b029-00c761240541','陪董令升西湖閲競渡  其一','朱翌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','馳波鬭艦疾輕鴻，歌鼓喧天保歲豐。',64,'全唐诗/poet.song.108000.json','["馳波鬭艦疾輕鴻，歌鼓喧天保歲豐。", "直面北風吹雨過，卷簾斜日照樓紅。", "吳兒戲水用長技，太守行春如醉翁。", "社稷中興豈無日，羣魚躍水正飛空。"]'),
('59d78f1d-fd6d-4f8f-9bd2-881646830626','陪董令升西湖閲競渡  其二','朱翌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','行樂何妨縱水嬉，勸耕猶喜及花時。',64,'全唐诗/poet.song.108000.json','["行樂何妨縱水嬉，勸耕猶喜及花時。", "風和官柳未飄絮，綠滿園桑無附枝。", "訓練指麾談笑裏，清凉瀟洒古今宜。", "西溪雨足歸舟穩，會送高帆入鳳池。"]'),
('3280d687-f4c6-4223-8464-3e8b2f7badc6','三衢胡定愍祠詩','朱翌','宋','宋诗','song-poetry','','[]','把酒論詩建業城，三年金石見交情。',64,'全唐诗/poet.song.108000.json','["把酒論詩建業城，三年金石見交情。", "羅池忽待中流泊，姑蔑應無劇雨傾。", "直道豈知人負我，英姿如在死猶生。", "鑪香銷盡叢祠晚，獨對西風淚臆橫。"]'),
('c3cbe354-c2ab-4968-9a90-d5aa7cdf8c91','買田潼溪','朱翌','宋','宋诗','song-poetry','','[]','求田得處便成家，笑爲汙邪祝滿車。',64,'全唐诗/poet.song.108000.json','["求田得處便成家，笑爲汙邪祝滿車。", "潄石枕流新夢想，带牛佩犢老生涯。", "歌成但可相舂杵，客到莫嫌炊飯砂。", "祭罷土龍春雨應，穩騎秧馬一鞭斜。"]'),
('2c07325f-deea-45a3-b672-d7273522d8e5','過烏龍嶺','朱翌','宋','宋诗','song-poetry','','[]','羣山低首避烏龍，行道驚看翠倚空。',64,'全唐诗/poet.song.108000.json','["羣山低首避烏龍，行道驚看翠倚空。", "地設中原如此險，人無鬭志若爲功。", "九重頗覺天門近，一卒能當蜀道雄。", "細酌粉泉庵下水，泠然歸去御剛風。"]'),
('06ee1b8b-6c34-46b6-83a6-0d650de6d9be','晚晴步謁楊令於烏龍寺','朱翌','宋','宋诗','song-poetry','','[]','舉頭廓廓見晴虛，山色秋光得自如。',64,'全唐诗/poet.song.108000.json','["舉頭廓廓見晴虛，山色秋光得自如。", "杖履可行三里近，斧斤不赦萬松疏。", "上人坐設刀圭飲，乃祖家無擔石儲。", "語罷寒溫晚歸去，相逢應不問遷除。"]'),
('12326041-033f-4632-bb82-ad41bf556bff','離臨安日范伯達送茶約至釣臺烹之正月十八日宿臺下兼簡務德','朱翌','宋','宋诗','song-poetry','','[]','過盡長灘喚落帆，舟人取火上高巖。',64,'全唐诗/poet.song.108000.json','["過盡長灘喚落帆，舟人取火上高巖。", "已携敗絮來投宿，記有珍茶旋啟緘。", "忽憶住時同短𦩘，要須于此辦長鑱。", "可憐一夜梅花雨，點滴猶隨舳尾銜。"]'),
('2fe976c0-473e-43a1-9b60-81a3c9aed85a','釣臺觀新刻范文正碑','朱翌','宋','宋诗','song-poetry','','[]','日角曈曈上蔡陽，有星飛去避餘光。',64,'全唐诗/poet.song.108000.json','["日角曈曈上蔡陽，有星飛去避餘光。", "東西怵迫謝新進，南北逍遥樂故鄉。", "載刻廟碑求琰琬，一新祠宇照滄浪。", "使君著意敦風俗，更作高堂牓卒章。"]'),
('c138d5ba-e42d-4b35-b601-71fd5c9d120a','競秀閣','朱翌','宋','宋诗','song-poetry','','[]','輞川遥展右丞圖，盤谷中藏李愿居。',64,'全唐诗/poet.song.108000.json','["輞川遥展右丞圖，盤谷中藏李愿居。", "龍睡潭深飛客櫂，鳳鳴枝老結吾廬。", "但令蠟屐去前齒，安用鴟夷託後車。", "西望子陵三十里，烟雲來往問何如。"]'),
('c6212f7b-7702-4464-870a-7fa9f6424340','遊玉泉  其一','朱翌','宋','宋诗','song-poetry','','[]','坡陀石上大紳垂，踞石跏趺世慮微。',64,'全唐诗/poet.song.108000.json','["坡陀石上大紳垂，踞石跏趺世慮微。", "奉引有春扶屐去，送歸生月带星稀。", "一時花木助歡笑，四顧風雲入指揮。", "是日乃書驚蟄節，鳴蛙已傍小池歸。"]'),
('2916d8f7-31de-458a-b70e-ffc9039f4e6f','遊玉泉  其二','朱翌','宋','宋诗','song-poetry','','[]','款段尋山不著鞭，每逢佳處且周旋。',64,'全唐诗/poet.song.108000.json','["款段尋山不著鞭，每逢佳處且周旋。", "生無一字誇金谷，喜與諸公會玉泉。", "雷轉正喧三級浪，紳垂直自九重天。", "有能庚伏留終日，大勝朝堂食萬錢。"]'),
('4dc52c84-ce2f-43d4-af5f-3f4025ccd389','立夏前一日登馬氏山亭','朱翌','宋','宋诗','song-poetry','','[]','百憂不到酒三行，萬事盡休棋一枰。',64,'全唐诗/poet.song.108000.json','["百憂不到酒三行，萬事盡休棋一枰。", "梅子未黄先著雨，櫻桃欲熟正防鶑。", "忽驚夏向明朝立，便恐春從此地更。", "數蝶飛來花寂寞，亂蛙鳴處水縱橫。"]'),
('32b7c56c-3b2a-46d3-92b2-e2f1cfa0213c','夏日登葉氏山亭','朱翌','宋','宋诗','song-poetry','','[]','雲氣向曉不待族，風伯忽來吹使醨。',64,'全唐诗/poet.song.108000.json','["雲氣向曉不待族，風伯忽來吹使醨。", "溪南溪北半篙碧，荷葉荷花一段奇。", "旋扣柴荆行問道，少休松檻坐移時。", "淵明志廣桑麻長，此語勿傳朝市知。"]'),
('8f52538c-7176-439b-bf8a-b4e4a00da09f','題翠波亭','朱翌','宋','宋诗','song-poetry','','[]','天垂疊巘翠相交，風展文漪碧半篙。',64,'全唐诗/poet.song.108000.json','["天垂疊巘翠相交，風展文漪碧半篙。", "勝日難逢宜樂此，好山多買不爲饕。", "了無歎息同登峴，忽有會心如在濠。", "更看溪光山色裏，紅霞蒸起萬株桃。"]'),
('17dda4cf-934f-45c6-b688-d54e4789fe94','七夕日遊仙人洞','朱翌','宋','宋诗','song-poetry','','[]','蟬引秋風上桂枝，登山臨水不勝悲。',64,'全唐诗/poet.song.108000.json','["蟬引秋風上桂枝，登山臨水不勝悲。", "獸蹲虎踞石見怪，天劃神刓洞出奇。", "無復碧藍雞刷羽，空餘青栗蝟攢皮。", "儻分衲子三椽屋，當與仙人五日期。"]'),
('a345558f-93db-4705-9b4f-1281bb8af21e','晨光亭夾徑草深庵僧澄鋤去之將種桃李','朱翌','宋','宋诗','song-poetry','','[]','徑荒隨處長蓬蒿，忽告通幽且盡薅。',64,'全唐诗/poet.song.108000.json','["徑荒隨處長蓬蒿，忽告通幽且盡薅。", "已問花翁移郁李，竟從金母折蟠桃。", "住庵事簡吾何力，種樹功高子有勞。", "吏用公材當小試，把鋤來趁雨如膏。"]'),
('5a54290c-59ca-4bd8-9599-3457170f04bf','晚步城外','朱翌','宋','宋诗','song-poetry','','[]','芒履寬柔野策輕，晚來無暑步重闉。',64,'全唐诗/poet.song.108000.json','["芒履寬柔野策輕，晚來無暑步重闉。", "人間爭夢大槐國，物外誰尋小草民。", "一鷺緩飛爲我伴，半川鋪練寫余真。", "何從可覺秋消息，忽有凉颸到白蘋。"]'),
('29f3de3e-7d44-4003-a26f-461fb7825ae2','冬至後三日與羅楚入倅廳兩松下梅花盛開取酒酌石臺上思得名手作松梅圖  其一','朱翌','宋','宋诗','song-poetry','','[]','老松鱗甲待拏雲，俯視梅花意亦親。',64,'全唐诗/poet.song.108000.json','["老松鱗甲待拏雲，俯視梅花意亦親。", "粉色上參冬嶺秀，虯枝下挽越溪真。", "乘閑到此能終日，與我來遊盡可人。", "今代華光古韋畢，生綃一幅兩傳神。"]'),
('eeada3bc-d586-4b17-b055-d91096659cda','冬至後三日與羅楚入倅廳兩松下梅花盛開取酒酌石臺上思得名手作松梅圖  其二','朱翌','宋','宋诗','song-poetry','','[]','匆匆前日賀書雲，那似今朝笑語親。',64,'全唐诗/poet.song.108000.json','["匆匆前日賀書雲，那似今朝笑語親。", "年例一來窺雪樣，歲寒同此見天真。", "梅間蜂陣長圍日，松下鴟蹲反嚇人。", "一碗檑茶未忘本，三杯薄酒不能神。"]'),
('ce421a41-7115-4a1b-bc0a-2021cb422432','冬至後雪夜','朱翌','宋','宋诗','song-poetry','','[]','臘前梅蕊未斜橫，至後醅香試滿觥。',64,'全唐诗/poet.song.108000.json','["臘前梅蕊未斜橫，至後醅香試滿觥。", "過眼文書開數葉，打窗風雨又三更。", "閉門高卧直差易，擁鼻微吟何似生。", "稍取濕薪供熱弄，住山如此不多爭。"]'),
('a1a64dc2-a720-4772-9157-a4cf186e035f','送鄧清臣之行在','朱翌','宋','宋诗','song-poetry','','[]','老去何嫌雪滿顛，放懷惟與子周旋。',64,'全唐诗/poet.song.108000.json','["老去何嫌雪滿顛，放懷惟與子周旋。", "起趨吳越時難得，上繼張余理必然。", "嶺海斷雲歸雁底，江湖春浪白鷗前。", "故人相見問今我，雨笠烟蓑事力田。"]'),
('b36194b9-5130-4d38-b8bf-f342132863cb','元宵懷都城簡胡令俊民時胡連夕在告','朱翌','宋','宋诗','song-poetry','','[]','天豁晴光合，簷收雪汁乾。',264,'全唐诗/poet.song.108000.json','["天豁晴光合，簷收雪汁乾。", "燈期欣在候，火令不爲難。", "方喜春風動，猶憐暮色寒。", "仙晨今夜樂，帝所舊年觀。", "郁郁卿雲密，葱葱瑞氣盤。", "五門雙闕聳，三島十洲攢。", "風伯清黄道，鈎陳衛赤鸞。", "聲流車水快，花影燭龍蟠。", "入望雲裳舉，低迷雜珮珊。", "歌翻樓上下，人與月團欒。", "夜色清凝露，香風靜泛蘭。", "陸蓮摇艷質，湯鯉轉驚瀾。", "故國雲天外，家風楚俗完。", "良時亦競作，游興頗相干。", "諸縣豐登際，元戎禮數寬。", "輟耕來野父，沽酒辦餘歡。", "少問飛鳬客，遥知道室安。", "樵青能笑語，太白酌瀰漫。", "要是弦堂宓，何妨花縣潘。", "黄庭須默課，燈錄不重看。", "羨子閉門坐，嗟予脚力殫。", "醉歸哦五字，一一待公刊。"]'),
('6eed7de7-7c82-4791-8f1b-3026cfbbe3f7','南華五十韻','朱翌','宋','宋诗','song-poetry','','[]','鄉里黄梅接，家居祖剎鄰。',288,'全唐诗/poet.song.108000.json','["鄉里黄梅接，家居祖剎鄰。", "常聞肉身佛，甘作磑坊人。", "堅有懸腰石，空無拂鏡塵。", "已舂諸米熟，自識本心真。", "拄杖敲頑質，袈裟繞凈身。", "衣傳千古信，法待五年伸。", "撥棹煩師送，投林避衆嗔。", "風幡俱不動，金瓦定非倫。", "汝聽宜皆諦，吾言决可遵。", "由茲開頓教，爲世作良因。", "葉墜雖歸本，烟斜不向新。", "鈴聲鳴白塔，霧氣走黄巾。", "塑手藏衣襲，閨姝敗鉢唇。", "全提諸佛印，開盡一花春。", "代代燈燈續，塵塵剎剎均。", "性天南北合，道德帝王親。", "歌鼓昭陵日，梯航外國珍。", "莊嚴及山谷，賜予出金銀。", "龍翥開飛帛，春溫布縯綸。", "鎮安清凈境，奔走護持神。", "樓閣三千界，香燈十二辰。", "蘇銘模妙墨，柳記刻豐珉。", "自昔炎荒地，常容放逐臣。", "流人悲去越，從者病居陳。"]'),
('b95925cf-8b22-4931-b52b-6bb09a4913ce','送吏部張尚書帥成都一百韻','朱翌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一代亨衢上，明公逸步超。',288,'全唐诗/poet.song.108000.json','["一代亨衢上，明公逸步超。", "河東書具作，圯下老相邀。", "海闊雲垂翼，天清斗壓杓。", "三人前鼎甲，千佛仰孤飈。", "弟子師尊董，諸儒稱述蕭。", "西崑收俊乂，東壁絕塵囂。", "別乘將離汴，輕舟徑指苕。", "湖山縱清美，家國尚飄摇。", "慟哭天傾柱，歸情戶見蛸。", "奉祠投里閈，招隠向山椒。", "並海屯千衛，披榛拱百僚。", "回鑾須故國，負靮且今朝。", "光列哀烏位，星馳封馬軺。", "賢裾來接武，陰沴自潜消。", "香案依丹陛，螭㘭立紫霄。", "飛鴻九天去，歸鶴一聲嘹。", "主上思圖舊，王人促見招。", "起居還左史，議論鄙南朝。", "大呂聲揚遠，元圭質匪彫。", "掖垣裁詔密，禁路賜纓彯。", "滅澆圖興夏，巡方首從姚。", "自南瞻析木，直北望玄枵。", "玉海千尋浪，江南五色鷂。", "矯如出塵隼，凜若在秋雕。"]'),
('52a0c1f7-747f-4b9b-8942-ccc2ab989574','宣城書懷','朱翌','宋','宋诗','song-poetry','','[]','高爽清凉郡，登臨佳麗都。',288,'全唐诗/poet.song.108000.json','["高爽清凉郡，登臨佳麗都。", "上連三蜀重，旁挾兩淮趨。", "天分光牛斗，溪行走舳艫。", "新林天際浦，青草柳邊湖。", "丁令鶴歸晚，琴高鯉疾驅。", "高城布渠答，近市表浮屠。", "龍具深耕雨，牛車富入租。", "鐘魚廣教飯，簫鼓敬亭巫。", "禱請俱先詣，齋修必盡愚。", "虔恭問杯珓，疇昔夢摴蒱。", "桃李萬家邑，魚鹽百賈區。", "棋爭三品勝，錢爲七郎輸。", "湖上同皇甫，樓中記獨孤。", "五雲裘可作，天馬錦應無。", "射的穿雲白，蓮房照水烏。", "山精今及采，鷹爪得同拘。", "右史隸題榜，太和存漏壺。", "劘牙虞吏像，衣褐卯神圖。", "蝎走收宵螫，蜂讙保穴雛。", "泉甘黄蘗舊，茶雋白雲腴。", "幽寂谷留馬，凌歊舟若鳬。", "山登天柱石，沙暖句溪蒲。", "洞啟三天秘，灘愁六刺迂。", "輕煙藏石女，微雨浴花姑。"]'),
('889feae6-5ec7-4230-b2db-c60a066cfc1d','陪崑山邑官遊慧聚寺詩','朱翌','宋','宋诗','song-poetry','','[]','日暗蒲鍼綠，風回柳影圓。',240,'全唐诗/poet.song.108000.json','["日暗蒲鍼綠，風回柳影圓。", "好山如有舊，勝事頗相牽。", "紺宇欣留屐，炎官快著鞭。", "神工盤岌嶪，妙手活蜿蜒。", "奇甚梁唐迹，偉哉張孟篇。", "故人逢異縣，舊話說當年。", "留滯江湖遠，驚呼歲月遷。", "還同一笑樂，相與對牀眠。", "筆向晴窗落，名垂漆榜鮮。", "味腴知茗勝，勢猛覺棋仙。", "飛蓋干霄上，危欄掛斗偏。", "壓雲雲掩苒，待月月嬋娟。", "石鏤珍球怪，杉重翠幄妍。", "迎風拳乳鵲，盡力叫饑蟬。", "雨脚斜侵戶，湖光遠拍天。", "徐澆白玉釀，笑折水晶蓮。", "時節酒中過，襟懷物外緣。", "安居豈城市，避世必林泉。", "好乞彈丸地，聊成痼疾烟。", "山祇應許我，木杪架飛椽。"]'),
('50c13e58-3948-4d2b-88fb-84fa1ede913e','再次前韻','朱翌','宋','宋诗','song-poetry','','[]','日走瞿曇宅，殷勤問覺圓。',240,'全唐诗/poet.song.108000.json','["日走瞿曇宅，殷勤問覺圓。", "荷珠翻雨碎，荇带逆風牽。", "安步穿芒屩，長驅斷蠟鞭。", "臨深呼屬玉，騎氣道蜿蜒。", "前輩幾人到，高情五字篇。", "翩翩遺濁世，落落度長年。", "斷石崖蜂出，喬枝谷鳥遷。", "端爲逃暑去，復作拂雲眠。", "心曠風林豁，書乾棐几鮮。", "丞方有公事，尉亦從羣仙。", "倚玉吾何幸，棲雲志未偏。", "久知情澹泊，不夢翠連娟。", "晚日斜吹綺，新詩欲鬭妍。", "微行窺沼鵠，孤坐蛻枝蟬。", "俯視千章木，如臨尺五天。", "韻高巾墊角，飲痛盞垂蓮。", "小築堅前約，茲遊定昔緣。", "欲誇山聳髻，安得思流泉。", "却恐樽無醁，羣憂爨不烟。", "誰來助清興，吹裂笛如椽。"]'),
('a5de08c6-1fb8-467e-a148-27e7539edeb0','次呂居仁九日羣集韻','朱翌','宋','宋诗','song-poetry','','[]','衣冠交上郡，氣象有中州。',72,'全唐诗/poet.song.108000.json','["衣冠交上郡，氣象有中州。", "九日一尊酒，千巖萬壑秋。", "星方聚吳分，魚已躍王舟。", "即事感今昔，乃情無去留。", "憂時俱出力，濟勝合先謀。", "北望邊風凜，戎衣詎敢休。"]'),
('e7762325-26ff-4029-83b2-1d779edd26e4','蔡倅羔羊齋  其一','朱翌','宋','宋诗','song-poetry','','[]','有生不釀羔羊酒，無日不誦羔羊詩。',32,'全唐诗/poet.song.108000.json','["有生不釀羔羊酒，無日不誦羔羊詩。", "賢哉蔡子勇成癖，自勵要如三代時。"]'),
('f95603c1-40ae-4ea3-bd8f-ee8496bdbebc','蔡倅羔羊齋  其二','朱翌','宋','宋诗','song-poetry','','[]','盡輸精白承休德，政用詩書造太平。',32,'全唐诗/poet.song.108000.json','["盡輸精白承休德，政用詩書造太平。", "略爲周家推在位，太顛閎夭散宜生。"]'),
('86ffcc62-268c-4420-a756-de6a9c891247','題李成山水','朱翌','宋','宋诗','song-poetry','','[]','好山誰定識真形，著白山人眼最親。',32,'全唐诗/poet.song.108000.json','["好山誰定識真形，著白山人眼最親。", "半夜忽聞遭有力，中書君召主林神。"]'),
('7775dbdd-0b3b-49c9-a901-32d03de808d9','題程幹燕公山水','朱翌','宋','宋诗','song-poetry','','[]','電眼觀山老更真，能分天造一層層。',32,'全唐诗/poet.song.108000.json','["電眼觀山老更真，能分天造一層層。", "直須擘華尊瀛手，始解鋪張入剡藤。"]'),
('c3c9d3c0-24a8-4f32-bf53-a0336527f1a1','石芥  其一','朱翌','宋','宋诗','song-poetry','','[]','古人重改陽城驛，吾輩欣聞石芥名。',32,'全唐诗/poet.song.108000.json','["古人重改陽城驛，吾輩欣聞石芥名。", "風味可人終骨鯁，樽前真見魯諸生。"]'),
('7d124a31-23fd-4379-82f4-de8fd54dba6c','石芥  其二','朱翌','宋','宋诗','song-poetry','','[]','長安官酒甜如蜜，風月雖佳嬾舉觴。',32,'全唐诗/poet.song.108000.json','["長安官酒甜如蜜，風月雖佳嬾舉觴。", "特送盤蔬還會否，與公新釀鬭端方。"]'),
('bbeca282-2688-4be8-ba95-8f00b842853e','山芥','朱翌','宋','宋诗','song-poetry','','[]','濕带青烟古澗濱，氣含石理助芳辛。',32,'全唐诗/poet.song.108000.json','["濕带青烟古澗濱，氣含石理助芳辛。", "山中酒醒凉生腦，乞與文園渴肺人。"]'),
('0969269a-9f7f-423e-b9e3-3079aff7d590','南山觀雪  其一','朱翌','宋','宋诗','song-poetry','','[]','入山初與雪雲俱，坐定雲收雪亦無。',32,'全唐诗/poet.song.108000.json','["入山初與雪雲俱，坐定雲收雪亦無。", "不見舊時蒼翠色，換將粉墨作新圖。"]'),
('1a7c6259-d39d-4880-b785-709b5f61cb77','南山觀雪  其二','朱翌','宋','宋诗','song-poetry','','[]','南遊客上妙高峰，拄杖敲冰袖障風。',32,'全唐诗/poet.song.108000.json','["南遊客上妙高峰，拄杖敲冰袖障風。", "卷起面前簾看雪，煙鬟渾插玉瓏璁。"]'),
('f3c67164-88d2-423a-8c87-b2532f34aee2','次韻書事  其一','朱翌','宋','宋诗','song-poetry','','[]','西風昨夜入庭梧，况味今年似舊無。',32,'全唐诗/poet.song.108000.json','["西風昨夜入庭梧，况味今年似舊無。", "想見防秋有長策，幽人真欲反吾廬。"]'),
('2196c271-3455-4b8b-83aa-5da1f83665c8','次韻書事  其二','朱翌','宋','宋诗','song-poetry','','[]','聖朝始悟文章弊，大霈首更詩賦科。',32,'全唐诗/poet.song.108000.json','["聖朝始悟文章弊，大霈首更詩賦科。", "白葦黄茅供一掃，英豪人物未消磨。"]'),
('ace9359c-6db1-4443-851d-624f7687aa93','次韻書事  其三','朱翌','宋','宋诗','song-poetry','','[]','熙寧事作崇寧樣，嘉祐政爲元祐師。',32,'全唐诗/poet.song.108000.json','["熙寧事作崇寧樣，嘉祐政爲元祐師。", "但得至誠行號令，坐令風俗似當時。"]'),
('39d79f42-04a5-4fd0-98df-373ddad72160','次韻書事  其四','朱翌','宋','宋诗','song-poetry','','[]','當年司馬溫公力，今日宣仁聖烈尊。',32,'全唐诗/poet.song.108000.json','["當年司馬溫公力，今日宣仁聖烈尊。", "哲后在天何慍喜，要令元老雪沉寃。"]'),
('c4e046cb-768f-4980-8560-bb2e8b95e4ac','天申節詩  其一','朱翌','宋','宋诗','song-poetry','','[]','南來欣遇千秋節，北向空馳萬里心。',32,'全唐诗/poet.song.108000.json','["南來欣遇千秋節，北向空馳萬里心。", "永日清風吹古寺，一杯聊見祝堯深。"]'),
('8a514591-a5d0-4dd8-a453-9a974bf90881','天申節詩  其二','朱翌','宋','宋诗','song-poetry','','[]','明慶曉班催百辟，鈞容仙部下層霄。',32,'全唐诗/poet.song.108000.json','["明慶曉班催百辟，鈞容仙部下層霄。", "如今獨立薰風裏，却聽羣仙奏九韶。"]'),
('d9a26e32-5fc5-495c-a7e5-81a121ad3b8f','南華書事詩  其一','朱翌','宋','宋诗','song-poetry','','[]','珍重南華五色禽，雲棲霧宿見無因。',32,'全唐诗/poet.song.108000.json','["珍重南華五色禽，雲棲霧宿見無因。", "雨中恐悞翩然出，我是閑人非貴人。"]'),
('0164eee0-8853-435e-b036-9461dab54bf0','南華書事詩  其二','朱翌','宋','宋诗','song-poetry','','[]','萬木杉從一寸栽，參天次第可推排。',32,'全唐诗/poet.song.108000.json','["萬木杉從一寸栽，參天次第可推排。", "他年空翠橋邊路，來選承天八柱材。"]'),
('8207daf8-063d-4ec9-ae91-f140ac4e738a','南華書事詩  其三','朱翌','宋','宋诗','song-poetry','','[]','真覺止能留一宿，桐鄉今已住連宵。',32,'全唐诗/poet.song.108000.json','["真覺止能留一宿，桐鄉今已住連宵。", "却將膏雨下山去，聊助南溟早晚潮。"]'),
('14935689-7cc3-4ef3-8816-9514c8600dda','南華書事詩  其四','朱翌','宋','宋诗','song-poetry','','[]','火樹燒春明躑躅，紫羅囊筆綴辛夷。',32,'全唐诗/poet.song.108000.json','["火樹燒春明躑躅，紫羅囊筆綴辛夷。", "花枝照眼蒙清潤，带雨游山亦自奇。"]'),
('2d504e78-1f78-4dfc-b2d7-533ae3a12275','曲江漁者得鱖魚棄之目爲師婆魚  其一','朱翌','宋','宋诗','song-poetry','','[]','巨口細鱗初出網，𩼎皮玳瑁乃同斑。',32,'全唐诗/poet.song.108000.json','["巨口細鱗初出網，𩼎皮玳瑁乃同斑。", "了無骨鯁人人喜，更擣鹽虀發笑顔。"]'),
('2ea04c8e-44a7-4d6e-b93a-cdcf7ae04ffb','曲江漁者得鱖魚棄之目爲師婆魚  其二','朱翌','宋','宋诗','song-poetry','','[]','溪友漁翁忍棄捐，却應游泳得長年。',32,'全唐诗/poet.song.108000.json','["溪友漁翁忍棄捐，却應游泳得長年。", "遐方未識珍羞貴，不道楊憑已得仙。"]'),
