('84e5e63d-b075-4ab5-9661-c8775667fa42','雪見羞','朱翌','宋','宋诗','song-poetry','','[]','白如白雪復何加，豈有寒英勝六花。',32,'全唐诗/poet.song.108000.json','["白如白雪復何加，豈有寒英勝六花。", "真是嶺南稀見雪，花光勝雪喜無差。"]'),
('891971db-64cc-4b86-80e6-db1ae5a7f8d3','睡軒三首  其一','朱翌','宋','宋诗','song-poetry','','[]','意馬心猿不用忙，睡鄉深處解行裝。',32,'全唐诗/poet.song.108000.json','["意馬心猿不用忙，睡鄉深處解行裝。", "華山聞有希夷子，安得斯人與對牀。"]'),
('81cb6271-441b-4693-b76b-fe64ad784f62','睡軒三首  其二','朱翌','宋','宋诗','song-poetry','','[]','諸公對奕我高眠，此法非人不可傳。',32,'全唐诗/poet.song.108000.json','["諸公對奕我高眠，此法非人不可傳。", "四脚棋槃皆黑子，孝先從此便爭先。"]'),
('bcb83bfc-66a4-4eab-87d7-7c5160e7b85e','睡軒三首  其三','朱翌','宋','宋诗','song-poetry','','[]','風和日永飽食已，雨急天寒戶不開。',32,'全唐诗/poet.song.108000.json','["風和日永飽食已，雨急天寒戶不開。", "遇此佳時無一事，搘牀高枕聽咍臺。"]'),
('0bda0e92-a753-4a81-a0d5-a260eb0814b8','謝惠楊梅','朱翌','宋','宋诗','song-poetry','','[]','杭州金氏越州楞，撒火飛星五月春。',32,'全唐诗/poet.song.108000.json','["杭州金氏越州楞，撒火飛星五月春。", "百果若重推貢士，風流應不下平津。"]'),
('d21357f1-f7c5-450e-a3b3-90407d15be36','南屏  其一','朱翌','宋','宋诗','song-poetry','','[]','百步階頭長進步，南屏堂上立移時。',32,'全唐诗/poet.song.108000.json','["百步階頭長進步，南屏堂上立移時。", "明明萬象森羅處，鍜鍊雕鎸費我詩。"]'),
('f9109c0d-5614-4480-96bf-4a00dd8c6ccc','南屏  其二','朱翌','宋','宋诗','song-poetry','','[]','早來風定絕塵霾，掃地如鏡窗盡開。',32,'全唐诗/poet.song.108000.json','["早來風定絕塵霾，掃地如鏡窗盡開。", "昏明四望移遠近，晝夜兩湖分去來。"]'),
('953197f6-7eb3-4222-bb40-6ab2bf9284ce','南屏  其三','朱翌','宋','宋诗','song-poetry','','[]','正當晝永六十刻，久坐僧齋烹雨前。',32,'全唐诗/poet.song.108000.json','["正當晝永六十刻，久坐僧齋烹雨前。", "滿園菜花開向夏，一雙蝴蝶飛上天。"]'),
('16f88c03-4773-42f2-8465-57aeb91e167a','寄題競秀亭  其一','朱翌','宋','宋诗','song-poetry','','[]','吳山越嶺老於行，何地誅茅寄此情。',32,'全唐诗/poet.song.108000.json','["吳山越嶺老於行，何地誅茅寄此情。", "直使浮雲無一點，千巖應接始分明。"]'),
('b24e9967-7998-4331-a0d8-a21d4b106a75','寄題競秀亭  其二','朱翌','宋','宋诗','song-poetry','','[]','來往人傳客寢安，問渠何事駐征鞍。',32,'全唐诗/poet.song.108000.json','["來往人傳客寢安，問渠何事駐征鞍。", "只應門外千山好，能使胸中百念寬。"]'),
('d039a190-889f-42eb-8498-2724fba09db7','觀烏龍山瀑布  其一','朱翌','宋','宋诗','song-poetry','','[]','一日一夜雨如傾，北山山頂垂天紳。',32,'全唐诗/poet.song.108000.json','["一日一夜雨如傾，北山山頂垂天紳。", "是間去海只咫尺，緩流何用走踆踆。"]'),
('99eba2db-12eb-4912-90f7-7487970c7ef1','觀烏龍山瀑布  其二','朱翌','宋','宋诗','song-poetry','','[]','五老峰前三峽橋，不論時節聽飛潮。',32,'全唐诗/poet.song.108000.json','["五老峰前三峽橋，不論時節聽飛潮。", "那知冷落窮山裏，忽見晴空練一條。"]'),
