('f7330fcc-521c-477d-bb4d-a345613f78a5','園中開牡丹一枝','朱翌','宋','宋诗','song-poetry','','[]','天下花王都洛京，清明寒食走香軿。',32,'全唐诗/poet.song.108000.json','["天下花王都洛京，清明寒食走香軿。", "東君欲表南來意，一朵蔫然尚典型。"]'),
('f67d2c5c-76fd-4a39-bfe6-015da7497f2f','詠紫荆','朱翌','宋','宋诗','song-poetry','','[]','鶴骨龍筋結壽枝，紅綃紫綺曝仙衣。',32,'全唐诗/poet.song.108000.json','["鶴骨龍筋結壽枝，紅綃紫綺曝仙衣。", "只應不奈麻姑爪，獨領春風住翠微。"]'),
('e33bd4e0-22fd-43b3-bc64-0be2700b3f64','有惠新醤及酒者','朱翌','宋','宋诗','song-poetry','','[]','拾遺久住浣花橋，生理誰能濟一毫。',32,'全唐诗/poet.song.108000.json','["拾遺久住浣花橋，生理誰能濟一毫。", "携醤藉糟來過我，故人惟有孟倉曹。"]'),
('c2a0e5f8-e526-430c-905d-e1883800fa09','聽鴿鈴','朱翌','宋','宋诗','song-poetry','','[]','蓬蒿門巷久張羅，豈有籠坊重客過。',32,'全唐诗/poet.song.108000.json','["蓬蒿門巷久張羅，豈有籠坊重客過。", "天外鴿鈴驚午枕，兒童誤起聽長呵。"]'),
('d970abf6-ab99-4567-a5e3-b8d007a2d0d5','次韻董令升四詠 尋幽亭','朱翌','宋','宋诗','song-poetry','','[]','帝遣銀河下太微，餘波散繞野人扉。',32,'全唐诗/poet.song.108000.json','["帝遣銀河下太微，餘波散繞野人扉。", "此行步步有佳處，盤礴孤亭試解衣。"]'),
('b1457ef4-138b-4b5c-9bcd-0fd31895703c','次韻董令升四詠 競秀亭','朱翌','宋','宋诗','song-poetry','','[]','山陰道士頃留連，應接烟雲馬不前。',32,'全唐诗/poet.song.108000.json','["山陰道士頃留連，應接烟雲馬不前。", "君說江南亦如此，我雖未到想當然。"]'),
('6757a605-c242-4118-a963-0485f011c49e','次韻董令升四詠 性樂堂','朱翌','宋','宋诗','song-poetry','','[]','且置紛紛事百端，從公繫馬白雲邊。',32,'全唐诗/poet.song.108000.json','["且置紛紛事百端，從公繫馬白雲邊。", "欲知太守樂其樂，山色溪聲得兩全。"]'),
('4107d6f1-1994-4d38-b5de-2e7f1ba97556','次韻董令升四詠 玉泉','朱翌','宋','宋诗','song-poetry','','[]','至寶何年伏九淵，飛空散作玉聲琤。',32,'全唐诗/poet.song.108000.json','["至寶何年伏九淵，飛空散作玉聲琤。", "那知夜半騰朝采，會見長虹屬太清。"]'),
('1053d841-e64a-45ed-b0b7-31ee96c19351','梅花','朱翌','宋','宋诗','song-poetry','','[]','姑射山頭冰雪仙，人間一見便豐年。',32,'全唐诗/poet.song.108000.json','["姑射山頭冰雪仙，人間一見便豐年。", "却應羞死琴臺女，不得乃翁分一錢。"]'),
('c01da30e-a91b-4ca5-bacb-172850ab6a6a','芥','朱翌','宋','宋诗','song-poetry','','[]','蔚然蒼石底，有此紫玉釵。',24,'全唐诗/poet.song.108000.json','["蔚然蒼石底，有此紫玉釵。", "本無塵土侵，寧畏霜霰埋。"]'),
('584e8b9b-d17b-4f39-9637-a67d45aeaaf2','芹','朱翌','宋','宋诗','song-poetry','','[]','幽人本無肉食願，岸草溪毛躬自薦。',32,'全唐诗/poet.song.108000.json','["幽人本無肉食願，岸草溪毛躬自薦。", "並隄有芹秀晚春，采掇歸來待朝膳。"]'),
('ce5ebc08-6362-407f-abe3-df7f76aea344','觀弄獅子','朱翌','宋','宋诗','song-poetry','','[]','狻猊日走二百里，於菟聞之望風靡。',96,'全唐诗/poet.song.108000.json','["狻猊日走二百里，於菟聞之望風靡。", "春晴酤酒大合樂，乃向尊前應宮徵。", "嚬呻奮迅左右顧，櫪馬悲鳴汗流水。", "供官自古藏太常，失脚何年落村裏。", "佛居勝義空谷中，吼法怖魔如此耳。", "人閒宜假不宜真，此理吾今得之矣。"]'),
('882f42c9-c36a-4b1d-905b-2e7d597a827a','詠昭君','朱翌','宋','宋诗','song-poetry','','[]','當時夫死若求歸，凜然義動單于府。',32,'全唐诗/poet.song.108000.json','["當時夫死若求歸，凜然義動單于府。", "不知出此更隨俗，顔色如花心糞土。"]'),
('67cc3960-d307-4bb5-be2c-10c52a55f622','登白衣寺鐘樓','朱翌','宋','宋诗','song-poetry','','[]','憑高直欲馭西風，百里纖毫盡發蒙。',64,'全唐诗/poet.song.108000.json','["憑高直欲馭西風，百里纖毫盡發蒙。", "樓觀相望秋色裏，江山爭麗海光中。", "雲容入座如相識，足力緣梯尚不窮。", "肯使詩成誇得意，撞鐘驚起坐禪翁。"]'),
('03ad5412-5247-47bb-9b1f-4ca6121f2795','咏慈溪普濟寺古松','朱翌','宋','宋诗','song-poetry','','[]','三國名臣宅，千楹釋子宮。',48,'全唐诗/poet.song.108000.json','["三國名臣宅，千楹釋子宮。", "但求除橘籍，不見老松公。", "懷抱凌雲上，規模偃蓋同。", "須防雷雨際，恐復化爲龍。"]'),
('52ac4a37-6410-4a94-bb6c-88afa05c529f','讀杜詩至減米散同舟路難思共濟舟人偶來告饑似詩讖也','朱翌','宋','宋诗','song-poetry','','[]','老翁起布衣，詩史天下選。',204,'全唐诗/poet.song.108000.json','["老翁起布衣，詩史天下選。", "眼中無全牛，萬象轉綮窽。", "曹劉知幾輩，波瀾付一卷。", "凄其憂世心，妙若醫國扁。", "惜哉無孔子，不得並墳典。", "豹露管中班，吾猶及淺淺。", "歲月走江淮，冷淡空盤盞。", "諸子不見味，咀嚼必禁臠。", "遺編過三復，奧義見百遍。", "長言起清風，竦立侍冠冕。", "減米散同舟，讀已事在眼。", "吾豈監河侯，不救在陳患。", "生塵甑屢空，戛釜聲不免。", "迢迢千里程，與汝共艱嶮。", "雖無百丈牽，顧有衆力挽。", "願學平原公，試草乞米簡。", "更問偕來人，恐有蔡明遠。"]'),
('4c8b51dd-842f-45c2-9e15-dd4da3fad655','輶歸自五羊得承可舊詩一編書其後','朱翌','宋','宋诗','song-poetry','','[]','君不見香山居士居洛陽，遠借五寺收文章。',182,'全唐诗/poet.song.108000.json','["君不見香山居士居洛陽，遠借五寺收文章。", "又不見巢父詩卷何所藏，留之天地同久長。", "鑄金琢石非不强，金流石泐不可防。", "以人傳人策甚良，世人顧未知其方。", "我昔宦游凌大江，年少從君璧一雙。", "勝時一詠同一觴，頗亦自愧搶榆枋。", "劫火不肯留青囊，日往月來心不忘。", "大兒南歸自五羊，袖中乃有萬丈光。", "伏而讀之喜莫量，重到虎踞龍盤鄉。", "今年貢舶早放洋，明珠大貝光溢箱。", "答賜不敢煩吾皇，願得君詩歸獻王。"]'),
('31ced68c-0750-4bd2-918f-8ad15fca28b7','投壺  其一','朱翌','宋','宋诗','song-poetry','','[]','誰可忘憂慰寂寥，夏長惟以一壺消。',64,'全唐诗/poet.song.108000.json','["誰可忘憂慰寂寥，夏長惟以一壺消。", "坐中皆欲從多馬，妙處何妨不絕梟。", "幸郭滑稽無事日，將遵取士中興朝。", "諸公有意來償進，貰酒何妨爲解貂。"]'),
('9713e4b6-99dc-439d-a821-a4958fdb7d0a','投壺  其二','朱翌','宋','宋诗','song-poetry','','[]','哨壺枉矢樂初筵，列坐分曹看令傳。',64,'全唐诗/poet.song.108000.json','["哨壺枉矢樂初筵，列坐分曹看令傳。", "龍躍隼飛驚背手，雲開電擊笑通天。", "齊侯晉侯誇酒肉，魯鼓薛鼓排方圓。", "何事吾人無一事，竹牀高卧聽錚然。"]'),
('f85c9448-f463-41da-b9cc-2a3f5c699e7a','投壺  其三','朱翌','宋','宋诗','song-poetry','','[]','五扶新拓室中筵，列算姑從舊制傳。',64,'全唐诗/poet.song.108000.json','["五扶新拓室中筵，列算姑從舊制傳。", "百發縱橫惟所命，一時勝負豈非天。", "功成只許全爲上，手熟猶如左畫圓。", "卜晝未厭仍卜夜，銅槃高捧燭花然。"]'),
('75247278-9835-4fa9-b174-a12b013847ec','投壺  其四','朱翌','宋','宋诗','song-poetry','','[]','三代遺文歎寂寥，考評今古得愁消。',64,'全唐诗/poet.song.108000.json','["三代遺文歎寂寥，考評今古得愁消。", "中行穆子雖爭雋，司馬溫公不貴梟。", "鈇鉞他年專將閫，羽儀從此冠天朝。", "倒囊賸欲陪賓戲，零落空餘一弊貂。"]'),
('a491b0eb-f94e-43da-b0cd-151e538ae01b','上巳陪諸公集西湖','朱翌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','今日我上巳，樂哉天氣新。',108,'全唐诗/poet.song.108000.json','["今日我上巳，樂哉天氣新。", "青春在西湖，湖水綠以勻。", "諸公乃肯遊，盤飧仍集珍。", "少縱方外談，一洗城中塵。", "喚船苦不早，行酒不計巡。", "始歎葑欲合，終喜鷗來親。", "茫茫天宇間，何地寄此身。", "共偷一日閑，恐負三月春。", "遥瞻後湖遊，海若從鉤陳。"]'),
('2b267dee-a6e5-4456-9a59-332a6977345e','六月十五日西湖宿齋','朱翌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','並湖西去望南屏，但見煙雲日日新。',64,'全唐诗/poet.song.108000.json','["並湖西去望南屏，但見煙雲日日新。", "山色漸爭秋氣勢，荷花全露曉精神。", "洗心用此無邊綠，處世端能不染塵。", "慚愧西湖敦夙夜，從今長作境中人。"]'),
('5eb3f4e0-a193-407e-b88d-be6b77cba444','金剛臺','朱翌','宋','宋诗','song-poetry','','[]','兒子門生交說勤，要翁一出步溪雲。',64,'全唐诗/poet.song.108000.json','["兒子門生交說勤，要翁一出步溪雲。", "金剛臺近城三里，玉友醅新盞十分。", "反照江山紅半歛，小春桃李暖如薰。", "心灰已冷無機事，戲象爭棋亦謾云。"]'),
('e1000b1a-81dd-4bdb-b646-a8b1cde5f9d6','綠萼梅','朱翌','宋','宋诗','song-poetry','','[]','不肯雷同自一家，青裙獨立水之涯。',32,'全唐诗/poet.song.108000.json','["不肯雷同自一家，青裙獨立水之涯。", "只應夜過許長史，全似當年萼綠華。"]'),
('ccd8335a-0f82-439c-855e-54a3466c8f8c','題山谷姚黄梅花','朱翌','宋','宋诗','song-poetry','','[]','姚花富貴江梅妙，俱是花中第一流。',32,'全唐诗/poet.song.108000.json','["姚花富貴江梅妙，俱是花中第一流。", "戲出小詩花一樣，先生下筆與春謀。"]'),
('c985b1f4-9b73-4e79-a287-3b699e64ce5c','素馨','朱翌','宋','宋诗','song-poetry','','[]','衆香發越充南溟，梅花腦飛水弄沉。',96,'全唐诗/poet.song.108000.json','["衆香發越充南溟，梅花腦飛水弄沉。", "露積旃檀薪降真，薰陸光射琉璃缾。", "山川草木一天芬，素質如玉備衆馨。", "烏髻粵女嬌滿簪，上官置酒結蓋纓。", "餘波潤澤龍涎春，北走萬里燕趙秦。", "騷人尚尤楚靈均，何爲不入離騷經。"]'),
('9af910cb-7c16-4d37-97ee-4dc9522a7a37','嶠南元夕時桃李盡花今歲遊人甚盛示王守','朱翌','宋','宋诗','song-poetry','','[]','太平文物自多奇，刺史風流照海涯。',64,'全唐诗/poet.song.108000.json','["太平文物自多奇，刺史風流照海涯。", "五福神遊先樂國，百燈王現應明時。", "笙簫合處春回煖，桃李陰中月落遲。", "醉倒花前天厚我，何須更間紫姑爲。"]'),
('123fa002-d390-461a-944e-4b6b4116bfe3','題清芬閣','朱翌','宋','宋诗','song-poetry','','[]','山腰繫烟帛，石齒潄灘雪。',96,'全唐诗/poet.song.108000.json','["山腰繫烟帛，石齒潄灘雪。", "千歲可坐致，清風在巖穴。", "五季浪拍天，不覆漁翁船。", "入山種美材，百世收棟椽。", "松廳正一臺，蓮幕壯兩河。", "少蓬薰班香，建州辦韓多。", "今代南海君，事事似諸父。", "何年繼昔遊，秋山祠乃祖。"]'),
('08a97c41-d085-452c-aebc-a134c9c1f0e4','句  其一','朱翌','宋','宋诗','song-poetry','','[]','下岩琢研溫如玉。',8,'全唐诗/poet.song.108000.json','["下岩琢研溫如玉。"]'),
('9a0eaab2-6be2-4189-b2e4-c51f89186808','句  其二','朱翌','宋','宋诗','song-poetry','','[]','昔時桐溪漢九卿，家在淮南天一柱。',16,'全唐诗/poet.song.108000.json','["昔時桐溪漢九卿，家在淮南天一柱。"]'),
('a43c0c84-f7b6-42f4-883e-17ade4b624a7','句  其三','朱翌','宋','宋诗','song-poetry','','[]','天上佳招飛鸑鷟，人間春色到蔓菁。',16,'全唐诗/poet.song.108000.json','["天上佳招飛鸑鷟，人間春色到蔓菁。"]'),
('529262ef-be70-4eb2-a873-f82801f64b74','句  其四','朱翌','宋','宋诗','song-poetry','','[]','天氣未佳宜且住，風濤如此亦安歸。',16,'全唐诗/poet.song.108000.json','["天氣未佳宜且住，風濤如此亦安歸。"]'),
('5990c462-f1ef-4c56-ae2a-186da01890e0','句  其五','朱翌','宋','宋诗','song-poetry','','[]','水篆行科斗，林妝囀畫眉。',12,'全唐诗/poet.song.108000.json','["水篆行科斗，林妝囀畫眉。"]'),
('e794725e-d408-4dee-9347-402cc20683aa','句  其六','朱翌','宋','宋诗','song-poetry','','[]','足下一來同晚步，先生小住待村舂。',16,'全唐诗/poet.song.108000.json','["足下一來同晚步，先生小住待村舂。"]'),
('4426e622-f74a-4c81-92c6-4701cbae8c00','句  其七','朱翌','宋','宋诗','song-poetry','','[]','四野綠迴春補闕，亂山塵浄雨修容。',16,'全唐诗/poet.song.108000.json','["四野綠迴春補闕，亂山塵浄雨修容。"]'),
('9dbeb33f-27d1-47f6-8430-07b71c4052bc','句  其八','朱翌','宋','宋诗','song-poetry','','[]','經年不濯子春足，半月才梳叔夜頭。',16,'全唐诗/poet.song.108000.json','["經年不濯子春足，半月才梳叔夜頭。"]'),
('a9ec430a-e0f8-4df2-ac25-b2564664181a','句  其九','朱翌','宋','宋诗','song-poetry','','[]','縉紳處士議所以，將軍貴人須畢之。',16,'全唐诗/poet.song.108000.json','["縉紳處士議所以，將軍貴人須畢之。"]'),
('dd40a167-97ad-4741-9cd2-21ae6b440186','句  其一○','朱翌','宋','宋诗','song-poetry','','[]','琉璃虛空甚圓滿，紫磨山川更新鑄。',16,'全唐诗/poet.song.108000.json','["琉璃虛空甚圓滿，紫磨山川更新鑄。"]'),
('d34aff50-00a7-47c9-9cb9-781de91405ec','句  其一一','朱翌','宋','宋诗','song-poetry','','[]','客來切勿令觀此，薏苡猶能困伏波。',16,'全唐诗/poet.song.108000.json','["客來切勿令觀此，薏苡猶能困伏波。"]'),
('bac14bac-d18b-4adc-96c1-5738bf622630','句  其一二','朱翌','宋','宋诗','song-poetry','','[]','水精透膜輕含液，絳縠離苞未變香。',16,'全唐诗/poet.song.108000.json','["水精透膜輕含液，絳縠離苞未變香。"]'),
('6b13c020-ad97-4f1e-92ab-7c15b6cb5319','句  其一三','朱翌','宋','宋诗','song-poetry','','[]','蘼蕪敷綠葉，系出蛾眉陰。',12,'全唐诗/poet.song.108000.json','["蘼蕪敷綠葉，系出蛾眉陰。"]'),
('4861d80e-7320-46b6-8505-63859a8e747a','句  其一四','朱翌','宋','宋诗','song-poetry','','[]','時過湯餠客，共破粵侯琛。',12,'全唐诗/poet.song.108000.json','["時過湯餠客，共破粵侯琛。"]'),
('2f7d57d9-60a8-422f-81f0-a6b86bf8858b','句  其一五','朱翌','宋','宋诗','song-poetry','','[]','三徑誰從陶靖節，重陽惟有傅延年。',16,'全唐诗/poet.song.108000.json','["三徑誰從陶靖節，重陽惟有傅延年。"]'),
('f7bb9c23-ae68-4de6-811d-1fbe5e4f8ffd','句  其一六','朱翌','宋','宋诗','song-poetry','','[]','無人馬爲二，對飲月成三。',12,'全唐诗/poet.song.108000.json','["無人馬爲二，對飲月成三。"]'),
('ddf82556-f3d1-4fa8-bbc0-b7be1ab56f80','睡起','姚孝錫','宋','宋诗','song-poetry','','[]','生涯甘分寄耕桑，山色圍門水遶牆。',64,'全唐诗/poet.song.108000.json','["生涯甘分寄耕桑，山色圍門水遶牆。", "困病久懲耽酒癖，愛閒猶有和詩忙。", "簷冰滴砌春猶冷，野馬浮川日漸長。", "舊事老年多記憶，故園歸夢正悠颺。"]'),
('1ff98591-c97b-4c93-a7fe-4dd17e1e8be7','柳溪別墅','姚孝錫','宋','宋诗','song-poetry','','[]','安車隨意飽甘肥，晚食徐行理亦齊。',64,'全唐诗/poet.song.108000.json','["安車隨意飽甘肥，晚食徐行理亦齊。", "山市日高人未集，柴門客至鳥先啼。", "溪橋散望携筇度，野寺牽吟信筆題。", "容膝易安聊自適，甕天閒看舞醯雞。"]'),
('d1a417f7-8ce9-4a61-bc74-9fcde55173c7','歲晚懷二弟','姚孝錫','宋','宋诗','song-poetry','','[]','少易成歡老易傷，壯遊垂白未還鄉。',64,'全唐诗/poet.song.108000.json','["少易成歡老易傷，壯遊垂白未還鄉。", "煙塵無復音書到，魂夢猶疲道路長。", "爆竹又驚新薦歲，屠蘇空憶舊傳觴。", "年年此日遥相憶，鴻雁何時續斷行。"]'),
('4a4761c0-be3c-45b5-9d2e-2467397f6d1f','睡起','姚孝錫','宋','宋诗','song-poetry','','[]','睡起日侵牖，開軒遥見山。',48,'全唐诗/poet.song.108000.json','["睡起日侵牖，開軒遥見山。", "曉風吹臘盡，芳草惹春還。", "煙暖鶑遷谷，雲低雁渡關。", "衰年人事減，遇酒得開顔。"]'),
('4384f9ce-04ba-49af-9c55-c198b30d1662','次李平子登臺有感韻','姚孝錫','宋','宋诗','song-poetry','','[]','落日孤雲带遠岡，戍樓烟瘴舊邊場。',64,'全唐诗/poet.song.108000.json','["落日孤雲带遠岡，戍樓烟瘴舊邊場。", "疲民卒歲方懷土，遠客憑高自憶鄉。", "漢使一朝延四皓，秦詩千古弔三良。", "行藏此意無人解，聊借青山送酒觴。"]'),
('efd711e8-d929-4fa9-8e5c-778af7c22676','九日題峰山','姚孝錫','宋','宋诗','song-poetry','','[]','不須歌吹上叢臺，千里晴川入座來。',64,'全唐诗/poet.song.108000.json','["不須歌吹上叢臺，千里晴川入座來。", "世事難憑休挂口，生涯見在且銜杯。", "無情趁暖花先老，有信迎寒雁已迴。", "遥想故園親種菊，霜枝露蘂向誰開。"]'),
('6af17a30-0cd6-4096-8f2b-eb43272a8051','次韻王無競見寄','姚孝錫','宋','宋诗','song-poetry','','[]','客懷重倚仲宣樓，白草黄雲塞上秋。',64,'全唐诗/poet.song.108000.json','["客懷重倚仲宣樓，白草黄雲塞上秋。", "山色不隨塵世改，水聲還抱故城流。", "隙中畏景那堪玩，鏡裏衰顔祇自羞。", "多愧詩人苦相憶，遠傳佳句弔清愁。"]'),
('91c925a3-3949-4a95-a06d-111fb0551965','閒居','姚孝錫','宋','宋诗','song-poetry','','[]','無客訪衰殘，柴門盡日關。',48,'全唐诗/poet.song.108000.json','["無客訪衰殘，柴門盡日關。", "耽書真是癖，惜酒近成慳。", "苔徑行搜句，茅檐卧看山。", "却嫌明鏡裏，偏照鬢毛斑。"]'),
('f1e58e40-9e7f-4ba1-a753-6b204aba3981','和成冠卿見寄','姚孝錫','宋','宋诗','song-poetry','','[]','別恨頻添鬢雪深，百年懷抱鬰沈沈。',64,'全唐诗/poet.song.108000.json','["別恨頻添鬢雪深，百年懷抱鬰沈沈。", "標名不挂金銀牓，涉世空堅鐵石心。", "俗物何勞供一醉，殘僧正欲伴孤吟。", "朱絃三弄虛簷寂，唯有清風是賞音。"]'),
('73c1b876-2857-4341-b787-bed3f0909b85','次韻秋興','姚孝錫','宋','宋诗','song-poetry','','[]','老畏年光速，愁添旅夢多。',48,'全唐诗/poet.song.108000.json','["老畏年光速，愁添旅夢多。", "西風著梧竹，歸思入煙波。", "夜永憑詩遣，顔衰得酒和。", "故溪千樹柳，誰復曬漁蓑。"]'),
('9b3fe27c-5cdb-4e62-8899-838e4067d946','感白髮','姚孝錫','宋','宋诗','song-poetry','','[]','彈鋏憑誰聽客歌，震雷那復化魚梭。',64,'全唐诗/poet.song.108000.json','["彈鋏憑誰聽客歌，震雷那復化魚梭。", "梳頭白雪驚新有，障眼元花比舊多。", "鄉問阻兵猶斷絕，羈懷憑酒暫消磨。", "不須更問今朝客，門外元無雀可羅。"]'),
('87901a30-1873-490a-8c70-2fa998955566','曉霽','姚孝錫','宋','宋诗','song-poetry','','[]','一夜雲峯卷迅雷，殘紅狼藉點蒼苔。',64,'全唐诗/poet.song.108000.json','["一夜雲峯卷迅雷，殘紅狼藉點蒼苔。", "鶑聲豈解留春住，燕語虛勞喚夢迴。", "愁寂頓疑詩思減，衰殘偏感歲華催。", "柳溪魚鳥應相識，乘興無嫌日日來。"]'),
('a8f3ba6d-8f17-4f2c-91aa-c01c8aa5f705','重九偶成','姚孝錫','宋','宋诗','song-poetry','','[]','天邊今日又重陽，隴樹紅飛雁信霜。',64,'全唐诗/poet.song.108000.json','["天邊今日又重陽，隴樹紅飛雁信霜。", "且插茱萸慰衰鬢，莫將詩句撓迴腸。", "歌勤皓齒人俱醉，舞戀晴暉蝶也忙。", "來日預期扶宿酒，未應籬菊減秋香。"]'),
('d612a2ed-224a-457f-bd95-f4dc7def5411','溪橋早春','姚孝錫','宋','宋诗','song-poetry','','[]','輕黄未染柳梢勻，連日溪風卷塞塵。',64,'全唐诗/poet.song.108000.json','["輕黄未染柳梢勻，連日溪風卷塞塵。", "乍暖乍寒花信晚，相呼相應鳥聲頻。", "少勤漫挾經綸策，老懶空餘病患身。", "追憶故園桃李樹，年年紅紫爲誰新。"]'),
('ac1ccc38-bce8-4d75-ab31-844ec2edd4c0','東軒琴示兒子沂','姚孝錫','宋','宋诗','song-poetry','','[]','古人無復見，但有東軒琴。',48,'全唐诗/poet.song.108000.json','["古人無復見，但有東軒琴。", "一鼓高山操，因窺古人心。", "正聲久沈埋，俚耳喧哇淫。", "正可自怡悅，不須求賞音。"]'),
('77a567ec-1a08-408c-b9ce-9e42ba27c5bb','花前獨酌二絕句  其一','姚孝錫','宋','宋诗','song-poetry','','[]','老將花酒作知音，起就花前酒自斟。',32,'全唐诗/poet.song.108000.json','["老將花酒作知音，起就花前酒自斟。", "莫便興來先酩酊，却妨真賞廢搜吟。"]'),
('b946965b-4d19-4291-859c-610cbf5b715a','花前獨酌二絕句  其二','姚孝錫','宋','宋诗','song-poetry','','[]','移得名花手自栽，花知不爲老人開。',32,'全唐诗/poet.song.108000.json','["移得名花手自栽，花知不爲老人開。", "興來誰是尊前客，唯有提壺送酒盃。"]'),
('eef84cb1-d1a6-4cf8-8029-15bf0939d9b1','題柳溪別墅','姚孝錫','宋','宋诗','song-poetry','','[]','雨霽風和不動塵，柳邊携酒賞晴春。',32,'全唐诗/poet.song.108000.json','["雨霽風和不動塵，柳邊携酒賞晴春。", "頻來溪鳥渾相識，度水穿花不避人。"]'),
('7871af73-5598-43c0-ab24-abc24220ace9','芍藥','姚孝錫','宋','宋诗','song-poetry','','[]','綠萼披風瘦，紅苞浥露肥。',24,'全唐诗/poet.song.108000.json','["綠萼披風瘦，紅苞浥露肥。", "只愁春夢斷，化作彩雲飛。"]'),
('c474fcd3-a1cc-424c-a22a-1b6aeae8b7cf','次韻李相公偶成','姚孝錫','宋','宋诗','song-poetry','','[]','簾鳥喚歸夢，竹風追夕凉。',48,'全唐诗/poet.song.108000.json','["簾鳥喚歸夢，竹風追夕凉。", "感時空有淚，却老分無方。", "流水依山白，孤雲带日黄。", "無人共尊酒，散髮卧藜牀。"]'),
('3a30fe14-3854-4330-9230-cbc3d75dc0a9','村居偶成','姚孝錫','宋','宋诗','song-poetry','','[]','靜愛柴門野興幽，杖藜徐步到巖丘。',64,'全唐诗/poet.song.108000.json','["靜愛柴門野興幽，杖藜徐步到巖丘。", "深林有獸鳥先噪，廢圃無人泉自流。", "土瘠稅租隨力辦，年豐禾黍過時收。", "客來不慮無供給，白酒黄雞亦易求。"]'),
('d933eee6-014c-498e-97d7-3a9ee01439e1','用峰山舊韻二首  其一','姚孝錫','宋','宋诗','song-poetry','','[]','信步西風寺，窮幽未覺賒。',48,'全唐诗/poet.song.108000.json','["信步西風寺，窮幽未覺賒。", "松根纏石瘦，雲磴出巖斜。", "思爽餘三唱，詩成自一家。", "空餘幾兩屐，不踏渡溪槎。"]'),
('c7629edc-6fb3-4233-b9da-3ff0029ba529','用峰山舊韻二首  其二','姚孝錫','宋','宋诗','song-poetry','','[]','春水上堤沙，春晴散望賒。',48,'全唐诗/poet.song.108000.json','["春水上堤沙，春晴散望賒。", "衰年花近眼，久客夢還家。", "映日孤鴻沒，迎風雙燕斜。", "平生江海意，早晚送浮槎。"]'),
('30ec059f-08dc-4a55-8c5e-9d2049932d96','題佛光寺','姚孝錫','宋','宋诗','song-poetry','','[]','臧穀雖殊竟兩亡，倚闌終日念行藏。',64,'全唐诗/poet.song.108000.json','["臧穀雖殊竟兩亡，倚闌終日念行藏。", "已忻境寂洗塵慮，更覺心清聞妙香。", "孤鳥带煙來遠樹，斷雲收雨下斜陽。", "人間未卜蝸牛舍，遠目橫秋益自傷。"]'),
('a9822591-96a9-437a-b5e1-c6981f2e8ab4','芭蕉','姚孝錫','宋','宋诗','song-poetry','','[]','鳳翅摇寒碧，虛庭暑不侵。',24,'全唐诗/poet.song.108000.json','["鳳翅摇寒碧，虛庭暑不侵。", "何因有恨事，常抱未舒心。"]'),
('40e8dee9-4134-46b8-a376-f501653dd16e','蜀葵','姚孝錫','宋','宋诗','song-poetry','','[]','傾心知向日，布葉解承陰。',24,'全唐诗/poet.song.108000.json','["傾心知向日，布葉解承陰。", "空側黄金盞，誰人與對斟。"]'),
('87017e17-1283-44b1-ba05-611eaafa6963','次韻公才對菊見懷','姚孝錫','宋','宋诗','song-poetry','','[]','髮蓬新感二毛侵，尚阻清尊對菊斟。',64,'全唐诗/poet.song.108000.json','["髮蓬新感二毛侵，尚阻清尊對菊斟。", "久擬芝蘭同臭味，莫疑魚鳥自高深。", "食貧豈復甘秦炙，客病空懷奏楚音。", "挂席無由上牛斗，漫憑流水送歸心。"]'),
('d6fde336-f1e5-4b5d-b2dd-9e63995bf163','寄田朝散善輔','姚孝錫','宋','宋诗','song-poetry','','[]','粉署標名舊，山城識面新。',48,'全唐诗/poet.song.108000.json','["粉署標名舊，山城識面新。", "青雲摧勁翮，空谷滯幽人。", "世路謀身拙，心田育德醇。", "久要知可卜，傾蓋已情親。"]'),
('ad4ebdaa-62b1-4330-b623-4d41a581a491','春日書懷','姚孝錫','宋','宋诗','song-poetry','','[]','雲散交情薄，棋翻世態新。',48,'全唐诗/poet.song.108000.json','["雲散交情薄，棋翻世態新。", "山容猶带臘，鳥語已回春。", "節物驚心遽，丘園入夢頻。", "東風如解語，端笑未歸人。"]'),
('994d1b47-0150-4baf-b4ac-45ce7f155035','春日溪橋','姚孝錫','宋','宋诗','song-poetry','','[]','留戀春光慰病顔，無情風雨卷春還。',64,'全唐诗/poet.song.108000.json','["留戀春光慰病顔，無情風雨卷春還。", "陰陰密綠籠溪暗，細細疏紅點徑斑。", "老去益憐詩思澀，歡來聊破酒腸慳。", "不嫌門外無車轍，得遂衰慵一味閒。"]'),
('4a17535c-c86d-41e6-af23-ab42a1eead57','登樓有懷','姚孝錫','宋','宋诗','song-poetry','','[]','老愧凭闌目力昏，百年懷抱向誰論。',64,'全唐诗/poet.song.108000.json','["老愧凭闌目力昏，百年懷抱向誰論。", "晴空雁起雲邊塞，夕照人歸郭外村。", "因記昔遊驚迅晷，暫將離恨付清尊。", "誰人肯似邊居士，遠駕朱輪過雀門。"]'),
('60200ab1-2730-4ae0-abe3-f6571e341eda','題滕奉使祠','姚孝錫','宋','宋诗','song-poetry','','[]','本期蘇鄭共揚鑣，不意芝蘭失後凋。',64,'全唐诗/poet.song.108000.json','["本期蘇鄭共揚鑣，不意芝蘭失後凋。", "遺老祇今猶涕泪，後生無復識風標。", "西陘雁度霜前塞，滹水樵爭日暮橋。", "追想生平英偉魄，凌雲一笑豈能招。"]'),
('1f3efca9-d6e6-4ab5-a767-2c45ecefc0bb','句  其一','姚孝錫','宋','宋诗','song-poetry','','[]','節物先後南北異，人情冷暖古今同。',16,'全唐诗/poet.song.108000.json','["節物先後南北異，人情冷暖古今同。"]'),
('c9382e79-39d4-4b44-9930-d8a3f949123a','句  其二','姚孝錫','宋','宋诗','song-poetry','','[]','紅纈退風花著子，綠鍼浮水稻抽秧。',16,'全唐诗/poet.song.108000.json','["紅纈退風花著子，綠鍼浮水稻抽秧。"]'),
('30fa2c41-89b8-4e7d-9008-d2b196ee9a1a','句  其三','姚孝錫','宋','宋诗','song-poetry','','[]','久客交情諳冷暖，衰年病骨識陰晴。',16,'全唐诗/poet.song.108000.json','["久客交情諳冷暖，衰年病骨識陰晴。"]'),
('02e9b184-b06a-4f27-ac6e-89ecc9d44bb1','句  其四','姚孝錫','宋','宋诗','song-poetry','','[]','烟染綠絲迷別浦，雨催紅糝綴長條。',16,'全唐诗/poet.song.108000.json','["烟染綠絲迷別浦，雨催紅糝綴長條。"]'),
('6daa488e-1177-4fbf-8ab5-6f6c90320118','句  其五','姚孝錫','宋','宋诗','song-poetry','','[]','愁邊日晷偏疑短，夢裏江鄉未當歸。',16,'全唐诗/poet.song.108000.json','["愁邊日晷偏疑短，夢裏江鄉未當歸。"]'),
('2fdb4fe6-b2f9-4b1d-a71c-8047a106dbce','句  其六','姚孝錫','宋','宋诗','song-poetry','','[]','盤無兼味慙留客，夢厭多岐不到鄉。',16,'全唐诗/poet.song.108000.json','["盤無兼味慙留客，夢厭多岐不到鄉。"]'),
('9e09fc78-16b5-4428-886f-1f742775976a','句  其七','姚孝錫','宋','宋诗','song-poetry','','[]','酒敵餘威翻索莫，詩含幽思倍清新。',16,'全唐诗/poet.song.108000.json','["酒敵餘威翻索莫，詩含幽思倍清新。"]'),
('0491224b-fde8-4fcd-9d69-77da5c3c24c9','句  其八','姚孝錫','宋','宋诗','song-poetry','','[]','岸漲魚吹沫，山空石轉雷。',12,'全唐诗/poet.song.108000.json','["岸漲魚吹沫，山空石轉雷。"]'),
('d357ade2-c330-4e24-bbdc-8a69d7049e0b','句  其九','姚孝錫','宋','宋诗','song-poetry','','[]','舞風初學絮，带雨不成花。',12,'全唐诗/poet.song.108000.json','["舞風初學絮，带雨不成花。"]'),
('7a2f9ba7-2e82-4bfb-83f9-20f744975262','句  其一○','姚孝錫','宋','宋诗','song-poetry','','[]','谷虛繁地籟，境寂散天香。',12,'全唐诗/poet.song.108000.json','["谷虛繁地籟，境寂散天香。"]'),
('b7b1ef9e-67b1-415f-89f0-e1a5e0fa4f31','句  其一一','姚孝錫','宋','宋诗','song-poetry','','[]','雲生古木千章秀，山抱晴川一掌平。',16,'全唐诗/poet.song.108000.json','["雲生古木千章秀，山抱晴川一掌平。"]'),
('ef11d20f-30c7-45e5-8038-ffc05b1bd8ae','句  其一二','姚孝錫','宋','宋诗','song-poetry','','[]','詩忙疏酒盞，俸薄減厨煙。',12,'全唐诗/poet.song.108000.json','["詩忙疏酒盞，俸薄減厨煙。"]'),
('b92cd3b0-7eeb-4948-8491-3256826cbfb8','句  其一三','姚孝錫','宋','宋诗','song-poetry','','[]','玄晏暮年常抱病，子山終日苦思歸。',16,'全唐诗/poet.song.108000.json','["玄晏暮年常抱病，子山終日苦思歸。"]'),
('ba8fa114-41ef-4e9e-8ad4-cf0682c07c3e','偈頌四十一首  其一','釋慧暉','宋','宋诗','song-poetry','','[]','山上欄外，水下檻前。',60,'全唐诗/poet.song.108000.json','["山上欄外，水下檻前。", "夜兔光雪，晝烏輝火。", "黄頭出妙，浄名入玄。", "胡僧印心，盧公傳衣。", "張三野曲，李四樵歌。", "船動碧波，海浸孤天。"]'),
('4e08afd6-c798-4167-9bfb-802e5cfa24d1','偈頌四十一首  其二','釋慧暉','宋','宋诗','song-poetry','','[]','陬月今朝三五風，嶺頭雪氣縛寒松。',64,'全唐诗/poet.song.108000.json','["陬月今朝三五風，嶺頭雪氣縛寒松。", "不知枯木得胡信，含玉靈花春夢中。", "瑞鳥飛來千萬峯，祥魚行過二三衆。", "紛然相見主人眼，歷歷雙眸處處通。"]'),
('15a82771-5cf5-45c9-9cae-4a366967e177','偈頌四十一首  其三','釋慧暉','宋','宋诗','song-poetry','','[]','如月今朝一日晨，風光破玉百花新。',32,'全唐诗/poet.song.108000.json','["如月今朝一日晨，風光破玉百花新。", "西來本祖再來也，萬岳千峯皆是親。"]'),
('197bd1a4-36de-4177-9be7-99bf503c0a80','偈頌四十一首  其四','釋慧暉','宋','宋诗','song-poetry','','[]','竺土之大仙，今日告涅槃。',24,'全唐诗/poet.song.108000.json','["竺土之大仙，今日告涅槃。", "鶴林之米子，當下得枯偏。"]'),
('785047fc-2d7e-4c0d-98dc-e5bd5af638ea','偈頌四十一首  其五','釋慧暉','宋','宋诗','song-poetry','','[]','學者恒沙無一悟，過在他討舌頭路。',32,'全唐诗/poet.song.108000.json','["學者恒沙無一悟，過在他討舌頭路。", "欲得忘形泯蹤跡，努力慇懃空裏步。"]'),
('0169eb7d-35ea-4de2-b68f-0f9304ac95ab','偈頌四十一首  其六','釋慧暉','宋','宋诗','song-poetry','','[]','花月今朝朔旭前，桂輪普轉滿天邊。',32,'全唐诗/poet.song.108000.json','["花月今朝朔旭前，桂輪普轉滿天邊。", "枝花馥郁清香在，烏鵲從來同夜蟾。"]'),
('596a1457-793d-4fe7-8c99-8feb05732cf5','偈頌四十一首  其七','釋慧暉','宋','宋诗','song-poetry','','[]','花落秦川流水香，雨清荷玉妙珠藏。',64,'全唐诗/poet.song.108000.json','["花落秦川流水香，雨清荷玉妙珠藏。", "祇麽堂堂消息子，見來一點不相當。", "靜夜鐘聲樓上冷，殘春岑色付紅陽。", "好是滿堂孤峻處，不知人世見金章。"]'),
('806c48a1-22a7-452a-b95a-d2733230b62c','偈頌四十一首  其八','釋慧暉','宋','宋诗','song-poetry','','[]','桃紅李白落空墀，天碧地青懸錦機。',32,'全唐诗/poet.song.108000.json','["桃紅李白落空墀，天碧地青懸錦機。", "雲鶴出籠過鳥道，飽參密旨不傳時。"]'),
('977bb7e7-dfaf-4d4f-b36c-305c07bc7df8','偈頌四十一首  其九','釋慧暉','宋','宋诗','song-poetry','','[]','余月今朝初一日，滿山綠樹影青青。',32,'全唐诗/poet.song.108000.json','["余月今朝初一日，滿山綠樹影青青。", "異苗繁茂只斯是，大地全分畫不成。"]'),
('2073384d-ccc4-4258-a2cc-9e52d0c191aa','偈頌四十一首  其一○','釋慧暉','宋','宋诗','song-poetry','','[]','千山鬰密處，凉飄洗夏熱。',24,'全唐诗/poet.song.108000.json','["千山鬰密處，凉飄洗夏熱。", "今日正當眼，利劍是鑌鐵。"]'),
('2a455dbf-a933-44ab-8b82-27881df88b2b','偈頌四十一首  其一一','釋慧暉','宋','宋诗','song-poetry','','[]','禁足護生曲直中，安居收念又機杇。',32,'全唐诗/poet.song.108000.json','["禁足護生曲直中，安居收念又機杇。", "一爐香氣香滿室，黄面老師弄拙巧。"]'),
('a21539ef-5b96-4dfd-abb7-d3dfd710ec1c','偈頌四十一首  其一二','釋慧暉','宋','宋诗','song-poetry','','[]','天橋橫海上，石人走玉階。',28,'全唐诗/poet.song.108000.json','["天橋橫海上，石人走玉階。", "玄源歌，孰得唱。", "妙唱奇，豈得知。"]'),
('30a09e7b-369e-49a2-b136-7fdb4b12bdfe','偈頌四十一首  其一三','釋慧暉','宋','宋诗','song-poetry','','[]','臯月今朝初旭光，玉輝破暗露堂堂。',32,'全唐诗/poet.song.108000.json','["臯月今朝初旭光，玉輝破暗露堂堂。", "日日分明久遠事，威音那畔是時祥。"]'),
('af10d399-7d0a-4f15-8f70-528c7ee8ac53','偈頌四十一首  其一四','釋慧暉','宋','宋诗','song-poetry','','[]','君看五月半旬颸，山上雪花滿地飛。',64,'全唐诗/poet.song.108000.json','["君看五月半旬颸，山上雪花滿地飛。", "烏鷄昨夜入雲外，鷺鶴今朝出紫微。", "木馬聲聲嘶北風，金鵝口口啼南枝。", "石翁氣瘦運步斷，玉士情豐豎拳稀。"]'),
('63a426c7-f740-4412-8b3f-ce4d30f8c51a','偈頌四十一首  其一五','釋慧暉','宋','宋诗','song-poetry','','[]','他家自有通霄路，何用從容求別路。',32,'全唐诗/poet.song.108000.json','["他家自有通霄路，何用從容求別路。", "巍巍絕頂落潭底，峭峭家風吹滿路。"]'),
('1bfb54ec-3175-43cd-b53e-269d75dfc958','偈頌四十一首  其一六','釋慧暉','宋','宋诗','song-poetry','','[]','且月今朝半夏辰，修行道者有疏親。',48,'全唐诗/poet.song.108000.json','["且月今朝半夏辰，修行道者有疏親。", "明頭合暗賓中主，暗裏含明主中賓。", "暗暗未明位裏真，明明不暗目前人。"]'),
('726dfebd-cfb4-4698-9928-f1bdf1b33fea','偈頌四十一首  其一七','釋慧暉','宋','宋诗','song-poetry','','[]','寂滅真功元無體，無功妙旨太深深。',32,'全唐诗/poet.song.108000.json','["寂滅真功元無體，無功妙旨太深深。", "同中有異麤中細，異中有同念裏心。"]'),
('f78fdca7-6cfa-42cb-ad1b-c93d80cb1aed','偈頌四十一首  其一八','釋慧暉','宋','宋诗','song-poetry','','[]','夜間洗熱凉飄飄，六月皎然滿天雪。',32,'全唐诗/poet.song.108000.json','["夜間洗熱凉飄飄，六月皎然滿天雪。", "青林日晚人歸宅，紅谷天明客喚月。"]'),
('3074b461-3e0a-42b7-9056-d62d422bd581','偈頌四十一首  其一九','釋慧暉','宋','宋诗','song-poetry','','[]','玉機轉側金堂冷，石室斜開鐵戶明。',32,'全唐诗/poet.song.108000.json','["玉機轉側金堂冷，石室斜開鐵戶明。", "木雞喚月壺天曉，泥牛吼花客游城。"]'),
('ca841259-f3aa-4db6-9586-e4e32beda7b9','偈頌四十一首  其二○','釋慧暉','宋','宋诗','song-poetry','','[]','諸佛出身處，東山水上行。',24,'全唐诗/poet.song.108000.json','["諸佛出身處，東山水上行。", "宸閨垂玉簾，雲榻擁天青。"]'),
('2752ca77-1148-4eb0-a709-4957a0d38f0e','偈頌四十一首  其二一','釋慧暉','宋','宋诗','song-poetry','','[]','相月今朝日氣旭，梧桐一葉落金風。',96,'全唐诗/poet.song.108000.json','["相月今朝日氣旭，梧桐一葉落金風。", "秋聲瀟索黄文玉，山上滿天愁殺中。", "目前機用無分外，那裏妙章絕萬工。", "破夢蝶魂飛大空，失船釣客艤孤篷。", "胡文新送北來鴻，鄉信始見他日功。", "舊山山轉月明後，歸路悠悠玉𤪑瓏。"]'),
('0d5ccb37-937e-4465-a6ae-899af6a50970','偈頌四十一首  其二二','釋慧暉','宋','宋诗','song-poetry','','[]','金氣黄楓半葉紅，晚來漁客倚青松。',60,'全唐诗/poet.song.108000.json','["金氣黄楓半葉紅，晚來漁客倚青松。", "多多動夢夜凉路，處處偷光午月峰。", "長安萬里景，大陽千里道。", "大悲閣前是鼎州，黄鶴樓前鸚鵡洲。"]'),
('c6a6d90a-07f2-44f3-995e-d9e034bdf790','偈頌四十一首  其二三','釋慧暉','宋','宋诗','song-poetry','','[]','殺氣到來黄葉秋，梧桐老冷隨河流。',52,'全唐诗/poet.song.108000.json','["殺氣到來黄葉秋，梧桐老冷隨河流。", "人間天上無分曉，從古至今誰得酬。", "恁麽辯得，尚带滯留。", "別得一路，正絕蹤由。"]'),
('47c86147-d9bd-4e63-8686-acef8c94033c','偈頌四十一首  其二四','釋慧暉','宋','宋诗','song-poetry','','[]','壯月今朝半月明，上來衲子眼睲睲。',32,'全唐诗/poet.song.108000.json','["壯月今朝半月明，上來衲子眼睲睲。", "難瞞衆眼病堂尅，何用洞家兒子情。"]'),
('8b857e8c-14c0-4a5d-bd3d-071eb97832e3','偈頌四十一首  其二五','釋慧暉','宋','宋诗','song-poetry','','[]','傳家清白，字字廓脫。',44,'全唐诗/poet.song.108000.json','["傳家清白，字字廓脫。", "玉袋金針，鋒鋒通達。", "今夜一輪月，千山萬派流。", "不覺劫壺鐵，巍然沒去留。"]'),
('ea5d2505-b675-4702-828f-c6f828661f86','偈頌四十一首  其二六','釋慧暉','宋','宋诗','song-poetry','','[]','玄月今朝白菊辰，含珠天草未開金。',32,'全唐诗/poet.song.108000.json','["玄月今朝白菊辰，含珠天草未開金。", "重陽九日初陽後，吹起香烟風正新。"]'),
('131f8be3-bab5-423f-8719-ad99262c0512','偈頌四十一首  其二七','釋慧暉','宋','宋诗','song-poetry','','[]','鐵夫破夢五更前，石人開眼一壺天。',64,'全唐诗/poet.song.108000.json','["鐵夫破夢五更前，石人開眼一壺天。", "木馬過閭風化後，玉虎振威野渡邊。", "主人穩坐草堂前，硬翁獨卧萬芊天。", "三箇胡猻弄錢夜，格外難求宿鶴邊。"]'),
('f2dc85b7-7f0a-4b73-b1bd-e3073c93adba','偈頌四十一首  其二八','釋慧暉','宋','宋诗','song-poetry','','[]','鬼箭南山射石虎，神鋒北岳刺驪龍。',32,'全唐诗/poet.song.108000.json','["鬼箭南山射石虎，神鋒北岳刺驪龍。", "好是滿堂霜月夜，寒冰出火舊家風。"]'),
('af67f145-27b8-4e94-aa4e-95f89c2187c9','偈頌四十一首  其二九','釋慧暉','宋','宋诗','song-poetry','','[]','陽月今朝初夜間，霜風吹地過金關。',32,'全唐诗/poet.song.108000.json','["陽月今朝初夜間，霜風吹地過金關。", "今宵分曉開爐火，仁者眉毛燒却寒。"]'),
('38fd3e53-37ff-4e3e-9621-749cf79f4377','偈頌四十一首  其三○','釋慧暉','宋','宋诗','song-poetry','','[]','小春霜刃，大家雪機。',105,'全唐诗/poet.song.108000.json','["小春霜刃，大家雪機。", "一堂禪侶，三世結制。", "時光可惜，歲花不留。", "自晨至暮，吃飯飲茶。", "道者一箇，無得禪心。", "從生至老，著衣談笑。", "道流半箇，莫知自心。", "徒勞念情，不識玄旨，苦哉悲矣。", "貧道孤老，走年難繫。", "謹勸雲衆，一生歸信。"]'),
('9cfbca7d-f92a-48e0-96be-ef3920b1af94','偈頌四十一首  其三一','釋慧暉','宋','宋诗','song-poetry','','[]','彈指圓成八萬門，掌中握却一乾坤。',32,'全唐诗/poet.song.108000.json','["彈指圓成八萬門，掌中握却一乾坤。", "鐵圍倒入黄泉底，一句截流萬水源。"]'),
('7156db1f-2dd6-4066-9128-d88fa1436c1c','偈頌四十一首  其三二','釋慧暉','宋','宋诗','song-poetry','','[]','辜月今朝初一日，正當冬至滿霜月。',32,'全唐诗/poet.song.108000.json','["辜月今朝初一日，正當冬至滿霜月。", "一陽佳節大家章，字字含玄向白日。"]'),
('390c691e-8d4a-40c7-b825-045cb43f3552','偈頌四十一首  其三三','釋慧暉','宋','宋诗','song-poetry','','[]','風吹松雪月當空，一色功中轉步同。',32,'全唐诗/poet.song.108000.json','["風吹松雪月當空，一色功中轉步同。", "刖路分時無雪月，合同一色落功功。"]'),
('b949c970-fa91-49d1-90da-258a22dbc2c6','偈頌四十一首  其三四','釋慧暉','宋','宋诗','song-poetry','','[]','璞玉光寒冰雪氣，松柏操彰湛水裏。',32,'全唐诗/poet.song.108000.json','["璞玉光寒冰雪氣，松柏操彰湛水裏。", "分明消息砂中金，丈夫自有沖天志。"]'),
('3df911a9-924f-437b-83af-fd99e9d752b0','偈頌四十一首  其三五','釋慧暉','宋','宋诗','song-poetry','','[]','除月今朝吉日朝，寒雲斷路韞天橋。',32,'全唐诗/poet.song.108000.json','["除月今朝吉日朝，寒雲斷路韞天橋。", "紛飛白雪象王窟，騎底普賢在昨霄。"]'),
('5b18b710-93e3-495f-bd0c-b49c35add1f8','偈頌四十一首  其三六','釋慧暉','宋','宋诗','song-poetry','','[]','寒夜無炭衰老衣，凉機透骨古堂微。',32,'全唐诗/poet.song.108000.json','["寒夜無炭衰老衣，凉機透骨古堂微。", "霜辛雪苦慕先律，雨宿風餐圓後奇。"]'),
('ae949b06-2a6a-4a45-9242-c95609b55e19','偈頌四十一首  其三七','釋慧暉','宋','宋诗','song-poetry','','[]','北面半窗陰已極，南方全室陽斜得。',32,'全唐诗/poet.song.108000.json','["北面半窗陰已極，南方全室陽斜得。", "不關陰氣與陽光，嶺上雪寒白似黑。"]'),
('66b1b81f-7a59-48b2-a52f-748e79a1e55f','偈頌四十一首  其三八','釋慧暉','宋','宋诗','song-poetry','','[]','寒凉徹骨時，通身難去處。',24,'全唐诗/poet.song.108000.json','["寒凉徹骨時，通身難去處。", "其間有眼在，新豐一曲子。"]'),
('e96bfb80-21dc-4ec3-81f2-c2dfb7c03a58','偈頌四十一首  其三九','釋慧暉','宋','宋诗','song-poetry','','[]','鐵樹風花物外春，一陽未發不傳真。',32,'全唐诗/poet.song.108000.json','["鐵樹風花物外春，一陽未發不傳真。", "自斯織出錦機夢，江月布祥碧浪新。"]'),
('0318e87a-e22f-40bb-aa40-d052038ae063','偈頌四十一首  其四○','釋慧暉','宋','宋诗','song-poetry','','[]','今宵分歲限陰陽，賓主交和曾不藏。',32,'全唐诗/poet.song.108000.json','["今宵分歲限陰陽，賓主交和曾不藏。", "寒雪苦辛霜後路，明朝明旭露春芳。"]'),
('c473fa4d-1da0-4e97-8cc0-325a0598c0a0','偈頌四十一首  其四一','釋慧暉','宋','宋诗','song-poetry','','[]','玉珠連朵萬年松，金鶴飛梢一樣桐。',32,'全唐诗/poet.song.108000.json','["玉珠連朵萬年松，金鶴飛梢一樣桐。", "三吉九祥當現座，千銀七寶浄慈峯。"]'),
('0fac4379-daa0-4e6a-9023-aa511052fdff','偈頌三十首  其一','釋慧暉','宋','宋诗','song-poetry','','[]','只箇玄妙訣，從來無異轍。',48,'全唐诗/poet.song.108000.json','["只箇玄妙訣，從來無異轍。", "撥開千嶂雲，放出一天月。", "建化門頭事，山僧未曾說。", "再來花木春，佛祖也難决。"]'),
('cf6b4df5-0449-44b2-82c0-8d7e695fdcd0','偈頌三十首  其二','釋慧暉','宋','宋诗','song-poetry','','[]','衲僧活眼睛，見破四天明。',24,'全唐诗/poet.song.108000.json','["衲僧活眼睛，見破四天明。", "六門之活計，處處而現成。"]'),
('a54691d4-0d8a-40db-b14b-33dc0713f170','偈頌三十首  其三','釋慧暉','宋','宋诗','song-poetry','','[]','家風是自己，自己是家風。',24,'全唐诗/poet.song.108000.json','["家風是自己，自己是家風。", "一如身心眼，全體是玄翁。"]'),
('1e047808-3819-4eb7-87b0-10b147dcf6f5','偈頌三十首  其四','釋慧暉','宋','宋诗','song-poetry','','[]','直把須彌鎚子，正打虛空皷子。',30,'全唐诗/poet.song.108000.json','["直把須彌鎚子，正打虛空皷子。", "穩坐寥寥而不妨，全身寂寂而忘志。"]'),
('c6b11b2a-284f-4822-a746-6e2ff8ddba4d','偈頌三十首  其五','釋慧暉','宋','宋诗','song-poetry','','[]','吾門廣大，從古難入。',30,'全唐诗/poet.song.108000.json','["吾門廣大，從古難入。", "徒展兩脚，不蹈階級。", "元非宮內，豈得建立。"]'),
('8489f165-0a8a-4fcc-b332-c85a22ab2973','偈頌三十首  其六','釋慧暉','宋','宋诗','song-poetry','','[]','青山山上，白雲雲下。',20,'全唐诗/poet.song.108000.json','["青山山上，白雲雲下。", "戶外水寒，波心船點。"]'),
('83e9a01d-be69-418f-a78b-bd04229ca7b0','偈頌三十首  其七','釋慧暉','宋','宋诗','song-poetry','','[]','妙處徹底妙，玄處徹底玄。',24,'全唐诗/poet.song.108000.json','["妙處徹底妙，玄處徹底玄。", "獨知分外事，誰見壺中天。"]'),
('6bd93b7d-aa74-4604-9481-42b36d32576e','偈頌三十首  其八','釋慧暉','宋','宋诗','song-poetry','','[]','真到做處，清虛妙體。',20,'全唐诗/poet.song.108000.json','["真到做處，清虛妙體。", "時時隨後，步步在前。"]'),
('0f8996bf-d538-4004-9ab5-4f9ffcc9a845','偈頌三十首  其九','釋慧暉','宋','宋诗','song-poetry','','[]','以大圓覺爲我伽藍，山河大地日月星辰。',36,'全唐诗/poet.song.108000.json','["以大圓覺爲我伽藍，山河大地日月星辰。", "身心安居平等性智，天上天下唯我獨尊。"]'),
('df92f611-8ffa-45ba-b572-a65304775c9b','偈頌三十首  其一○','釋慧暉','宋','宋诗','song-poetry','','[]','玉龍起雨上東天，石虎出風下北山。',32,'全唐诗/poet.song.108000.json','["玉龍起雨上東天，石虎出風下北山。", "夜兔穿雲南海底，晝烏破暗西畔岩。"]'),
('27c63639-00e9-459d-914e-d0bb9214948d','偈頌三十首  其一一','釋慧暉','宋','宋诗','song-poetry','','[]','家傳妙旨不言語，洞上真機絕外來。',32,'全唐诗/poet.song.108000.json','["家傳妙旨不言語，洞上真機絕外來。", "若有人云知父道，孤然孫子笑咍咍。"]'),
('5e1d97e9-884d-4e8d-9330-d55c0d5b3770','偈頌三十首  其一二','釋慧暉','宋','宋诗','song-poetry','','[]','路遮戶外，家包雲中。',20,'全唐诗/poet.song.108000.json','["路遮戶外，家包雲中。", "客游三月，主居月宮。"]'),
('06b408ea-6ec6-45b9-b464-47d627f7141c','偈頌三十首  其一三','釋慧暉','宋','宋诗','song-poetry','','[]','風波滅盡而悔當時之事，碧海澄明而恨十分之恩。',44,'全唐诗/poet.song.108000.json','["風波滅盡而悔當時之事，碧海澄明而恨十分之恩。", "潭水月落而带清光之影，壺天雲盡而存青霄之晴。"]'),
('ca2172da-cad1-45fa-98ca-46c34fa8a253','偈頌三十首  其一四','釋慧暉','宋','宋诗','song-poetry','','[]','稜稜一氣未生，凄凄一神未現。',42,'全唐诗/poet.song.108000.json','["稜稜一氣未生，凄凄一神未現。", "默默風未起波，皎皎月未發光。", "歷歷萬象未亂，明明森羅未參。"]'),
('7befb971-8508-4268-bb60-409ac251f873','偈頌三十首  其一五','釋慧暉','宋','宋诗','song-poetry','','[]','佛日高懸，祖月彌朗。',30,'全唐诗/poet.song.108000.json','["佛日高懸，祖月彌朗。", "僧雲漫漫，法雨浩浩。", "禪林花發，教風春迎。"]'),
('b5cc1c61-59a1-4c11-b177-6d9bc266f0e7','偈頌三十首  其一六','釋慧暉','宋','宋诗','song-poetry','','[]','春色千林花正開，秋潭萬水月猶明。',32,'全唐诗/poet.song.108000.json','["春色千林花正開，秋潭萬水月猶明。", "夏熱綠楊影滿地，冬寒白樹覆前庭。"]'),
('19b4c1fe-5965-4aa5-80c4-d64d57186561','偈頌三十首  其一七','釋慧暉','宋','宋诗','song-poetry','','[]','少室胡僧，履子留隻。',40,'全唐诗/poet.song.108000.json','["少室胡僧，履子留隻。", "米樹應供，趺子出雙。", "新豐老人，問殺首座。", "大陽兄者，兼養青鷂。"]'),
('50b99625-827c-49af-a0eb-6bf39de6d3c6','偈頌三十首  其一八','釋慧暉','宋','宋诗','song-poetry','','[]','枯木雲籠秀，雲中袍玉立。',48,'全唐诗/poet.song.108000.json','["枯木雲籠秀，雲中袍玉立。", "寒潭月夜圓，潭底侵魚入。", "回頭開正眼，頭上戴帽出。", "芳草破春烟，草芊拂天內。"]'),
('0953c86c-7103-4b4b-9901-8801ea1bf4a7','偈頌三十首  其一九','釋慧暉','宋','宋诗','song-poetry','','[]','綠岩枯木，不落人間。',40,'全唐诗/poet.song.108000.json','["綠岩枯木，不落人間。", "紅谷芳草，不厭溫寒。", "西南東北，各不相關。", "三段玄處，正開眼看。"]'),
('b3322416-8020-4305-ba6b-d7c5e1886b9f','偈頌三十首  其二○','釋慧暉','宋','宋诗','song-poetry','','[]','圓蟾出冷，晶旭入暖。',20,'全唐诗/poet.song.108000.json','["圓蟾出冷，晶旭入暖。", "惠光破暗，才輝照明。"]'),
('52983060-2793-4d1c-a075-568f469cd661','偈頌三十首  其二一','釋慧暉','宋','宋诗','song-poetry','','[]','運步堂堂，通身歷歷。',30,'全唐诗/poet.song.108000.json','["運步堂堂，通身歷歷。", "東道西說，南來北去。", "全得寸心，直用尺情。"]'),
('ee65bfac-9706-4254-b096-388df2920706','偈頌三十首  其二二','釋慧暉','宋','宋诗','song-poetry','','[]','古佛道場，尚乘車子。',92,'全唐诗/poet.song.108000.json','["古佛道場，尚乘車子。", "澄源潭水，猶棹孤舟。", "夜鶴穿潭底，雲月落銀籠。", "天龍無雨，汗馬而無鞭也。", "從此出生犢牛兒，金吼銀聲滿蘆水。", "微毛依舊正受中，玄角又带漫雪草。", "一回倒騎牧童夢，數笛吹來樵子歌。"]'),
('def92398-7c84-43ea-b211-4ce6911e1baf','偈頌三十首  其二三','釋慧暉','宋','宋诗','song-poetry','','[]','行脚大事，一段宗要。',42,'全唐诗/poet.song.108000.json','["行脚大事，一段宗要。", "直拈起兔角佛杖，正舉著龜毛祖拂。", "若人拈起舉著時，人盡有禮謝在時。"]'),
('635dd9bd-7df3-415a-8ae3-60a25067f3f0','偈頌三十首  其二四','釋慧暉','宋','宋诗','song-poetry','','[]','花露殘春一樣芳，月餘潭底萬年光。',32,'全唐诗/poet.song.108000.json','["花露殘春一樣芳，月餘潭底萬年光。", "水脈冷寒凉焇焇，雲形虛幕露堂堂。"]'),
('9e94f5cf-6d9b-4460-8a04-158c7fcd67b4','偈頌三十首  其二五','釋慧暉','宋','宋诗','song-poetry','','[]','春夢朦朧，秋月玲瓏。',20,'全唐诗/poet.song.108000.json','["春夢朦朧，秋月玲瓏。", "夏凉寂寂，冬寒空空。"]'),
('f3fa41cb-05c8-400c-92e9-45334cdfa224','偈頌三十首  其二六','釋慧暉','宋','宋诗','song-poetry','','[]','梁土皇帝，南天太子。',52,'全唐诗/poet.song.108000.json','["梁土皇帝，南天太子。", "相見端的，不識妙旨。", "廓然不識莫公私，太子皇帝對面時。", "一片檀香爐上火，殘紅吹起發花枝。"]'),
('55d108db-daab-4f0f-9914-051228596bb0','偈頌三十首  其二七','釋慧暉','宋','宋诗','song-poetry','','[]','靈劍刃輝在匣中，清光所照侵虛空。',32,'全唐诗/poet.song.108000.json','["靈劍刃輝在匣中，清光所照侵虛空。", "密通消息不傳句，天上人間功不同。"]'),
('288dec8e-e43f-4868-9f58-beada587e45d','偈頌三十首  其二八','釋慧暉','宋','宋诗','song-poetry','','[]','有時破關知落處，有時透關契密旨。',48,'全唐诗/poet.song.108000.json','["有時破關知落處，有時透關契密旨。", "有時妙容拜位裏，有時光燭囑機頭。", "箇中有體用賓主，箇中有宛轉傍參。"]'),
('4b0212c2-5a33-4b38-a6c4-5267d17739ab','偈頌三十首  其二九','釋慧暉','宋','宋诗','song-poetry','','[]','朝說暮說，出廣長舌。',20,'全唐诗/poet.song.108000.json','["朝說暮說，出廣長舌。", "坐卧經行，萬里鑌鐵。"]'),
('fd2fc446-a183-46d2-a4f3-8d695a595c93','偈頌三十首  其三○','釋慧暉','宋','宋诗','song-poetry','','[]','一段大事，古今難通。',40,'全唐诗/poet.song.108000.json','["一段大事，古今難通。", "三乘曲說，去來易空。", "衲僧眼目，端的無工。", "禪和信趣，脫然絕蹤。"]'),
('72953887-8944-4b6f-ae07-5083565b4d16','偈頌三十首  其三一','釋慧暉','宋','宋诗','song-poetry','','[]','不夜真燈，破夜心月。',30,'全唐诗/poet.song.108000.json','["不夜真燈，破夜心月。", "穿日玄談，不日妙訣。", "一句了然，不涉途轍。"]'),
('c160b206-dfc7-48c8-bc6a-c0a77989c173','偈十首  其一','釋慧暉','宋','宋诗','song-poetry','','[]','外罷諸緣絕言語，內無喘息合幽玄。',32,'全唐诗/poet.song.108000.json','["外罷諸緣絕言語，內無喘息合幽玄。", "心如牆壁忘功處，以入道源空劫前。"]'),
('d0cc4ec1-7913-40b6-9e83-eef1e3351279','偈十首  其二','釋慧暉','宋','宋诗','song-poetry','','[]','一回轉意光，千里絕情方。',24,'全唐诗/poet.song.108000.json','["一回轉意光，千里絕情方。", "悟後夢醒後，孤然坐古堂。"]'),
('02ced41c-ad62-44e7-a72b-814126c23508','偈十首  其三','釋慧暉','宋','宋诗','song-poetry','','[]','少而可努力，老而可歇心。',24,'全唐诗/poet.song.108000.json','["少而可努力，老而可歇心。", "都盧懶萬事，雙眸淚濕襟。"]'),
('ca02b139-4dc8-4dfc-a220-a827388a9167','偈十首  其四','釋慧暉','宋','宋诗','song-poetry','','[]','直下撥開木上座，驀端握却毫長老。',32,'全唐诗/poet.song.108000.json','["直下撥開木上座，驀端握却毫長老。", "衲僧氣宇乾坤外，一夜寒冰通體到。"]'),
('735760a4-8d80-4a70-95f9-d902ace000e7','偈十首  其五','釋慧暉','宋','宋诗','song-poetry','','[]','玉人深睡澄潭妙，石漢眼開花岳笑。',32,'全唐诗/poet.song.108000.json','["玉人深睡澄潭妙，石漢眼開花岳笑。", "不是今朝新發悟，三生大定了知少。"]'),
('1f174b65-d363-4bc0-a26d-fd15304ed654','偈十首  其六','釋慧暉','宋','宋诗','song-poetry','','[]','一回得妙，二度忘妙。',50,'全唐诗/poet.song.108000.json','["一回得妙，二度忘妙。", "急急歸雲，堆堆白雲。", "別增真照，殊出月照。", "芬芸百花，馥郁紅花。", "春窗暖笑，破家好笑。"]'),
('f47dd675-74f4-44b1-902b-34c769b6c53a','偈十首  其七','釋慧暉','宋','宋诗','song-poetry','','[]','人間無佛時，早是如來機。',44,'全唐诗/poet.song.108000.json','["人間無佛時，早是如來機。", "世界無塵境，新看深妙奇。", "若具此眼，便人天師。", "忽有這漢，何用擬議。"]'),
('695fd739-0b23-4441-951e-7181dfafcc95','偈十首  其八','釋慧暉','宋','宋诗','song-poetry','','[]','定林隻履，天台楖𣗖。',52,'全唐诗/poet.song.108000.json','["定林隻履，天台楖𣗖。", "鈯斧住山，橫擔鑌鐵。", "獨有雲床老胡僧，徒見夜中天上月。", "目前無極分外心，少室花容是妙訣。"]'),
('4ceeda00-840f-4ca3-9f78-68fa913f3a17','偈十首  其九','釋慧暉','宋','宋诗','song-poetry','','[]','正偏融融而路斷於鳥道之表，君臣堂堂而容儼於玉殿之中。',46,'全唐诗/poet.song.108000.json','["正偏融融而路斷於鳥道之表，君臣堂堂而容儼於玉殿之中。", "到底難說，妙處絕同。", "別得傍道，見萬年松。"]'),
('36fb4e4c-0b93-4a97-8b96-7e8705fe607c','偈十首  其一○','釋慧暉','宋','宋诗','song-poetry','','[]','皎皎而月澄，嶺上之孤松。',50,'全唐诗/poet.song.108000.json','["皎皎而月澄，嶺上之孤松。", "凄凄而風渡，半夜之空中。", "深深也妙訣，自坐少林之峯。", "了了也真氣，元居虛谷之功。"]'),
('67c97156-4495-4611-bf78-33830be4c2c8','頌十六首  其一','釋慧暉','宋','宋诗','song-poetry','','[]','一片天光三五風，玉墀吹斷嶺頭松。',64,'全唐诗/poet.song.108000.json','["一片天光三五風，玉墀吹斷嶺頭松。", "巍然山上澄湛下，忽爾雲同霜月中。", "堆堆全體乾坤裏，密密滿心天地表。", "碌碌𥐢𥐢通用眼，驪珠擊碎草芊忡。"]'),
('aa9c7b74-3a1d-429f-80df-ba02121d9e71','頌十六首  其二','釋慧暉','宋','宋诗','song-poetry','','[]','路斷無依著，滿船乘雪月。',48,'全唐诗/poet.song.108000.json','["路斷無依著，滿船乘雪月。", "夜午不相關，全體蹈金鐵。", "唱出歸家歌，恣吹還鄉曲。", "從斯野子夢，徒爾難分節。"]'),
('abc381c8-1a52-469a-b8f7-41145994bf95','頌十六首  其三','釋慧暉','宋','宋诗','song-poetry','','[]','轉功就位，獨看古風。',50,'全唐诗/poet.song.108000.json','["轉功就位，獨看古風。", "再通消息，轉位就功。", "功位齊顯，千岳萬峯。", "又轉春芳，俱隠位功。", "畢竟不用，頻弄萬工。"]'),
('aa86cfd4-e864-47c7-a094-1e747fa5c125','頌十六首  其四','釋慧暉','宋','宋诗','song-poetry','','[]','祖翁四借吾門事，密密疏疏著眼視。',64,'全唐诗/poet.song.108000.json','["祖翁四借吾門事，密密疏疏著眼視。", "位裏有功隠裏顯，功中有位弟中師。", "功位不須功位外，主賓不揀主賓機。", "偏正回互沒分曉，樵子笠穿戴月歸。"]'),
('65eb80d1-a086-48dd-b078-d3bfd6123326','頌十六首  其五','釋慧暉','宋','宋诗','song-poetry','','[]','不行心處，不盡凡心。',108,'全唐诗/poet.song.108000.json','["不行心處，不盡凡心。", "若於心處見於凡心，不妨箇箇了得心心。", "不掛本衣，不著元裳。", "自求本衣，再裝元裳。", "不用人人，會取堂堂。", "何須正當，何坐空床。", "正當恁麽，尚在虛旁。", "切忌未生，坐妙路方。", "如起歸信，更堪厚賞。", "畢竟捨去，一樹花香。"]'),
('c298d7bf-b05a-4b56-bc5a-36c72baa7301','頌十六首  其六','釋慧暉','宋','宋诗','song-poetry','','[]','上正之器根密密而難言，中當之器要了了而幽玄，下偏之器見明明而滿天。',55,'全唐诗/poet.song.108000.json','["上正之器根密密而難言，中當之器要了了而幽玄，下偏之器見明明而滿天。", "學人分上事紛紛而不玄，主家活計事寂寂而不傳。"]'),
('bc2463ff-9b90-4b21-a957-f9d7fd78d5be','頌十六首  其七','釋慧暉','宋','宋诗','song-poetry','','[]','不覺蹈過鑌鐵關，悠然穩坐月蘆寒。',32,'全唐诗/poet.song.108000.json','["不覺蹈過鑌鐵關，悠然穩坐月蘆寒。", "別得妙方更難到，巍巍頂相若當看。"]'),
('4b607245-2aac-434d-b77d-421512fde0b0','頌十六首  其八','釋慧暉','宋','宋诗','song-poetry','','[]','高高而獨坐，便是見滲漏。',48,'全唐诗/poet.song.108000.json','["高高而獨坐，便是見滲漏。", "寥寥而氣浄，正是情滲漏。", "明明而神露，悉是語滲漏。", "畢竟同混處，從古絕滲漏。"]'),
('5bcfc6aa-82c9-4452-89f5-5d352c775f1e','頌十六首  其九','釋慧暉','宋','宋诗','song-poetry','','[]','不傳之傳句，先賢也不傳。',138,'全唐诗/poet.song.108000.json','["不傳之傳句，先賢也不傳。", "佛祖未出興，早是有付傳。", "不妙之妙句，古聖也難宣。", "黄頭碧眼老，如何及言宣。", "不真之真句，人天未生前。", "若以言道趣，只徒在目前。", "不傳妙真句，三世不變遷。", "畢竟道人眼，萬歲絕易遷。", "寥寥而本傳不傳之傳，明明而今妙不妙妙，玄密密而深到不真真玄。", "畢竟道人眼，億劫不異遷。"]'),
('166ccc2c-d420-4c2b-865f-ad4c695fbda1','頌十六首  其一○','釋慧暉','宋','宋诗','song-poetry','','[]','參得五語，功勳始成。',70,'全唐诗/poet.song.108000.json','["參得五語，功勳始成。", "有時不說，恣口說行。", "有時不玄，空失妙正。", "有時不顯，纔一氣生。", "有時不出，獨來水清。", "有時不生，未開眼睛。", "畢竟見得，連天曉星。"]'),
('9d4a5785-0267-4304-a670-f45ff409739b','頌十六首  其一一','釋慧暉','宋','宋诗','song-poetry','','[]','黄面手中花一枝，頭陀微笑識人希。',32,'全唐诗/poet.song.108000.json','["黄面手中花一枝，頭陀微笑識人希。", "人天百萬共尊貴，何不打頭勘座師。"]'),
('226b742f-7cde-47b0-8fa9-0e2dfad37d6c','頌十六首  其一二','釋慧暉','宋','宋诗','song-poetry','','[]','蹈泥運土自參機，收足展掌自到奇。',32,'全唐诗/poet.song.108000.json','["蹈泥運土自參機，收足展掌自到奇。", "箇箇須應曾轉撥，真燈破夜意光微。"]'),
('769ef572-61c3-4ccf-b657-e2d7c8125ec9','頌十六首  其一三','釋慧暉','宋','宋诗','song-poetry','','[]','武帝功德人天果，圓覺無功真到心。',32,'全唐诗/poet.song.108000.json','["武帝功德人天果，圓覺無功真到心。", "清浄本然誰會得，碧蘿深鎖古山岑。"]'),
('2b938c8c-acf2-4b2a-a7d9-0b381f869b8c','頌十六首  其一四','釋慧暉','宋','宋诗','song-poetry','','[]','曠劫無塵世界中，恣吹野曲晚來風。',32,'全唐诗/poet.song.108000.json','["曠劫無塵世界中，恣吹野曲晚來風。", "看看本來無一物，滿山雲樹雪花紅。"]'),
('747809bd-f8e7-4b91-b946-4e1f8731e4bd','頌十六首  其一五','釋慧暉','宋','宋诗','song-poetry','','[]','明明梵音海潮音，青青勝彼世間音。',32,'全唐诗/poet.song.108000.json','["明明梵音海潮音，青青勝彼世間音。", "雨則慧日破諸闇，日則名爲觀世音。"]'),
('7266ea2f-e08a-422e-a002-7b650a7d2c93','頌十六首  其一六','釋慧暉','宋','宋诗','song-poetry','','[]','可憐多客滿堂僧，打睡送時亂佛承。',32,'全唐诗/poet.song.108000.json','["可憐多客滿堂僧，打睡送時亂佛承。", "悟入至今無一箇，驀頭端的盡三乘。"]'),
('8805d260-9819-4c89-aa93-efe15e44e103','和芙蓉和尚四句偈頌 妙唱不干舌','釋慧暉','宋','宋诗','song-poetry','','[]','如如寂滅自無情，一句從來本見成。',32,'全唐诗/poet.song.108000.json','["如如寂滅自無情，一句從來本見成。", "舌運廣長元不間，雪峯相見望州亭。"]'),
