('daca435d-811b-405c-9220-9ab3ae5db1ee','五位頌  其三','釋慧暉','宋','宋诗','song-poetry','','[]','正中來，帝命旁分展化才。',28,'全唐诗/poet.song.108000.json','["正中來，帝命旁分展化才。", "杲日初昇沙界靜，靈然曾不带纖埃。"]'),
('27ff9ab4-cf39-4726-98d2-b382bd3021a0','五位頌  其四','釋慧暉','宋','宋诗','song-poetry','','[]','兼中至，長安大道閑遊戲。',28,'全唐诗/poet.song.108000.json','["兼中至，長安大道閑遊戲。", "處處無私空合空，法法同歸水投水。"]'),
('c1f1e582-f92a-4155-873d-d212d9f92411','五位頌  其五','釋慧暉','宋','宋诗','song-poetry','','[]','兼中到，白雲斷處家山妙。',28,'全唐诗/poet.song.108000.json','["兼中到，白雲斷處家山妙。", "撲碎驪龍明月珠，崑崙入海無消耗。"]'),
('4a3bd10c-d7d9-4b83-bb12-9a6c3431772a','維摩大士不答文殊問如何是菩薩入不二法門頌','釋慧暉','宋','宋诗','song-poetry','','[]','浄名大士口如盆，一默無端拏雷雲。',64,'全唐诗/poet.song.108000.json','["浄名大士口如盆，一默無端拏雷雲。", "十聖瘦然居足下，三賢了爾失全分。", "飄飄而出溪風骨，濯濯而清月水紋。", "天外孤松峯頂聳，晚樓霜雪夢猶昏。"]'),
('62d2c25f-c764-47fb-9b7b-815a608707ea','答雲居西和尚偈','釋慧暉','宋','宋诗','song-poetry','','[]','和尚不知禪，困來便打眠。',24,'全唐诗/poet.song.108000.json','["和尚不知禪，困來便打眠。", "泥牛喫水草，木馬咬瓦磚。"]'),
('fe44bbfb-d61c-4113-ac69-98852dfec93c','偈四首  其一','釋慧暉','宋','宋诗','song-poetry','','[]','朔風凜凜掃寒林，葉落歸根露赤心。',64,'全唐诗/poet.song.108000.json','["朔風凜凜掃寒林，葉落歸根露赤心。", "萬派朝宗船到岸，六窗虛映芥投針。", "本成現，莫他尋，性地閑閑耀古今。", "戶外凍消春色動，四山渾作木龍吟。"]'),
('2443861d-55cf-496a-87ba-fb2edbff3670','偈四首  其二','釋慧暉','宋','宋诗','song-poetry','','[]','巢知風，穴知雨，甜者甜兮苦者苦。',48,'全唐诗/poet.song.108000.json','["巢知風，穴知雨，甜者甜兮苦者苦。", "不須計較作思量，五五從來二十五。", "萬般施設到平常，此是叢林飽參句。"]'),
('090a90e8-5f0a-4a43-a22a-9f3cec746cfa','偈四首  其三','釋慧暉','宋','宋诗','song-poetry','','[]','谷之神，樞之要。',58,'全唐诗/poet.song.108000.json','["谷之神，樞之要。", "裏許旁參，回途得妙。", "雲雖動而常閑，月雖晦而彌照。", "賓主交參，正偏兼到。", "十洲春盡花凋殘，珊瑚樹林日杲杲。"]'),
('3ac6af55-90e4-4154-bd8c-55d6a734fa8f','偈四首  其四','釋慧暉','宋','宋诗','song-poetry','','[]','皮膚脫落絕方隅，明了身心一物無。',32,'全唐诗/poet.song.108000.json','["皮膚脫落絕方隅，明了身心一物無。", "妙入道寰深靜處，玉人端馭白牛車。"]'),
('9eeed401-83ea-4f5e-baf6-43958f38475b','頌古十九首  其一','釋慧暉','宋','宋诗','song-poetry','','[]','那吒太子本來身，卓卓無依不受塵。',32,'全唐诗/poet.song.108000.json','["那吒太子本來身，卓卓無依不受塵。", "雲散水流天地靜，籬間黄菊正爭春。"]'),
