('a73b754e-07b7-41dd-8baf-9ee850f732ab','頌古十九首  其一一','釋慧暉','宋','宋诗','song-poetry','','[]','上座莫要禮老朽，興平未易揚家醜。',32,'全唐诗/poet.song.108000.json','["上座莫要禮老朽，興平未易揚家醜。", "尊貴從來不出門，渠儂豈在威音後。"]'),
('5ccff36b-4e51-46d8-a780-59bafccfd3d8','頌古十九首  其一二','釋慧暉','宋','宋诗','song-poetry','','[]','午夜山房月色深，十分明白墮功勛。',32,'全唐诗/poet.song.108000.json','["午夜山房月色深，十分明白墮功勛。", "撥開向上通天竅，烟嶂重重不見人。"]'),
('c2c00814-9028-4896-a40b-e55647b73887','頌古十九首  其一三','釋慧暉','宋','宋诗','song-poetry','','[]','故山岌岌鎖寒烟，未肯將心輕授傳。',32,'全唐诗/poet.song.108000.json','["故山岌岌鎖寒烟，未肯將心輕授傳。", "玉女夜尋無字印，石人遥指月明前。"]'),
('71739632-bdce-48c1-8c80-ef7724f98ed5','頌古十九首  其一四','釋慧暉','宋','宋诗','song-poetry','','[]','一片孤雲不露醜，白雲兒倚青山父。',32,'全唐诗/poet.song.108000.json','["一片孤雲不露醜，白雲兒倚青山父。", "鶴巢靈滴夢初回，新月半鈎升萬戶。"]'),
('5f3d94ef-b108-43eb-9f27-b0a9862376b8','頌古十九首  其一五','釋慧暉','宋','宋诗','song-poetry','','[]','寂寂無依病正深，雪老當年痛處針。',32,'全唐诗/poet.song.108000.json','["寂寂無依病正深，雪老當年痛處針。", "一喚喚回春夢破，千山渾作木龍吟。"]'),
('f965cd33-dfde-4a9a-94f4-354987735c7b','頌古十九首  其一六','釋慧暉','宋','宋诗','song-poetry','','[]','心徑苔生何處去，謝家人不在漁船。',32,'全唐诗/poet.song.108000.json','["心徑苔生何處去，謝家人不在漁船。", "蘆花萬頃水天闊，白鳥深沉任轉旋。"]'),
('32b8afb3-055d-4607-ac07-cadc0cfe15d7','頌古十九首  其一七','釋慧暉','宋','宋诗','song-poetry','','[]','不打飛鳶便到來，大圓鏡裏絕塵埃。',32,'全唐诗/poet.song.108000.json','["不打飛鳶便到來，大圓鏡裏絕塵埃。", "東君節令分明也，桃李年年二月開。"]'),
('c595264c-35b0-40a0-a6f6-aca5c1992f60','頌古十九首  其一八','釋慧暉','宋','宋诗','song-poetry','','[]','□世如來一口吞，故山深靜月黄昏。',32,'全唐诗/poet.song.108000.json','["□世如來一口吞，故山深靜月黄昏。", "光分頂後千門曉，坐看春回入燒痕。"]'),
('70467e72-1384-407c-a203-76562fe08e52','頌古十九首  其一九','釋慧暉','宋','宋诗','song-poetry','','[]','混而不雜體常虛，雪月交光類莫如。',32,'全唐诗/poet.song.108000.json','["混而不雜體常虛，雪月交光類莫如。", "應處萬端無罣礙，片雲自在卷還舒。"]'),
('e8c69d9f-05ce-40f8-a16d-4ad3b2177dad','贈慧暉偈','釋雲居西','宋','宋诗','song-poetry','','[]','雲居不會禪，洗足上床眠。',24,'全唐诗/poet.song.108000.json','["雲居不會禪，洗足上床眠。", "不覺枕子落，打破常住磚。"]'),
('58bc521a-17e0-40db-9afa-8551a78ba134','蒙亭詩和張洵韻','葉宗諤','宋','宋诗','song-poetry','','[]','我行幾許踰沅湘，直抵八桂灕水旁。',144,'全唐诗/poet.song.108000.json','["我行幾許踰沅湘，直抵八桂灕水旁。", "千山倒影摇溪光，秀色不借草木蒼。", "茲亭構勝俯回塘，野花風遞羅綺香。", "巖前伏波航羽觴，一洗塵思生清凉。", "疑有仙人白玉牀，壺中景迥日月長。", "步此仙籟音琅琅，世間名利真毫芒。", "此景不獨冠南方，恨不築室輕侯王。", "回首塵迹空渺茫，瞥去未必計非良。", "其如樽酒情難忘，恍然一夢五雲鄉。"]'),
('0c93c49b-f617-46ed-8932-95421312364f','句','葉宗諤','宋','宋诗','song-poetry','','[]','鳳凰臺上山吞月，白鷺洲邊水接天。',16,'全唐诗/poet.song.108000.json','["鳳凰臺上山吞月，白鷺洲邊水接天。"]'),
('b2148654-5ae5-4244-9ef1-d81c2d8f0b5c','通山  其一','李傳正','宋','宋诗','song-poetry','','[]','我愛通羊好，居民山作城。',24,'全唐诗/poet.song.108000.json','["我愛通羊好，居民山作城。", "眼前無俗事，枕畔有灘聲。"]'),
('b287b897-366c-4f1a-9768-87954f439b3e','通山  其二','李傳正','宋','宋诗','song-poetry','','[]','我愛通羊好，回環雲水間。',24,'全唐诗/poet.song.108000.json','["我愛通羊好，回環雲水間。", "重巒與疊嶂，真是翠屏山。"]'),
('8f289b17-bc42-4e1c-92a2-876514685672','通山  其三','李傳正','宋','宋诗','song-poetry','','[]','我愛通羊好，清無一點塵。',24,'全唐诗/poet.song.108000.json','["我愛通羊好，清無一點塵。", "峭山多洞戶，樵牧識仙人。"]'),
('e54681f5-b2be-4f90-97ce-5a7aad97738d','遊淡山巖','彭從虎','宋','宋诗','song-poetry','','[]','竹苞未翦山雖幽，福庭勝概難窮搜。',96,'全唐诗/poet.song.108000.json','["竹苞未翦山雖幽，福庭勝概難窮搜。", "天公念此久閉塞，密召五丁詒厥謀。", "巽維一夕啟邃竇，光圓甕牖端相侔。", "方床翠屏廣羅列，藥臼香山深抉鎪。", "道人振錫蟒潜遁，處士化石巖中留。", "訓狐昨夜又鳴報，果是五馬今朝遊。"]'),
('9fd1f14a-432e-4cc4-970c-3e0f41a13bab','句','李會','宋','宋诗','song-poetry','','[]','金沙灘上雙鸂鶒，肯爲分司御史來。',16,'全唐诗/poet.song.108000.json','["金沙灘上雙鸂鶒，肯爲分司御史來。"]'),
('47b641f2-84f5-4613-bcbd-13a7664019e0','紹興丁巳二月三十日同晏元老馮應禮羅君瑞遊龍多山訪飛仙遺迹以兩詩書事  其一','何麒','宋','宋诗','song-poetry','','[]','世路聱牙赤水過，故升天險問龍多。',64,'全唐诗/poet.song.108000.json','["世路聱牙赤水過，故升天險問龍多。", "書中舊識唐公昉，圖裏又聞馮蓋羅。", "絳闕岧岧雙鶴下，青空杳杳八鸞歌。", "一篇跳出孫樵語，未應虛皇玉字科。"]'),
('a0af0cc3-4e72-4ad2-8a82-395f64f64abd','紹興丁巳二月三十日同晏元老馮應禮羅君瑞遊龍多山訪飛仙遺迹以兩詩書事  其二','何麒','宋','宋诗','song-poetry','','[]','丁令梅仙梁市客，穿雲隨我上虛無。',64,'全唐诗/poet.song.108000.json','["丁令梅仙梁市客，穿雲隨我上虛無。", "携持頼有竹都尉，偃蹇更逢松大夫。", "山積五倉窺石□，霞拖九芒覓丹爐。", "聖泉聞說經湯旱，中有龍蟠不用雩。"]'),
('08c2da2e-8975-41cc-9beb-82ede34a36dc','南樓','何麒','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','武昌形勢鳳凰邊，萬里長江落檻前。',32,'全唐诗/poet.song.108000.json','["武昌形勢鳳凰邊，萬里長江落檻前。", "笑殺元規亂天下，南樓何藉此人傳。"]'),
('e2b71db1-93d8-4b19-9622-cc6ac5610424','外大父丞相初登科爲雒縣主簿經攝垍窯鎮稅官留詩護國寺中令狐監征錄以見寄謹再拜追和而記其後','何麒','宋','宋诗','song-poetry','','[]','傳翁遺墨賸咨嗟，四海當年尚一家。',64,'全唐诗/poet.song.108000.json','["傳翁遺墨賸咨嗟，四海當年尚一家。", "大老不爲今日用，小詩徒遣後人誇。", "興來思跨巴滇馬，歸去方乘下澤車。", "燕麥兔葵僧舍裏，何如夢得訪桃花。"]'),
('30438940-8ee6-4f26-87eb-4a3240073ae5','虎丘','何麒','宋','宋诗','song-poetry','','[]','平地涌巖壑，棱層驚大雄。',48,'全唐诗/poet.song.108000.json','["平地涌巖壑，棱層驚大雄。", "何曾遠人世，真欲傍天宮。", "白虎威靈在，赤烏緣影空。", "生公能說法，音與塔鈴同。"]'),
('eef1612c-a1b4-4c96-85ad-20767cf5509b','巖下觀瀑旦晚異狀子文有詩輒次其韻','何麒','宋','宋诗','song-poetry','','[]','瀑色清明氣猶雄，非煙非雲非白虹。',96,'全唐诗/poet.song.108000.json','["瀑色清明氣猶雄，非煙非雲非白虹。", "兜羅綿光秀罘罳，瑠璃□影摇簾櫳。", "風吹銀潢灑蒼壁，日照玉柱擎青空。", "誰言物象要有盡，我覺端倪殊不窮。", "思涌迴翔掀舞時，句在縹緲空濛中。", "更將七字寫亭午，倚天長劍拖芒鋒。"]'),
('e74b8f42-e161-4ebe-ad37-85651c261bcd','題陽華巖','何麒','宋','宋诗','song-poetry','','[]','名山固多巖，茲巖擅天下。',144,'全唐诗/poet.song.108000.json','["名山固多巖，茲巖擅天下。", "屋大享千人，谷深量萬馬。", "谽谺通一水，旁午飛橋跨。", "石礫巧彫鎪，松篁森繪畫。", "古人棲遁處，文字猶憑藉。", "語妙元次山，名高陶別駕。", "瞿君三體篆，殆可斯翁亞。", "却後累百年，吾人來歎吒。", "伊予邱壑姿，嗜好若天假。", "終焉卜真隠，學道冀陶冶。", "丹成生羽翼，召節青童把。", "揮手挹霞芒，竦身朝帝者。"]'),
('479e9002-2453-4892-b999-257584d3bc25','題師子巖  其一','何麒','宋','宋诗','song-poetry','','[]','旦爲陽華遊，軒豁諧素志。',144,'全唐诗/poet.song.108000.json','["旦爲陽華遊，軒豁諧素志。", "那知此嵌巖，近在回翔地。", "石如狻猊狀，蹲伏呀可畏。", "雖無嚬呻威，尚使百獸避。", "漫郎嗜泉石，足跡靡不至。", "是巖端見遺，定自求其備。", "澹巖冠湘中，瓌瑋傳萬耳。", "此郎靳一言，亦以山無水。", "骨多欠膋血，草木咸枯悴。", "其誰喜冥搜，韻語發天祕。", "石門何晃蕩，坐久三歎喟。", "徑欲挽銀潢，淙淙滿人意。"]'),
('9af8da9f-a764-4a89-af4a-6591146b31e7','題師子巖  其二','何麒','宋','宋诗','song-poetry','','[]','一楠枯再生，兩石合無罅。',12,'全唐诗/poet.song.108000.json','["一楠枯再生，兩石合無罅。"]'),
('a4ae696a-b1dc-486a-b857-cb81f408c6aa','題師子巖  其三','何麒','宋','宋诗','song-poetry','','[]','梁山韮黄妙天下，玉筯金釵盈大把。',16,'全唐诗/poet.song.108000.json','["梁山韮黄妙天下，玉筯金釵盈大把。"]'),
('b761a490-0dce-465f-b0f3-e14bab10658f','建炎丞相成國呂忠穆公退老堂  其一','徐公裕','宋','宋诗','song-poetry','','[]','注意惟聞簡帝心，聊成退老寓登臨。',64,'全唐诗/poet.song.108000.json','["注意惟聞簡帝心，聊成退老寓登臨。", "放懷綠野巖瞻重，寄傲平泉國念深。", "海闊水雲和島嶼，時清鐘鼓樂園林。", "謝公豈久東山趣，天下蒼生傒作霖。"]'),
('7ceccbdd-f18a-4d44-b5ca-013c81241901','建炎丞相成國呂忠穆公退老堂  其二','徐公裕','宋','宋诗','song-poetry','','[]','國棟帡幪不日成，天河星斗宿簷楹。',64,'全唐诗/poet.song.108000.json','["國棟帡幪不日成，天河星斗宿簷楹。", "台符影燭江山麗，赤舄光臨草木榮。", "猿鶴從今驚夜帳，鹽梅行復作和羹。", "衰顔白髮塵埃客，狂斐裁詩繼頌聲。"]'),
('cfaf6497-10cb-47c0-848a-30ad266ddb50','宮詞四首  其一','吳百生','宋','宋诗','song-poetry','','[]','妙選昭陽進，羞花妬六宮。',48,'全唐诗/poet.song.108000.json','["妙選昭陽進，羞花妬六宮。", "行階蓮落地，隨御柳含風。", "按舞天光近，徵歌燭影紅。", "夜深金殿合，環珮月明中。"]'),
('3cf8602d-6ec4-4e84-85f4-c778cb0539b6','宮詞四首  其二','吳百生','宋','宋诗','song-poetry','','[]','阿嬌金屋閉，羣玉奉龍轝。',48,'全唐诗/poet.song.108000.json','["阿嬌金屋閉，羣玉奉龍轝。", "夜色明光酒，春風長信裾。", "傳宣嚴仗合，應侍冶容虛。", "笑簇嫣然地，名花總不如。"]'),
('fc917e61-1682-46ac-8507-3f177767ac9f','宮詞四首  其三','吳百生','宋','宋诗','song-poetry','','[]','鈞樂雲中動，鑾輿天上行。',48,'全唐诗/poet.song.108000.json','["鈞樂雲中動，鑾輿天上行。", "百花齊醉日，孤月獨明更。", "玉漏頻催酒，金爐細結甍。", "春秋有常幸，日日調清平。"]'),
('00454e69-8c43-4f5f-b282-9505d3d0e70e','宮詞四首  其四','吳百生','宋','宋诗','song-poetry','','[]','中使質明催，珠宮寶扇迴。',48,'全唐诗/poet.song.108000.json','["中使質明催，珠宮寶扇迴。", "髻雲雙鳳擁，歌雪百花堆。", "競立徼殊寵，群趨望獨魁。", "壽陽春夜額，貼盡一庭梅。"]'),
('62f7d078-0ebb-417f-984b-15f65cfd0d8b','莫釐遠眺','吳百生','宋','宋诗','song-poetry','','[]','金庭隔塵聳，玉柱插天浮。',48,'全唐诗/poet.song.108000.json','["金庭隔塵聳，玉柱插天浮。", "石古不知歲，谿虛長欲秋。", "繡重紅錯翠，錦簇閣兼樓。", "望裏三州遠，吟邊松月留。"]'),
('2f656c13-8a85-42ab-85c0-924865ab943e','烏夜啼','吳百生','宋','宋诗','song-poetry','','[]','夜夜烏來啼未央，明月出戶空飛霜。',32,'全唐诗/poet.song.108000.json','["夜夜烏來啼未央，明月出戶空飛霜。", "吹笳征夫不就寢，宮筵列燭聲滿堂。"]'),
('778c59e2-1238-40fc-845d-e674fb9cb18a','鹿苑禪寺','范潔','宋','宋诗','song-poetry','','[]','晉遠風流八百年，虎溪無復社中賢。',64,'全唐诗/poet.song.108000.json','["晉遠風流八百年，虎溪無復社中賢。", "愛斯吐月吞風屋，有此開花結子蓮。", "直使淵明通耿介，亦教靈運費攀援。", "知師戒潔方投社，欲對松窗設榻眠。"]'),
('96896973-722a-4127-b170-6ae7350c6ba9','題徽宗宸翰','康與之','宋','宋诗','song-poetry','','[]','玉輦宸遊事已空，尚餘奎藻繪春風。',32,'全唐诗/poet.song.108000.json','["玉輦宸遊事已空，尚餘奎藻繪春風。", "年年花鳥無窮恨，盡在蒼梧夕照中。"]'),
('cdf93440-aa64-4fb1-898a-8b6066bbbef3','遊慧力寺  其一','康與之','宋','宋诗','song-poetry','','[]','天涯芳草盡綠，路旁柳絮爭飛。',28,'全唐诗/poet.song.108000.json','["天涯芳草盡綠，路旁柳絮爭飛。", "啼鳥一聲春晚，落花滿地人歸。"]'),
('8be1136b-9d33-45ac-8d17-9584544cc4a9','遊慧力寺  其二','康與之','宋','宋诗','song-poetry','','[]','江上濃陰曉未開，瘦筇支我上蒼苔。',32,'全唐诗/poet.song.108000.json','["江上濃陰曉未開，瘦筇支我上蒼苔。", "春寒前日去已盡，今日又從何處來。"]'),
('f533fffe-fd49-4755-8c15-afc5aad4042a','僻居','康與之','宋','宋诗','song-poetry','','[]','巷僻過從少，柴門盡日關。',48,'全唐诗/poet.song.108000.json','["巷僻過從少，柴門盡日關。", "鶑聲常在柳，雲影不離山。", "有道難言□，雖貧未厭閒。", "川原煙四暝，春思有無間。"]'),
('b4be6a00-7c6c-470c-837c-3a0b8c26023b','鷺','康與之','宋','宋诗','song-poetry','','[]','春暗汀洲杜若香，風標公子白霓裳。',32,'全唐诗/poet.song.108000.json','["春暗汀洲杜若香，風標公子白霓裳。", "碧天片雪忽飛去，何處人家水滿塘。"]'),
('1ed0f692-49d5-4191-b01f-637bb85e2875','琵琶','康與之','宋','宋诗','song-poetry','','[]','夜深琵琶聲似裂，一曲霓裳一庭月。',32,'全唐诗/poet.song.108000.json','["夜深琵琶聲似裂，一曲霓裳一庭月。", "曲終人影在西階，困倚東風步摇折。"]'),
('04a2b664-e0f1-436d-8b1a-62c23b52ad44','可惜','康與之','宋','宋诗','song-poetry','','[]','簾幕重重下玉鈎，隔簾春在柳梢頭。',32,'全唐诗/poet.song.108000.json','["簾幕重重下玉鈎，隔簾春在柳梢頭。", "東風著意相料理，吹去楊花不自由。"]'),
('079de10a-f3be-4109-86d5-0891321e6550','鶴舒臺','康與之','宋','宋诗','song-poetry','','[]','白雲深處路崎嶇，鶴去臺空景物殊。',64,'全唐诗/poet.song.108000.json','["白雲深處路崎嶇，鶴去臺空景物殊。", "山展翠屏連紫幕，泉分清溜滴明珠。", "道人祇問丹砂井，隠客猶尋九節蒲。", "試問葛仙仙去後，至今遺蹟事如何。"]'),
('17f6e723-d747-4d1c-b18d-a86b151c975c','招真詞','康與之','宋','宋诗','song-poetry','','[]','白鶴巢兮丹井空，蓬山杳兮煙霞濛。',124,'全唐诗/poet.song.108000.json','["白鶴巢兮丹井空，蓬山杳兮煙霞濛。", "陵谷變兮今古，木葉下兮秋風。", "飛仙去兮朝太微，黄冠野服兮以遊以嬉。", "餐霞卧月兮世不我違，與世滌映兮天門可馳。", "蒼龍嘷兮雲漫扉，石泉冽兮山芋肥。", "俯仰宇宙兮日月蔽虧，靈秀回薄兮野芳呈姿。", "山中之樂兮萬化莫移，仙人不來兮隠者曷歸。"]'),
('72e589de-24fb-4dd0-bcd7-88729687049a','嚴陵懷古','康與之','宋','宋诗','song-poetry','','[]','建武中興寶運開，股肱俱是濟時才。',32,'全唐诗/poet.song.108000.json','["建武中興寶運開，股肱俱是濟時才。", "漢家鼎祚如磐石，此老方圖拂袖來。"]'),
('369d2521-8922-42d3-994c-ab5453f069c6','玉虹洞二首  其一','康與之','宋','宋诗','song-poetry','','[]','睡起疏簾一半開，更無人迹過青苔。',32,'全唐诗/poet.song.108000.json','["睡起疏簾一半開，更無人迹過青苔。", "須臾蒼狗風前變，雷雨驅潮出海來。"]'),
('444d0d70-d916-46c6-880e-caa98ba6153c','玉虹洞二首  其二','康與之','宋','宋诗','song-poetry','','[]','滿山一夜風篁響，透屋三更月露寒。',32,'全唐诗/poet.song.108000.json','["滿山一夜風篁響，透屋三更月露寒。", "自掩殘書推枕睡，江湖秋夢水雲寬。"]'),
('42ce4dff-1e20-46af-84e6-91ee4c6e64ef','詩一首','康與之','宋','宋诗','song-poetry','','[]','越王山下千樹梅，逐客年年走馬來。',64,'全唐诗/poet.song.108000.json','["越王山下千樹梅，逐客年年走馬來。", "寒玉滿枝風色裏，不受暖靄輕煙催。", "故人千里復萬里，折香欲寄生徘徊。", "孤吟獨醉常夜半，山月野風騎馬回。"]'),
('68f3d6a1-49af-44bf-b3ce-bfe69d66ab72','戲爲妓山氏作','康執權','宋','宋诗','song-poetry','','[]','昔日緹縈亦如許，盡道生男不如女。',32,'全唐诗/poet.song.108000.json','["昔日緹縈亦如許，盡道生男不如女。", "河陽滿縣皆春風，忍使梨花偏带雨。"]'),
('599388d7-146b-4c0b-a435-cbe9468bf0d5','建炎丞相成國呂忠穆公退老堂詩二首  其一','康執權','宋','宋诗','song-poetry','','[]','退老堂成席未溫，天書夜到領侯藩。',64,'全唐诗/poet.song.108000.json','["退老堂成席未溫，天書夜到領侯藩。", "周褎申伯保南土，唐起裴公護北門。", "猿鶴豈應愁舊隠，虎貔方看擁華軒。", "公家報政由來速，佇入延英覲帝尊。"]'),
('a6de9d08-f66f-41e9-b906-f840e1c343a8','建炎丞相成國呂忠穆公退老堂詩二首  其二','康執權','宋','宋诗','song-poetry','','[]','公居臨海亦經年，每恨淹留阻執鞭。',64,'全唐诗/poet.song.108000.json','["公居臨海亦經年，每恨淹留阻執鞭。", "異縣忽聞登帥閫，此身那得侍賓筵。", "古今誰似功名老，出入榮持將相權。", "從此鳳池歸路駃，未容雁蕩奉周旋。"]'),
('f9eb1792-65eb-4386-bcb5-993ac75c7cd2','弔王忠肅','楊由義','宋','宋诗','song-poetry','','[]','太原城下屹行宮，雲樹籠葱掩碧空。',32,'全唐诗/poet.song.108000.json','["太原城下屹行宮，雲樹籠葱掩碧空。", "鐵馬無聲汾水急，滿天風雨泣英雄。"]'),
('9a68259b-5ae1-4e23-a6aa-368d47e9a972','哭郭若虛','程時翼','宋','宋诗','song-poetry','','[]','一枝夭矯摩雲操，三尺光芒報國心。',32,'全唐诗/poet.song.108000.json','["一枝夭矯摩雲操，三尺光芒報國心。", "易水歌殘聲杳杳，□□月落夜沉沉。"]'),
('a5645998-33d2-4bc6-9175-34ff5780ccbc','雁','朱乘','宋','宋诗','song-poetry','','[]','八月新霜岸草枯，數聲哀怨雁來初。',32,'全唐诗/poet.song.108000.json','["八月新霜岸草枯，數聲哀怨雁來初。", "憑君試向沙汀看，恐带匈奴二帝書。"]'),
('c55c8b6a-e1f5-4121-82ff-8653a79c9688','華亭山房象山','黄大輿','宋','宋诗','song-poetry','','[]','客游厭城市，僧房見巖壑。',108,'全唐诗/poet.song.108000.json','["客游厭城市，僧房見巖壑。", "偉石羅衆峯，寒砂結層堮。", "爲谷既窈窕，置嶺復綿邈。", "溪源互相注，花草紛已錯。", "空聞先王夢，徒觀楚臣作。", "行雲在俛仰，北渚應酬酢。", "天機契如幻，意匠起冥漠。", "周流屬多豫，寤寐欣所託。", "有懷山中人，從爾芳杜若。"]'),
('75b3016b-3d6c-4ee3-927a-773e825eb7bd','登慈恩塔','范智聞','宋','宋诗','song-poetry','','[]','獨上慈恩塔，疏懷亦慨然。',24,'全唐诗/poet.song.108000.json','["獨上慈恩塔，疏懷亦慨然。", "異朝多少事，不改舊山川。"]'),
('4db7f902-7f8b-47f3-930d-e4405b76470a','蒼玉洞','范智聞','宋','宋诗','song-poetry','','[]','山容嶻嶭石爲身，造化安排氣象勻。',64,'全唐诗/poet.song.108000.json','["山容嶻嶭石爲身，造化安排氣象勻。", "杳窱一灣開洞府，巉巖四立護風塵。", "溪光照野疑無夜，樹色參天不計春。", "誰把翠崖磨似玉，喜留詩語記幽人。"]'),
('074c7e25-ac3a-4b9f-831f-f8fbb0a1a9fc','臨終詩','釋有規','宋','宋诗','song-poetry','','[]','讀書已覺眉棱重，就枕方欣骨節和。',32,'全唐诗/poet.song.108000.json','["讀書已覺眉棱重，就枕方欣骨節和。", "睡起不知天早晚，西窗殘日已無多。"]'),
('45445a95-f79c-458d-8a6e-b8c669a2c456','書戶','小郗道人','宋','宋诗','song-poetry','','[]','日轉庭槐影漸移，重門複屋傳呼遲。',32,'全唐诗/poet.song.108000.json','["日轉庭槐影漸移，重門複屋傳呼遲。", "不如拂袖穿雲去，說與落花流水知。"]'),
('738612ae-1f5f-4857-b84f-c91406a04646','夢中作','王珩','宋','宋诗','song-poetry','','[]','舂罷雞□□，□行犬吠難。',24,'全唐诗/poet.song.108000.json','["舂罷雞□□，□行犬吠難。", "溪深水馬健，霜重橘奴肥。"]'),
('5d29b877-9f3a-4aaf-86be-2623d2351d63','詩一首','釋清止','宋','宋诗','song-poetry','','[]','江南江北正干戈，茅屋深遷入薜蘿。',64,'全唐诗/poet.song.108000.json','["江南江北正干戈，茅屋深遷入薜蘿。", "夢幻利名知險惡，虛舟身世若風波。", "石門路險交遊少，竹塢雲深筍蕨多。", "閙裏打閑誰似我，千巖春色一聲歌。"]'),
('fb4b3d39-5e3c-4a0a-b8f2-4bc914a5d3f0','詩一首','釋慧日','宋','宋诗','song-poetry','','[]','溪遶茅堂山遶溪，溪山深處是真棲。',32,'全唐诗/poet.song.108000.json','["溪遶茅堂山遶溪，溪山深處是真棲。", "山人若問西來意，雲自高飛鳥自啼。"]'),
('f67236cf-0332-4322-af80-eec09f5c779b','麻溪渡','汪寺丞','宋','宋诗','song-poetry','','[]','麻溪渡口古灘頭，萬疊青山遶四周。',64,'全唐诗/poet.song.108000.json','["麻溪渡口古灘頭，萬疊青山遶四周。", "地僻鼎分三縣界，淵澄輻輳兩川流。", "客槎時下佗山木，漁槳偏歸暮雨舟。", "寂寞一年曾再到，可憐異代謫仙游。"]'),
('00d1821f-f01e-4262-b2c3-a9fcc4bf39c9','句  其一','毛德如','宋','宋诗','song-poetry','','[]','睡覺昏昏厭鼓聲。',8,'全唐诗/poet.song.108000.json','["睡覺昏昏厭鼓聲。"]'),
('2b87077b-cedb-4612-91c0-e5bef0f8fc4c','句  其二','毛德如','宋','宋诗','song-poetry','','[]','城頭松柏鎖愁烟。',8,'全唐诗/poet.song.108000.json','["城頭松柏鎖愁烟。"]'),
('7dbb31da-c51a-47ad-80bf-c654119f9e68','廣野軒','張之才','宋','宋诗','song-poetry','','[]','城隅荒僻地，瀟灑亦清虛。',48,'全唐诗/poet.song.108000.json','["城隅荒僻地，瀟灑亦清虛。", "雅有林泉樂，閒同郊野居。", "小園春自好，幽逕客來疏。", "不學樊遲稼，虞卿喜著書。"]'),
('35e69fac-d4c9-47db-82e2-43e4d737ece8','句','吳民載','宋','宋诗','song-poetry','','[]','條風著野方蠶月，高樹移陰又麥秋。',16,'全唐诗/poet.song.108000.json','["條風著野方蠶月，高樹移陰又麥秋。"]'),
('2b6789d5-d9bf-4af4-9c2c-254f108d7d6e','贈張淡道人','徐逢原','宋','宋诗','song-poetry','','[]','鐵笛愛吹風月夜，夾衣能御雪霜天。',32,'全唐诗/poet.song.108000.json','["鐵笛愛吹風月夜，夾衣能御雪霜天。", "伊予試問行年看，笑指松筠未是堅。"]'),
('a63a4ba7-c4bc-4daf-a6d8-200286fad2af','吏部員外郎傅公','《靖康小雅》作者','宋','宋诗','song-poetry','','[]','强敵寒盟，兵忽踰塞。',60,'全唐诗/poet.song.108000.json','["强敵寒盟，兵忽踰塞。", "公持漢節，迓客于界。", "控弦欻來，率土震駭。", "外臣桀傲，自矜强大。", "公誓不慴，有死無拜。", "殺身成仁，播美千載。"]'),
('5104dc07-7a74-40bd-bbd5-2b04c0f5e9ee','河東馬步軍副總管王公','《靖康小雅》作者','宋','宋诗','song-poetry','','[]','矯矯虎臣，捍城於并。',60,'全唐诗/poet.song.108000.json','["矯矯虎臣，捍城於并。", "殫其智力，爲國長城。", "攻踰兩時，敵不能乘。", "無食無援，百雉乃傾。", "負像赴水，義不苟生。", "大節卓偉，千載光明。"]'),
('f80710b7-29ca-43c1-b646-127bdf3cddc1','真定府路兵馬都鈐轄劉公','《靖康小雅》作者','宋','宋诗','song-poetry','','[]','將軍死綏，古人所長。',60,'全唐诗/poet.song.108000.json','["將軍死綏，古人所長。", "有如劉公，與城俱亡。", "兵挐常山，公以身當。", "生竭其勇，力挫戎行。", "天未悔禍，敵勢益張。", "公雖瞑目，萬古傳芳。"]'),
('e6de9787-6ab3-4c6e-b5b0-85a3b50ee253','太尉鎮洮軍節度使同知樞密院事种公','《靖康小雅》作者','宋','宋诗','song-poetry','','[]','壯哉此翁，謀深氣勁。',100,'全唐诗/poet.song.108000.json','["壯哉此翁，謀深氣勁。", "終始一節，佑我三聖。", "百戰之餘，所料必勝。", "提師入援，敵讋威令。", "疊盡良策，衆莫之聽。", "割地增幣，强鄰益橫。", "萬里長城，恃爲藩屏。", "倏嗟不祿，亂何有定。", "旌旗無光，兵民凄哽。", "餘烈昭昭，方求獨盛。"]'),
('e958fc49-79fe-41c7-979c-8b94568f7db8','果州團練使何公','《靖康小雅》作者','宋','宋诗','song-poetry','','[]','巍巍京師，帝王之澤。',60,'全唐诗/poet.song.108000.json','["巍巍京師，帝王之澤。", "臨制華夏，憲相紫極。", "邊塵漲天，雨墜矢石。", "千雉摧毀，公死於敵。", "欃槍舒芒，萬象變色。", "獨垂忠烈，以光載籍。"]'),
('35afc110-4ec7-4d8b-909d-8235cca71f9f','內使黄公','《靖康小雅》作者','宋','宋诗','song-poetry','','[]','在昔漢唐，亡由閹宦。',60,'全唐诗/poet.song.108000.json','["在昔漢唐，亡由閹宦。", "出或用之，鮮不貽患。", "豈期黄公，獨稟高見。", "白髮虔心，有聞必諫。", "竭力東城，以身死難。", "揭名不磨，萬世炳煥。"]'),
('44c8ffeb-6a1b-48cd-8be1-f31bb8d6c0dc','提舉京城四壁守禦劉公','《靖康小雅》作者','宋','宋诗','song-poetry','','[]','有赫劉公，心在王室。',60,'全唐诗/poet.song.108000.json','["有赫劉公，心在王室。", "氣吞强敵，忠貫日月。", "九鼎既淪，四溟蕩潏。", "公如山嶽，萬仞屹屹。", "富貴莫誘，威武莫屈。", "仗節而死，無愧委質。"]'),
('37df1b26-b283-42f9-8281-202170e6beb6','太學生徐公','《靖康小雅》作者','宋','宋诗','song-poetry','','[]','欃槍騰光，遂勃太陽。',60,'全唐诗/poet.song.108000.json','["欃槍騰光，遂勃太陽。", "六龍不翔，昧昧八荒。", "公欲挾飛，再麗咸桑。", "怒髮烈烈，力鎸暴羌。", "白刃亙野，視猶蝟芒。", "凜凜之氣，雖死不亡。"]'),
('dbb978a8-6667-4395-8ca9-e72410c419d1','吏部侍郎李公','《靖康小雅》作者','宋','宋诗','song-poetry','','[]','烈烈李公，實備全德。',100,'全唐诗/poet.song.108000.json','["烈烈李公，實備全德。", "義動幽明，氣貫金石。", "扈蹕敵營，爰究忠烈。", "杞人之憂，廢立大厄。", "公挺不顧，二將面叱。", "勇甚雷霆，天地動色。", "命輕鴻毛，名高斗極。", "燎火之焚，不變藍璧。", "滔天之溺，砥柱獨立。", "死得其所，震耀方冊。"]'),
('6728ee5f-23d3-4e7e-a5a8-ddf58f5149a7','兵部尚書孫公','《靖康小雅》作者','宋','宋诗','song-poetry','','[]','巍巍孫公，忠烈俱偉。',100,'全唐诗/poet.song.108000.json','["巍巍孫公，忠烈俱偉。", "受天大任，淵渟山峙。", "謀謨密宥，帝所眷倚。", "付以留鑰，又託以子。", "天未悔禍，甘赴萬死。", "國家德澤，周及遠邇。", "罹茲禍變，孰奮而起。", "公節不渝，獨負大美。", "若神人然，衆所仰止。", "彼以偷生，徒奄如鬼。"]'),
('9e7f3ed0-1a05-4bd3-b494-e5eb778c2b53','僉書樞密院事張公','《靖康小雅》作者','宋','宋诗','song-poetry','','[]','金人强悍，一歲再至。',60,'全唐诗/poet.song.108000.json','["金人强悍，一歲再至。", "公提郡兵，疾驅入衛。", "敵將易姓，公秉大義。", "獨敢抗言，必復趙氏。", "欲扶日馭，力掃氛翳。", "身拘名張，忠烈振世。"]'),
('42f4c5bf-a8da-447e-829a-064660cd3536','東京留守宗公','《靖康小雅》作者','宋','宋诗','song-poetry','','[]','洪河滔滔，撼野摧山。',100,'全唐诗/poet.song.108000.json','["洪河滔滔，撼野摧山。", "砥柱中立，獨當狂瀾。", "敵勢焰焰，動植俱殘。", "公俯視之，若螢燐然。", "知無不爲，獨殿中原。", "方事北討，將以身先。", "赤羽若日，朱旗絳天。", "二賊巧沮，行或止還。", "雖醢二賊，奚足償焉。", "奪之遽矣，中外悲歎。"]'),
('9f63905b-b0f3-4933-b2bf-da3a75937177','河北都轉運使王公','《靖康小雅》作者','宋','宋诗','song-poetry','','[]','建炎紹統，銳於中興。',100,'全唐诗/poet.song.108000.json','["建炎紹統，銳於中興。", "乃得賢輔，食蘗飲水。", "責君堯舜，良哉股肱。", "苟用其言，不難丕承。", "時相巨蠹，忌嫉才能。", "群邪翼之，如彼鸇鷹。", "公奮不顧，忠勇日增。", "瞻之維何，垂天之鵬。", "瑣瑣潜善，陋比蛙蠅。", "賢死奸壽，何戒何懲。"]'),
('926b9c4d-3677-4ec8-a9c9-767e0db9e22d','御史中丞秦公','《靖康小雅》作者','宋','宋诗','song-poetry','','[]','天崩地陷，革我洪圖。',60,'全唐诗/poet.song.108000.json','["天崩地陷，革我洪圖。", "孰敢爭之，維時醇儒。", "祈復明辟，義在捐軀。", "猛虎垂涎，遂捋其鬚。", "驪龍不睡，乃探其珠。", "身赴沙漠，名振九區。"]'),
('8eb8498b-2f5e-493d-83cc-de46f1d878e8','辭再主清凉偈','釋智朋','宋','宋诗','song-poetry','','[]','相煩專使入煙霞，灰冷無湯不點茶。',32,'全唐诗/poet.song.108000.json','["相煩專使入煙霞，灰冷無湯不點茶。", "寄語甬東賢太守，難教枯木再生花。"]'),
('ea2371aa-f52d-411b-b72b-1d86b5afe232','中山即事','芮毓','宋','宋诗','song-poetry','','[]','幾年壓塵囂，屢欲返初服。',72,'全唐诗/poet.song.108000.json','["幾年壓塵囂，屢欲返初服。", "鷦鷯安一枝，何必戀微祿。", "瀟灑此村居，茅舍带修竹。", "田園薄有收，積書高過屋。", "所以課子孫，利用聚吾族。", "光大不可期，庶幾守耕讀。"]'),
('95aaf09f-2e69-4653-a26e-cc3af7be8927','句','呂氏','宋','宋诗','song-poetry','','[]','前身當是陶淵明，愛酒不入遠公社。',16,'全唐诗/poet.song.108000.json','["前身當是陶淵明，愛酒不入遠公社。"]'),
('a075596e-9457-4dad-85da-f0bda6b97dd2','句','靖康臣僚','宋','宋诗','song-poetry','','[]','伊尹定歸商社稷，霍光終作漢臣鄰。',16,'全唐诗/poet.song.108000.json','["伊尹定歸商社稷，霍光終作漢臣鄰。"]'),
('f6fa32a0-053b-407d-b27e-05fd1650bff7','題黄連步接官亭壁','鄱陽婦人','宋','宋诗','song-poetry','','[]','故里蕭條一望間，此身飄泊歎空還。',32,'全唐诗/poet.song.108000.json','["故里蕭條一望間，此身飄泊歎空還。", "感時有恨無人說，愁斂雙蛾對暮山。"]'),
('47024712-b16b-4840-90af-5e2c20cfcaad','客臨安懷舊都','東都故老','宋','宋诗','song-poetry','','["\u897f\u6e56"]','曾見宜秋輦路門，大書黄榜許游行。',32,'全唐诗/poet.song.108000.json','["曾見宜秋輦路門，大書黄榜許游行。", "漢家寬大風流在，老去西湖樂太平。"]'),
('ec59fa73-0147-4f2f-893e-eef69678adee','詩一首  其一','范宗尹','宋','宋诗','song-poetry','','[]','丈人古君子，清德肖冰玉。',48,'全唐诗/poet.song.108000.json','["丈人古君子，清德肖冰玉。", "仕宦三十載，一飽猶仰祿。", "驅車向金闕，此行何太速。", "家山豈不戀，陶令瓶無粟。"]'),
('6e34e091-77a1-4d0a-abeb-e1c6737b36af','詩一首  其二','范宗尹','宋','宋诗','song-poetry','','[]','曉出城東路，尋僧聊避喧。',48,'全唐诗/poet.song.108000.json','["曉出城東路，尋僧聊避喧。", "宿雲開嶺岫，晚稻沒川原。", "村暗桑枝合，林紅柿子繁。", "日斜僮僕困，共喜到山門。"]'),
('80d59c16-2a51-40ec-8f41-fce1d36e5cf1','詩一首  其三','范宗尹','宋','宋诗','song-poetry','','[]','古寺山環合，崎嶇路僅通。',48,'全唐诗/poet.song.108000.json','["古寺山環合，崎嶇路僅通。", "一庵寒閉戶，羣木夜號風。", "幽勝窮探盡，塵勞洗滌空。", "茲遊恐不再，聊記小詩中。"]'),
('9b9933f8-1518-4c85-9f0a-4485f90dc9e0','題石橋','范宗尹','宋','宋诗','song-poetry','','[]','古木森森白晝昏，瀑泉飛處兩山分。',64,'全唐诗/poet.song.108000.json','["古木森森白晝昏，瀑泉飛處兩山分。", "石梁跨谷欣初睹，茗椀浮花信舊聞。", "行古向來悲一跌，潔身此去欲三薰。", "至人儻有矜憐意，便與提携出世紛。"]'),
('0ca0dcbc-041d-4e04-b511-83363db1213a','遊大有空明洞','范宗尹','宋','宋诗','song-poetry','','[]','暫到山中禮法壇，空明雲氣逼面寒。',32,'全唐诗/poet.song.108000.json','["暫到山中禮法壇，空明雲氣逼面寒。", "當年孤鶴是何處，遥想天風墜羽翰。"]'),
('4bcc2a6b-b05b-4c45-82a9-83fcff89d369','題雁蕩山','范宗尹','宋','宋诗','song-poetry','','[]','一徑入幽谷，隨山幾縈盤。',168,'全唐诗/poet.song.108000.json','["一徑入幽谷，隨山幾縈盤。", "雲樹深蓊蔚，石溪響潺湲。", "我來春色晚，山花亦何繁。", "好鳥不知名，向人自關關。", "遺我發興新，探討忘疲艱。", "龍湫信奇絕，飛泉落雲間。", "快瀉萬斛珠，濺沫霜雪寒。", "尊者所經行，草木不可芟。", "敢將塵土足，濯此清泠灣。", "晚投野僧家，山作碧玉環。", "高堂極虛明，可寄須臾閑。", "此行端爲山，山窮我當還。", "明朝驅車去，依然隨塵寰。", "勝處未易忘，神遊清夜闌。"]'),
('7cffed77-dd3e-481e-8762-04a12d04963b','寄張趙二相三首  其一','胡寅','宋','宋诗','song-poetry','','[]','賢哲不同才，論心則皆仁。',168,'全唐诗/poet.song.108000.json','["賢哲不同才，論心則皆仁。", "去就不同趨，惟義乃可親。", "仁非比周用，推己以逮人。", "義非楚越疏，顧不私其身。", "伊誰覺後世，凜凜周先民。", "姬公徂東山，流言起齗齗。", "召公發金匱，王逆繡裳新。", "它日奭有疑，不悅公未逡。", "子往暨汝濟，公語尤諄諄。", "忠誠共白日，勢利一飛塵。", "姬家八百祀，盛業兩公因。", "其人不可見，此意常自真。", "吁嗟刎頸士，一失爲參辰。", "我思尚友徒，表此三千臣。"]'),
('14ff6b43-5d7b-4b52-a275-a12966b6ed8f','寄張趙二相三首  其二','胡寅','宋','宋诗','song-poetry','','[]','昨朝觀抵戲，千步廣場對。',168,'全唐诗/poet.song.108000.json','["昨朝觀抵戲，千步廣場對。", "甲也烏獲徒，顧步熊虎態。", "乙也乘勢來，躑躅進復退。", "或有敗甲心，弦矢立其背。", "甲初奮左臂，一箭奮者廢。", "甲復舉右股，再射舉者墜。", "坐令乙取勝，或乃一笑快。", "因思中山趙，秦睨猶拾塊。", "何爲廉將軍，恥與相如會。", "不念國之存，以吾兩人在。", "一朝私仇破，兩虎共穴內。", "他年藺公薨，頗老仍見代。", "坑兵四十萬，大福遂不再。", "依然卞莊子，拱手視成敗。"]'),
('ccaf1e95-23f9-43d2-8ea6-bca936dc8463','寄張趙二相三首  其三','胡寅','宋','宋诗','song-poetry','','[]','河出崑崙墟，江出岷山底。',168,'全唐诗/poet.song.108000.json','["河出崑崙墟，江出岷山底。", "涵涵受百瀆，滾滾經萬里。", "水惟準之平，而德鑑之比。", "離堆與砥柱，何事中流起。", "坐令平者傾，復使明者滓。", "臣門雖如市，臣心要如水。", "勿爲砥柱激，乃作天地紀。", "在家而有怨，惟舜處父子。", "在邦而有怨，惟旦憂室毀。", "夫豈忿慾哉，過是非天理。", "蕭曹貧賤交，隙自將相起。", "迄能除芥蔕，至死相推美。", "彼亦何所監，覆轍有餘耳。", "同時秦漢人，異趣百代史。"]'),
('c4ea10ec-5ffb-40ff-855b-0bf4295d8ee5','題浯溪','胡寅','宋','宋诗','song-poetry','','[]','戎馬胡爲踐神京，翠華東巡朝太清。',192,'全唐诗/poet.song.108000.json','["戎馬胡爲踐神京，翠華東巡朝太清。", "扶桑大明湧少海，虎符百萬屯雲興。", "皇威意無窮髮北，老傅坐籌自巾幗。", "謀臣猛將俄解體，吹入胡笳一蕭瑟。", "塞南莽莽多穹廬，塞鴈年年不繫書。", "回首朔雲清淚滿，傷心玉坐碧苔虛。", "中興聖主宣光類，羣材合沓風雲會。", "會稽甲楯今幾時，於鑠王師尚時晦。", "最喜鄴侯開肅宗，不謂晨昏急近功。", "竟使大唐宏業墜，豐碑有媿昭無窮。", "徙倚碑前三太息，江水東流豈終極。", "頌聲諧激不爲難，君王早訪平戎策。"]'),
('bc31cdea-a91f-4eb1-b32f-a1fb73361af1','和范元作五絕  其一','胡寅','宋','宋诗','song-poetry','','[]','馬遷法左氏，實錄繫日月。',24,'全唐诗/poet.song.108000.json','["馬遷法左氏，實錄繫日月。", "孰傳經世學，儻可論絕筆。"]'),
('6689bdd7-2504-43cc-820f-2b5b32b8f464','和范元作五絕  其二','胡寅','宋','宋诗','song-poetry','','[]','久矣閟大音，無譏鄶以下。',24,'全唐诗/poet.song.108000.json','["久矣閟大音，無譏鄶以下。", "一聞入聖處，萬古洗凡馬。"]'),
('279a423f-0458-4dbc-a482-e878b12111f4','和范元作五絕  其三','胡寅','宋','宋诗','song-poetry','','[]','種學根不深，履道乃郵傳。',24,'全唐诗/poet.song.108000.json','["種學根不深，履道乃郵傳。", "欲收反約功，必也破萬卷。"]'),
('bf6a6ee7-1f26-477e-ae22-f9fc9eff2944','和范元作五絕  其四','胡寅','宋','宋诗','song-poetry','','[]','挾策博塞殊，愚智相千萬。',24,'全唐诗/poet.song.108000.json','["挾策博塞殊，愚智相千萬。", "反躬誠且樂，此事要早辦。"]'),
('3225f26a-53d5-4df8-bb35-46db8f45cb24','和范元作五絕  其五','胡寅','宋','宋诗','song-poetry','','[]','閲書五行下，未勝百迴讀。',24,'全唐诗/poet.song.108000.json','["閲書五行下，未勝百迴讀。", "至道一念存，請事不遠復。"]'),
('d3d3f353-2852-44ea-af63-6d946d5f9778','和韓司諫叔夏樂谷五吟 布被','胡寅','宋','宋诗','song-poetry','','[]','昔年司馬公，清德如伯夷。',96,'全唐诗/poet.song.108000.json','["昔年司馬公，清德如伯夷。", "簞瓢不改樂，又似吾先師。", "平生一布被，天地乃吾知。", "豈比平津侯，挾詐坐受嗤。", "公今蹈前修，自適性所宜。", "不受寒暑變，炎凉但相推。", "彼美錦繡溫，蒙覆真虎皮。", "愧非三絕手，何以嗣銘詩。"]'),
('6cfb37b6-7cdf-42c1-b0b6-43b5f1b3fb3b','和韓司諫叔夏樂谷五吟 竹枕','胡寅','宋','宋诗','song-poetry','','[]','故鄉清渭濱，一節取君子。',96,'全唐诗/poet.song.108000.json','["故鄉清渭濱，一節取君子。", "相從大江南，展轉秋風裏。", "清慵笑玉便，傲兀勝隠几。", "屏山煙景媚，醉倒日高起。", "此君通晝夜，俗士乃輕鄙。", "願言一奠枕，四海春睡美。", "鏗鏗孫子荆，未便洗吾耳。", "得意大槐宮，古今真夢爾。"]'),
('e8de1240-ebef-4cd2-8c2b-09ac4bdac5d8','和韓司諫叔夏樂谷五吟 瓦爐','胡寅','宋','宋诗','song-poetry','','[]','靈臺凈含光，虛室自生白。',96,'全唐诗/poet.song.108000.json','["靈臺凈含光，虛室自生白。", "縹緲沉水香，瓦篆青冪冪。", "何用金狻猊，浮動羅綺席。", "緇黄手秉持，兒女衣篝僻。", "一從胡塵漲，岱華腥膻隔。", "君臣若際會，至治發明德。", "普熏遍十方，氤氳本埏埴。", "何人學孔禱，鼻觀久已塞。"]'),
('e647be74-9217-4821-9a20-fcfa283d5021','和韓司諫叔夏樂谷五吟 蒲團','胡寅','宋','宋诗','song-poetry','','[]','少年慕簡冊，編蒲抄古書。',96,'全唐诗/poet.song.108000.json','["少年慕簡冊，編蒲抄古書。", "有聞未能行，常恐迷厥初。", "青氈雪窗夜，卧起卷復舒。", "歲久亦穿穴，客冷不及渠。", "知公已坐忘，物我歸如如。", "黄團穩疊足，繡茵一籧篨。", "傳聞伏蒲諫，天子懷每虛。", "出處諒未免，裹輪聯鋒車。"]'),
('07743e6c-da76-4c10-95e9-cdc4686eee40','和韓司諫叔夏樂谷五吟 紙帳','胡寅','宋','宋诗','song-poetry','','[]','細皺卷寒波，輕明籠白霧。',96,'全唐诗/poet.song.108000.json','["細皺卷寒波，輕明籠白霧。", "何以相徘徊，歲晚正凝沍。", "枕欹一尺竹，被展幾幅布。", "賢哉楮先生，不以貧不顧。", "夜玉圍紅綃，羞澀强自賦。", "書生說富貴，志士安貧素。", "風驚銀海潮，春在明月庫。", "先生睡方濃，不覺糟床注。"]'),
('97342348-c2b3-428a-9070-b16eb6ea8800','送黄彥達歸建安','胡寅','宋','宋诗','song-poetry','','[]','漳濱讀書夜復日，十七年間駒過隙。',128,'全唐诗/poet.song.108000.json','["漳濱讀書夜復日，十七年間駒過隙。", "相逢忽認語音存，面皺髯張都不識。", "歲晚懸鶉百結穿，坐寒我亦無青氈。", "少時意氣今何似，對此猶能吸百川。", "北風草木傷遲暮，秀嶺長松色如故。", "須知憂道不憂貧，莫厭儒冠羨紈袴。", "坐悲四海方橫流，長劍未試心未休。", "寄語幔亭雲外客，他年終約紫霄遊。"]'),
('28d8f943-d427-4e21-acfc-5f06bc55ea7a','題全州礱岩','胡寅','宋','宋诗','song-poetry','','[]','蓋山限華夷，夷水不得出。',144,'全唐诗/poet.song.108000.json','["蓋山限華夷，夷水不得出。", "澗壑相奮撞，竟朽此山骨。", "想其初洞達，借勢有神物。", "臂開青石壁，黤黮烏龍窟。", "奔流成長溪，岩洞寒突兀。", "秉燭千步遊，怪景纔彷彿。", "華髮結乳頂，空翠誰掃拂。", "石田耕未熟，石鼓響不沒。", "靈仙眇羽化，古廟凜紆鬰。", "我來庚伏初，弄水解纓紱。", "清甘流渴肺，妙聽含鍾律。", "兩腋御泠然，回首歎飄忽。"]'),
('91f6c406-af54-422c-9144-005f2e8d8c59','示上封長老洪辯','胡寅','宋','宋诗','song-poetry','','[]','濯足瀟湘湄，瘦藤拄衡岳。',228,'全唐诗/poet.song.108000.json','["濯足瀟湘湄，瘦藤拄衡岳。", "尋山半吳楚，何意得雄邈。", "青冥幾石級，屐齒響犖硞。", "低昂度翳鬰，軒翥見披剝。", "下視千萬山，碧海潮初落。", "無風浪自鼓，浮動洶嶽嶽。", "誰云地南傾，鼇足有踸踔。", "請看高幾許，天近只一握。", "高寒變沖融，三伏謝焦灼。", "羣松何人種，凜立傲冰雹。", "况彼凡草木，跂望難簉著。", "精廬憑佛力，雲外聊自託。", "上方連兜率，下界指蝸角。", "道人洪河辯，萬卷歸領畧。", "湯休以詩鳴，澄觀老禪縛。", "相從塵垢外，一語符啐啄。", "愁雲結蒼梧，來雁眇燕朔。", "鄴侯有舊隠，此興吾數數。", "不須理牙籤，借問有三學。"]'),
('13155b68-974a-4ae0-9d8b-37f96ebcd26f','示高臺足菴紹印','胡寅','宋','宋诗','song-poetry','','[]','萬生紛綸墮迷網，誰能自拔起情想。',192,'全唐诗/poet.song.108000.json','["萬生紛綸墮迷網，誰能自拔起情想。", "隙塵初傍陰色空，燒草又趁春風長。", "將身出家參佛祖，此病中作膏肓養。", "足菴道人肯珍重，不與凡流較斤兩。", "彼方彈雀棄隋珠，我自舍魚取熊掌。", "高臺平挹石廩翠，古轍下輾雷溪響。", "粥魚齋鼓不經營，竹月松風靜來往。", "定心古井波浪息，夜氣靈源襟韻爽。", "憶昔幽尋度雲壑，見投佳句論鄉黨。", "豈惟高格擅風騷，頗信中扃得平廣。", "轉頭塵事還匆匆，入夢勝遊真莽莽。", "山梅有信寄一枝，更欲青鞋快真賞。"]'),
('080f8156-7665-44cb-9a41-54da6ba85849','記夢','胡寅','宋','宋诗','song-poetry','','[]','夜夢虛齋整衣冠，客五六輩相揖還。',192,'全唐诗/poet.song.108000.json','["夜夢虛齋整衣冠，客五六輩相揖還。", "中有一人少留連，叩簷叩齒禱甚虔。", "顧謂吾儕曷傾耳，紅藥叢深鳥聲美。", "翻枝颭葉縹緲間，俄有珍禽集雕欄。", "宛然小鶴未省見，羽翮紺碧光斕斑。", "凝眸一瞬觀對立，忽成四鶴齊飛入。", "赴予紛泊若投林，藻錦縈带復動衿。", "綠毛么鳳只倒掛，翠襟鸚鵡空好音。", "或將攬取不從手，相視眙愕萌爭心。", "吾殊無言行且睨，與客徐理出戶意。", "徘徊八翼疑驂鸞，雜遝諸儒競連袂。", "不知剝啄誰扣門，推枕高樹晨光暾。"]'),
('f7333cdd-4f43-4e57-a022-dd812f0c64d3','示能仁長老祖秀','胡寅','宋','宋诗','song-poetry','','["\u8861\u5c71"]','此世未可出，太虛無古今。',192,'全唐诗/poet.song.108000.json','["此世未可出，太虛無古今。", "一塵絕點染，萬象羅蕭森。", "白雲從何來，舒卷亦無心。", "流風散遠影，花雨釋重陰。", "俄然際碧海，倏爾歸遥岑。", "方來詎可執，已去誰能尋。", "何人知此意，魚鳥徒高深。", "道人乃如許，灑落湘之南。", "冥鴻豈避弋，倦鶴亦投林。", "昔年淮泗間，清譽喧佩簪。", "石塔縫無際，鹽官鼓無音。", "衡山亦何有，神廩供爨鬵。", "十年一紙衲，綵線穿金針。", "上方萬壑外，微笑開我襟。", "幽懷久自契，俗慮何由侵。", "攀蘿共明月，流水寫瑶琴。"]'),
('d59db737-8753-4e3a-8565-6630125407a1','題能仁照菴紹亨所建','胡寅','宋','宋诗','song-poetry','','[]','福州多僧天下聞，緇衣在處如雲屯。',192,'全唐诗/poet.song.108000.json','["福州多僧天下聞，緇衣在處如雲屯。", "何人能了一大事，齋魚粥鼓徒紛紛。", "雲中復表第二月，何異汙渠鑑毛髮。", "不獨詩人水鏡昏，定知佛祖龕燈滅。", "道人朅來南山下，蓋頭隨分茅一把。", "菩薩果地已孤高，石廩峯前更瀟灑。", "草菴初就來乞名，試往尋之水竹清。", "莫訝此菴安四壁，大千沙界總分明。", "觀君所至金碧煥，公才利用如澄觀。", "隣僧無頼苦侵疆，何似古人不爭畔。", "從他三毒癡貪嗔，我自元無一點塵。", "携菴南北東西住，萬象光中獨露身。"]'),
('f87548dc-a052-48cb-bb21-57db3546d2be','送余澤還義興','胡寅','宋','宋诗','song-poetry','','["\u8861\u5c71"]','挾策漳濱兩韶稚，君後南隨州計吏。',352,'全唐诗/poet.song.108000.json','["挾策漳濱兩韶稚，君後南隨州計吏。", "相逢冠歲璧池頭，頓覺詞華使人惴。", "謂宜雲路恣騰踏，豈料霜蹄多蹶躓。", "君才視我十倍加，蓄積那堪五經笥。", "已窮孟軻不動處，得喪窮通歸一致。", "每懷會合未曾款，輒復鴻燕春秋異。", "寸莛才欲撞舂容，不盡之音耳空記。", "去年邂逅得所願，千里過我少停轡。", "圍爐燒栗忘夜分，蹙雪訪梅喜春至。", "窺園細看百卉動，陟榭滿挹千峯翠。", "讀君舊詩黄鍾律，觀君新德清廟器。", "默求至善不近名，下視羣愚非飾智。", "常虞涉世傷坦率，見語躬行合謹細。", "值君隠憂方食蓼，而我美疹如紾臂。", "飛觴引滿不復能，戰飲吳門夢中事。", "采菊聊同茗碗清，丸艾時歸藥婆利。", "忠言贈公豈肉骨，益友貺予真補劓。", "浮雲聚散古則爾，人生出處孰無累。", "聞道雙珠已候門，便乘一葉同插翅。", "朱樓婉娩托旅夢，江樹霏微攪離思。", "一區衡山勿負約，三絕麟經更涵粹。", "得時而駕諒不免，有使且寄相思字。"]'),
('3fd306d5-25d4-4e6f-af5a-263b0422848f','送朱翌赴召','胡寅','宋','宋诗','song-poetry','','[]','青松出澗底，志已楝梁具。',120,'全唐诗/poet.song.108000.json','["青松出澗底，志已楝梁具。", "平生飽霜雪，歲晚中尋度。", "屈伸諒有時，窮達係所遇。", "如君才與學，八面有餘裕。", "志修文自昌，身阨守愈固。", "已甘韞匵藏，寧願莫邪鑄。", "急趨冠蓋林，萬里便跬步。", "時來則卿相，慎勿負平素。", "霜繁千嶂晚，天闊三江注。", "倘遇子陵臺，爲我一回顧。"]'),
('e333fed8-d455-42d5-b47f-dfad78d980ad','與范信仲及嚴陵同官納凉萬松亭','胡寅','宋','宋诗','song-poetry','','[]','黄堂無徒真面壁，休暇相招出城北。',96,'全唐诗/poet.song.108000.json','["黄堂無徒真面壁，休暇相招出城北。", "千岩窈窕萬松豪，把酒觀棋得終日。", "此邦前修邈難繼，嚴范千古堂堂色。", "用之折箠笞犬羊，否則持竿弄泉石。", "我才濩落何足道，行藏未有資身策。", "公當長嘯起家聲，雲臺高敞風塵息。"]'),
('a2056a93-df66-4cb3-a92f-87a1b2c3917e','和信仲酴醿','胡寅','宋','宋诗','song-poetry','','[]','化工收餘春，不令寂寞回。',168,'全唐诗/poet.song.108000.json','["化工收餘春，不令寂寞回。", "殷勤三月盡，更放名花開。", "燦然白雪姿，亂灑青雲堆。", "奇香滿深院，冷艷絕浮埃。", "弟昆林下蘭，執友嶺上梅。", "何年蕊珠殿，移根畫堂栽。", "邂逅得佳客，開窗設尊罍。", "檀心半未展，更著紅燭催。", "惜無傾城髻，斜插一枝來。", "賞心不可奈，折取浸瑶醅。", "可憐清夜闌，疊鼓如輕雷。", "笙簫發夢想，雲雨下陽臺。", "櫻厨未羞澀，高會意重陪。", "花魂入詩韻，屬和愧非才。"]'),
('2e46dc2a-0512-4342-897c-af57d84880c0','和吳元衡','胡寅','宋','宋诗','song-poetry','','[]','先生頌酒夸兩豪，使我讀之如飲醪。',80,'全唐诗/poet.song.108000.json','["先生頌酒夸兩豪，使我讀之如飲醪。", "詩情不逐春光老，春在毫端尤婉好。", "頗聞下堂小不佳，未欲頌公長者車。", "不道芳菲成一夢，滿城寒食藉梨花。", "便把千峯名擬峴，同撥新醅酬闕典。"]'),
('00867046-abbf-40d1-8924-61b1857dc3a1','和元衡送牡丹','胡寅','宋','宋诗','song-poetry','','[]','春工知君亦好奇，倚檻山丹開壓枝。',64,'全唐诗/poet.song.108000.json','["春工知君亦好奇，倚檻山丹開壓枝。", "山城何人識國艷，中州對此稱花時。", "新詩秀色摇京洛，詞鋒生使侵疆拓。", "金明釣賞思見之，貢花驛使來莫遲。"]'),
('aabccbb4-02e4-4a1d-9cf1-4f0cd2d7bf9d','題永州東山西亭','胡寅','宋','宋诗','song-poetry','','[]','此亭得名從子厚，琬琰一篇傳不朽。',192,'全唐诗/poet.song.108000.json','["此亭得名從子厚，琬琰一篇傳不朽。", "我來相望三百年，誤使承流稱太守。", "初無施舍慰民心，漫有詩歌諠衆口。", "東山妓女北海尊，歌舞春風醉花柳。", "欲回面勢直西南，更植脩篁遮培塿。", "卷舒雲雨襟袖間，濺浣冠纓塵土後。", "近聞王師頻奏凱，狂虜不復窺廬壽。", "吾君神武光宣上，將相宏畧方召偶。", "遄歸北狩定有期，開拓中原豈無手。", "顧予疎懶歸意迫，當世功名息心久。", "寄言悵望獨醒人，欲報厚德乏瓊玖。", "遥山蹙黛酒如江，勸我日飲無何有。"]'),
('18b97678-daae-49ab-b49e-4116d3f0fa88','題朝陽閣','胡寅','宋','宋诗','song-poetry','','[]','瀟水東來北流去，宛宛山城挾江住。',128,'全唐诗/poet.song.108000.json','["瀟水東來北流去，宛宛山城挾江住。", "城中萬瓦蔽雄觀，江外千岩自幽趣。", "朝陽近止瀟之西，繫舸捫苔上石蹊。", "翠壁劃開光黤湛，高蘿垂覆綠冥迷。", "排岩闖水飛欄出，挂插洄潭老蛟脊。", "渾疑海蜃噴珠宮，復訝樓船褰繡帟。", "鳴鸞佩玉不須論，西雨南雲手覆翻。", "寄語子牟來獨夜，試看天闕瑞霞暾。"]'),
('0ffd4ee1-4a6b-43d6-9ae9-ceb4d7e82139','題永倅廳康功堂','胡寅','宋','宋诗','song-poetry','','[]','政拙催科永陵守，實頼賢僚明可否。',128,'全唐诗/poet.song.108000.json','["政拙催科永陵守，實頼賢僚明可否。", "邦人復嗣海沂歌，倉廩雖空閭里有。", "功成將去朝日邊，更闢虛堂得晝眠。", "後圃好花初著土，前簷新竹已參天。", "貔貅未飽軍需急，赤子如魚釜中泣。", "若知王業在農桑，國勢無勞憂岌岌。", "酒闌四壁讀前碑，吏隠猶勝五馬隨。", "千古濂溪周別駕，一篇清獻錦江詩。"]'),
('ba4ceb55-ff4b-4761-bc5a-97d15da11987','送茶與陳霆用賈閣老韻','胡寅','宋','宋诗','song-poetry','','[]','閩相渺天涯，新茗誰與促。',96,'全唐诗/poet.song.108000.json','["閩相渺天涯，新茗誰與促。", "對茲火雲候，漫說酒千斛。", "要須臨水榭，滿啜一甌玉。", "泠然生兩腋，萬里那更僕。", "想君坐茅齋，口授汗如沃。", "飽餐先生饌，睡思莽難逐。", "玉川亦何有，撐拄文字腹。", "遣餉良未多，精品端不辱。"]'),
('bc590e00-e917-4472-9ee3-1a3352fdec33','用前韻示賈閣老','胡寅','宋','宋诗','song-poetry','','[]','壑源春未回，已著金鼓促。',96,'全唐诗/poet.song.108000.json','["壑源春未回，已著金鼓促。", "爭先入包匭，價比金盈斛。", "何人敢僣睨，奉御食惟玉。", "草荈空有名，氣格臣與僕。", "緬懷侍凝粹，苦口同啟沃。", "散仙今得伴，鸞鳳相追逐。", "雪泛定州甆，澆此飲河腹。", "飽食慚太倉，那復驚寵辱。"]'),
('9ab1ec05-fc6b-4974-8ba6-91acd01e4667','遊雲湖','胡寅','宋','宋诗','song-poetry','','[]','衡湘久來往，眼到山輒對。',288,'全唐诗/poet.song.108000.json','["衡湘久來往，眼到山輒對。", "愛山真自性，久看眼未礙。", "今朝渡石潭，蘭槳亂青带。", "初升岸稍高，忽喜地更大。", "行行兩垣間，沙路得平快。", "豁然見良疇，小覽百里外。", "涵溶趙家汑，千頃疏幾澮。", "人家隔楊柳，或映桑林背。", "連連麻麥墟，雞犬達鳴吠。", "宛如京洛郊，北望一悵慨。", "古城誰所築，隠隠僅如塊。", "娉婷九冢藏，巧緻六寶在。", "想其夸壯時，豈念遺迹晦。", "主人隴西生，懇款具鮭菜。", "墅前稼尤美，彌壤黄雲曬。", "雲湖從此逝，日暖風不噫。", "循岡逶迤登，呀口駭漰沛。", "是名湖西缺，節縮有石埭。", "舍輿尚盤陀，漸見湖尾派。", "菰蒲傍籬落，獵獵村沽旆。", "曳筇大隄長，隄址屹然塞。", "胡床羅四五，植傘據其會。", "恍若畫圖張，綵筆窮物界。", "滿奩開玉鏡，萬象自清汰。"]'),
('d4d51bd0-64f4-435d-b3bd-7ac6747c90dd','示龍王長老法讚','胡寅','宋','宋诗','song-poetry','','[]','東峯峨龍頭，西嶺掉其尾。',192,'全唐诗/poet.song.108000.json','["東峯峨龍頭，西嶺掉其尾。", "蜿蜒藏爪鬣，雲卧久未起。", "誰憑象教力，掛腹千柱啟。", "重天飛鐵鳳，寶地按金指。", "於今幾百年，松柏合抱峙。", "悄無車馬塵，一徑渺雲水。", "我來亦何事，蠟屐自遊徙。", "讚公好禪伯，道俗共懽喜。", "浮雲本無心，錫杖聊壁倚。", "借問此山名，其實安所止。", "答云蒼岑頂，萬觴湧清泚。", "伊何司蓄洩，神物宜在此。", "又言干戈際，流血幾萬里。", "龍胡爲自珍，岩洞深伏弭。", "笑挹香松槽，漱盥白玉齒。", "清風出長嘯，月凈天如洗。"]'),
('5a9cec0e-ef33-4813-ba67-796e67910086','示龍王長老法讚用舊韻先公佳城與寺相直','胡寅','宋','宋诗','song-poetry','','[]','堂堂感麟翁，耿耿跨箕尾。',192,'全唐诗/poet.song.108000.json','["堂堂感麟翁，耿耿跨箕尾。", "已垂百世芳，何用東山起。", "平生夢奠處，鬰鬰佳城啟。", "禪枝附奕葉，魚粥常千指。", "老龍卧頹波，秀木森嶷峙。", "堆螺沃黛山，瀉玉摐金水。", "上人一錫拄，心寂倦他徙。", "我亦希子文，仕已忘慍喜。", "時來語道要，中立旁不倚。", "而君樂幻空，說定不說止。", "永懷先覺人，愧發汗流泚。", "彝倫出筆削，一是無彼此。", "修程不自勉，九十半百里。", "相彼齅世芬，所向輒摇弭。", "未知吾相馬，異質遺毛齒。", "更須求真龍，萬古資一洗。"]'),
('1357144b-951b-4886-b450-b15228378bc9','賦韓叔夏雪齋','胡寅','宋','宋诗','song-poetry','','["\u8861\u5c71"]','君不見齊王築宮夸孟子，瑶殿珠階千柱啟。',136,'全唐诗/poet.song.108000.json','["君不見齊王築宮夸孟子，瑶殿珠階千柱啟。", "只知歌舞暖娥眉，君未能賢寧樂此。", "又不見玉局文章萬丈光，七年忍凍吟黄岡。", "忽騎白鳳凌天去，江上空餘一草堂。", "不如衡山樂谷藏春風，明窗小閣地爐紅。", "物自涅緇分凈穢，我方瀌睍閲窮通。", "夜驚山竹珊瑚折，起愛溪松濛曉月。", "蹇馿烏帽去相尋，可但子猷清興發。"]'),
('67f2c2e2-1c4f-456c-938c-56f093b15bc2','和仁仲歸鄉有感','胡寅','宋','宋诗','song-poetry','','[]','大堤蜿蜒挾江長，卉木同泛春風香。',80,'全唐诗/poet.song.108000.json','["大堤蜿蜒挾江長，卉木同泛春風香。", "青青嘉蔬不用買，采擷烹瀹皆堪嘗。", "羜肥豕腯白黑正，酒美魚賤吞江鄉。", "豈惟物産具豐好，地勢固可爭雄强。", "歸來作賦興不淺，一飯美芹心詎央。"]'),
('c1e599d1-0be6-4fcd-b1c8-159edd07ef42','登南紀樓','胡寅','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','西望巫峽峯，東望洞庭湖。',288,'全唐诗/poet.song.108000.json','["西望巫峽峯，東望洞庭湖。", "南望大江橫，北望楚王墟。", "平時十萬戶，鴛瓦百賈區。", "夜半車擊轂，差鱗銜舳艫。", "麥麻漫沃衍，家家足粳魚。", "深山雞犬接，誰復識於菟。", "挻禍者何人，火獵而兵屠。", "庚戌日南至，渠魁宴宜都。", "一膾八百姬，坐無羊與豬。", "葛伯殺餉童，湯征自亳徂。", "恢恢天網漏，莽莽一紀餘。", "遺民百存一，茨棘伏且逋。", "有田不敢耕，十倍出賦租。", "籍戶析丁口，奏言民數敷。", "一縣三十家，一城三百廬。", "指爲太平象，蒼穹焉可誣。", "翩翩兩孤鶴，歸自青海隅。", "長松雖好在，池圃傷榛蕪。", "邦君能好客，授館高明居。", "春風摇宇宙，慘澹心盤紆。", "玉花暗寒食，桑穀凍不蘇。", "流民渡沔來，曳牛負其孥。", "似聞俶擾中，復有紅巾徒。", "轇轕隨鄧間，厥意知何如。"]'),
('704b50b6-4f66-4b3a-8a10-7a8346d7c67e','題關雲長廟','胡寅','宋','宋诗','song-poetry','','[]','西方有幻師，以利行幻術。',288,'全唐诗/poet.song.108000.json','["西方有幻師，以利行幻術。", "利他乃甘言，自利則其實。", "曾微證形象，顧喜論恍惚。", "可憐億兆人，明智百無一。", "泯然俱受紿，寧以鬼自怵。", "疑怖既迫心，祈禱便屈膝。", "千載浮屠氏，箇箇提一律。", "雲長忠烈士，蜀漢凜三傑。", "許身初擇義，遇主益秉節。", "一受先主知，不爲曹公屈。", "最後圍樊城，許南已無拂。", "智畧孫吳儔，議徙股膽慄。", "惜哉片言戾，壯志遂紆鬰。", "至今想英風，使我竦毛骨。", "廟祀禮則宜，爲國有典秩。", "而彼天台僧，相此山水窟。", "欲繕廬而處，假靈宣鬼物。", "章鄉城近止，將軍此焉沒。", "斯人兼畏仰，吾計行可必。", "唱云暴悍魂，岩壑擅營室。", "從吾受凈戒，父子歸命佛。", "初猶未赫烜，靈響沉寂謐。", "奈何無盡翁，作記極詞筆。", "一毛成萬鈞，財施日盈溢。"]'),
('46e74614-2652-4205-9df7-ea38a5bb45d9','和仁仲孱陵有感','胡寅','宋','宋诗','song-poetry','','[]','奸雄乘亂謀稱帝，不暇從容問傳器。',224,'全唐诗/poet.song.108000.json','["奸雄乘亂謀稱帝，不暇從容問傳器。", "荀公死坐靳殊錫，文舉誅因白畿地。", "金根曲蓋乘五時，謬以踞火尤吳兒。", "懸知以鼠睨漢獻，終欲搏噬如饑狸。", "吁嗟白日蒙浮雲，豫州奮臂提孤軍。", "虎熊爭先氣烈烈，魚水相契情氳氳。", "赤壁端如殽二陵，於操猶或稱其能。", "身在行間一交戰，阿瞞始信河難馮。", "仲謀亦恃江濤漲，豈憂炎德終淪喪。", "孱陵自駐遏吳師，要知身繫蒼生望。", "丈夫蓋棺事方休，未報平生宗國仇。", "英雄安得無塊土，固令於此分荆州。", "春風吹花不濡滯，綠滿郊原何蔽翳。", "前漢興隆後漢頹，永懷啟沃臨行際。"]'),
('d97aed93-2141-443b-b465-c0d6bc992438','和仁仲遊桃源','胡寅','宋','宋诗','song-poetry','','[]','桃江穩楫蘭舟渡，記得劉郎有仙路。',264,'全唐诗/poet.song.108000.json','["桃江穩楫蘭舟渡，記得劉郎有仙路。", "未能趨海訪神仙，且欲沿溪看紅樹。", "釣竿已自慰羈束，平生况得滄洲趣。", "最欣傲吏輕儻來，擬學淵明賦歸去。", "與君一問桃花宿，豈但行如武陵暮。", "伯陽八十有一篇，立教清凈貴自然。", "神仙之說何所始，虛怪汗漫無中邊。", "漁郎迷路去家久，雖踐勝境終迴旋。", "雕辭飾實好事者，至令千載猶流傳。", "寧聞自古有仙人，茂陵垂老一語真。", "豈伊冠履薦紳士，惑溺不異蚩蚩民。", "誠能御氣友造物，陋彼蟬蛻悲埃塵。", "想見桃源之野花正開，牧兒模管吹出芳林來。", "不知人家尚幾許，雲屏玉帳空悠哉。", "霏紅泛綠竟杳杳，我亦乘興山陰迴。", "不如與君歸種待蕡實成蹊，晝永無地生蒼苔。"]'),
('32ce62f3-d383-4904-8dc8-d2510bb71b92','歸舟濡滯示仁仲','胡寅','宋','宋诗','song-poetry','','[]','扁舟下荆江，信宿七百里。',192,'全唐诗/poet.song.108000.json','["扁舟下荆江，信宿七百里。", "少縈玉州岸，翠壁紅樓起。", "提携桃竹杖，飛步同徙倚。", "永嘯來長風，極望際天水。", "登臨興未窮，歸思孰能弭。", "枕湖駕高浪，萬頃期一葦。", "飛廉不借便，進尺或退咫。", "莽蒼入葭蘆，回環亂洲沚。", "刺篙力言匱，挽纜路仍圮。", "物用各有時，奡盪未可鄙。", "風水亦何心，邂逅乃如此。", "快意得濡滯，贏縮固其理。", "子文三已仕，了不見慍喜。", "斯猶未稱仁，胡不聽行止。", "南山定非遠，風駛一帆耳。", "携壺上翠微，旅瑣爲君洗。"]'),
('912d0133-50e0-460e-9dce-90efeda4223d','過方廣不遇主僧留示','胡寅','宋','宋诗','song-poetry','','[]','崎嶇犖确梁復矼，頳肩四力流汗杠。',195,'全唐诗/poet.song.108000.json','["崎嶇犖确梁復矼，頳肩四力流汗杠。", "笋輿軋軋三十里，乃值道人遊近邦。", "倦軀且借禪榻卧，仰睇傑閣丹青龐。", "泉湍夜挾風雨壯，撼床殷枕如濤江。", "晴巒空濛染佛髻，白月皓皓團僧窗。", "高杉大松間修竹，烟旄霧蓋參雲幢。", "要須酒壺綴羊羫，哀簫怨笛歌鬟雙。", "緬懷東岩謝太傅，提携靚艷凌崆㟅。", "不學香山白居士，只與如滿相敦厖。", "想君聞之笑且{口厖}，西東分流嶺頭瀧。", "歸來亦復有何好，方寸坐以鐘魚降。", "留詩六反皆震動，魚誰考擊鐘誰撞。"]'),
('486ead04-0649-4c92-a940-108663b1ca1a','和叔夏海棠次東坡韻','胡寅','宋','宋诗','song-poetry','','[]','久矣心灰形槁木，有爛錦衾誰與獨。',224,'全唐诗/poet.song.108000.json','["久矣心灰形槁木，有爛錦衾誰與獨。", "殷勤調護得繁枝，抹黛施朱盡凡俗。", "池上靚粧開曉鏡，露晞嬌潤離湯谷。", "佳人得意矜絕代，陋彼牽蘿補茅屋。", "真賞幸逢尊有酒，清玩可使食無肉。", "十眉彷彿畫難親，百匝徘徊看未足。", "兩旬綠秀承紅嫩，一日籬槿何能淑。", "朝來但覺花照眼，夜去不夢松生腹。", "休誇艷杏蔭白鷼，漫說夭桃夾疎竹。", "固知尤物人共愛，也使先生動心目。", "老坡有詠記江城，少陵無句慚巴蜀。", "顧我荒詞陪絕唱，何異斥鷃追黄鵠。", "夜來風雨太豪橫，惆悵遥峯縈度曲。", "不如却賦黑牡丹，寄語孔翠防抵觸。"]'),
('5a959798-a8bb-4638-8368-54a381e4a147','和彥達新居','胡寅','宋','宋诗','song-poetry','','[]','喜居夏屋成，竹樹讙燕雀。',156,'全唐诗/poet.song.108000.json','["喜居夏屋成，竹樹讙燕雀。", "門徑眇雲水，亦見輪蹄錯。", "君本有用才，魏匏自濩落。", "平生五車勤，歲晏一簞樂。", "永言青眼舊，每笑春風薄。", "共保貞石心，火炎豈能鑠。", "激志山岳聳，放懷宇宙廓。", "過我雖蹁躚，拄杖得所托。", "但慚城市遠，兼味止葵藿。", "方羅玉麈揮，忽聽金奏作。", "薰然陶天和，寧復慕人爵。", "澹泊道義交，已謝勢利怍。", "遥知尊杓存，酒熟待同酌。"]'),
('2060fd0c-2ab1-4492-89ff-a71105439d59','寄題義陵吳簿義方堂','胡寅','宋','宋诗','song-poetry','','[]','萬生天地間，靈者乃知義。',288,'全唐诗/poet.song.108000.json','["萬生天地間，靈者乃知義。", "何獨於義明，而利心亦熾。", "茲焉分兩軌，君子小人異。", "秉義一毛輶，百川利趨亟。", "紛紛冒貨賄，役役奔勢位。", "資之以狼貪，攘之以螳臂。", "深較毫釐差，交攻兵刃𨧫。", "大賈五百金，徙蜀死無庇。", "小偷慚簠簋，褫魄對犴吏。", "一生幾量屐，身後糞土棄。", "夫豈無良心，習慣遂殊致。", "試令呼之跖，悍目艴然視。", "又或號之夷，喜笑亦隨至。", "也知清譽好，寧自濁汙置。", "頹波日不反，方跖尚當愧。", "有美短簿賢，老矣能劼毖。", "善爲子孫謀，闢堂寘經笥。", "松筠歲寒色，不種春藻媚。", "郴山固奇變，其江瀉青翠。", "盤礴以蜿蟺，淑氣宜産粹。", "是將出秀民，庸稱名堂意。", "願言承學子，不受流俗漬。", "雖共雞鳴起，拳拳閔顔志。", "本原孝而恭，由此充其類。"]'),
('a9cce767-a1dc-41e5-ad12-bfc4f20c62cd','和仁仲賞梅','胡寅','宋','宋诗','song-poetry','','[]','萬竅鳴饕風，千秋厄嚴雪。',164,'全唐诗/poet.song.108000.json','["萬竅鳴饕風，千秋厄嚴雪。", "花心獨沖融，足以慰愁絕。", "太和起孤根，枝上見明滅。", "稍稍占芳辰，時時破苞結。", "天葩忽晏粲，餘卉盡騷屑。", "培植幸逢賢主人，平臺翠竹承清薰。", "要看千樹挂山月，肯把一枝縈鬢雲。", "輕風休吹落繽紛，待我詩成酬繼君。", "飛觴半酣未忍去，詩情花氣相氤氳。", "須知魏夫人，元長姑射神。", "咄哉趙飛燕，况乃楊太真。", "但願華筵對晴昊，年年領袖百花春。"]'),
('6330637d-1df2-4939-bfcf-a0e86c102f9c','赴德秀海棠之集','胡寅','宋','宋诗','song-poetry','','[]','穿山復履塍，忽望翠林杳。',120,'全唐诗/poet.song.108000.json','["穿山復履塍，忽望翠林杳。", "漸近一崦環，茅簷凈而小。", "赴君雞黍約，仍被酒壺繞。", "爛爛庭下花，迎予遍開了。", "誰將淡燕脂，染雪團枝裊。", "枯碁忘勝負，響鐵聽窈眇。", "煩襟浣一笑，至樂如此少。", "愛君富才藝，守約自强矯。", "諸子如松筠，意氣在雲表。", "幸是田舍隣，不作離別悄。"]'),
('fefe128c-2dbd-4da7-a742-dc4b80e50296','和劉彥沖白髮','胡寅','宋','宋诗','song-poetry','','[]','避炎掃浄室，卧看浮爐烟。',168,'全唐诗/poet.song.108000.json','["避炎掃浄室，卧看浮爐烟。", "讀君五字詩，鶴髮驚臞仙。", "緬懷少壯日，意氣橫無邊。", "春風鬰雙鬢，綠草爭芳妍。", "酒豪既跌宕，花惱仍狂顛。", "涉境如刺繡，針行久忘邅。", "中路一線通，悟彼稱世賢。", "不知老將至，此道聞尼宣。", "高山戴雪早，從人嘲樂天。", "青青復種種，榮謝理固然。", "市翁一彈籋，意眇飛鴻前。", "何況大丈夫，乃顧兒女憐。", "爲語偓佺輩，癡心莫攀緣。", "褭蹄諒可鑄，此物無由玄。"]'),
('09fea058-b8e1-4771-9ecc-76a64c5382d4','醉步前溪示彥沖','胡寅','宋','宋诗','song-poetry','','[]','溪南溪西渺雙溪，中有良苗綠千畦。',112,'全唐诗/poet.song.108000.json','["溪南溪西渺雙溪，中有良苗綠千畦。", "參差人家傍脩竹，隠約負戴通山蹊。", "南溪先生冰雪胸，虛堂坐詠荷花風。", "西溪散人晞汗髮，半夜泉頭飲明月。", "欲賞奇文析疑義，藴隆當路不可越。", "安得阿香輕著鞭，驅龍噀雨玄雲邊。", "徑携枕簟就公宿，對床飽聽秋聲懸。"]'),
('bc4b001f-45b9-4a6c-935c-2510c310a023','和彥沖三日飲','胡寅','宋','宋诗','song-poetry','','[]','名園直萬金，一頃連芳蔭。',168,'全唐诗/poet.song.108000.json','["名園直萬金，一頃連芳蔭。", "秀巒千尋矗，石井百尺深。", "花殘尚聞鶑，林勝不留鵀。", "時來覓清暑，却扇凉沉沉。", "三盃有道通，萬戶無法禁。", "平生師洙泗，正爾戒已甚。", "相彼無漏學，亦復忌疏滲。", "紅顔不肯駐，白髮來寖寖。", "洗心聆妙語，至味良足飲。", "常聞麗澤兌，美潤相灌浸。", "淡交那甘壞，諒直靡讒譛。", "此歡屬吾輩，端匪異人任。", "又憐囁嚅子，有口終自噤。", "不若更歌呼，醉挽溪流枕。"]'),
('b525c850-37bf-47a1-807d-a1659fb289f7','又和早飲','胡寅','宋','宋诗','song-poetry','','[]','零露漙漙風滿塘，美人不來儼分行。',96,'全唐诗/poet.song.108000.json','["零露漙漙風滿塘，美人不來儼分行。", "天葩艷然出翠被，倚檻嫋嫋傳秋香。", "對之索酒飛觴快，浩如一海朝千派。", "主人絕倒任忘形，接籬便向三花掛。", "狂夫未是詩酒豪，先生卓爾能禪逃。", "忽聽雷聲起淵默，坐使萬竅皆呼號。"]'),
('ae3bab34-3473-4b4e-81fc-a42601b10349','自開善寺飯已赴彥脩之集新陂初成次其韻','胡寅','宋','宋诗','song-poetry','','[]','旱氣欲流石，澗溪失盈溶。',168,'全唐诗/poet.song.108000.json','["旱氣欲流石，澗溪失盈溶。", "況逢青田渴，萬鍤决使東。", "南山思照影，三日雲氣重。", "玉蜺忽墮地，行君竹林中。", "潤騰百年樟，翠寫千丈松。", "澄之新湯橫，浄綠涵秋容。", "是日看雨花，一香萬緣空。", "歸來趁清約，賞心還此同。", "桂枝耀三更，裊裊來天風。", "名觴或可醉，警讀安得慵。", "永謝世味醺，敢懷歸意濃。", "朝懽過狎洽，夜氣方沖融。", "意超謔浪表，伊誰躡斯蹤。", "獨愧和篇斐，不堪稱兩雄。"]'),
('912aeb92-264e-419d-8ab1-c136fcd4c3bb','賦吳守友石臺','胡寅','宋','宋诗','song-poetry','','[]','南圃繚粉牆，幽徑便蠟屐。',216,'全唐诗/poet.song.108000.json','["南圃繚粉牆，幽徑便蠟屐。", "蒙然遇高蔭，炎景不予赫。", "天成一高坫，爲印子雲宅。", "大藤如虯龍，陟降蜿尾脊。", "青冥搴茂葉，何異張翠帟。", "想見春風時，紫蕊濃可摘。", "富哉他山骨，輦致羅鐵碧。", "或如爨桐斷，或若林筍刺。", "或如五老拳，或若太華擘。", "或如虎方踞，或若羱欲躑。", "或崎難著足，或坦可敷席。", "或倚以憩憊，或坐以對弈。", "廣輪兩拓手，叢秀不迫窄。", "何須狻猊座，方丈出戲劇。", "况論芥子中，不與須彌隔。", "有之則似之，知君介如石。", "石中有良玉，終古不變易。", "茲遊謝蘭亭，何用嘆陳迹。"]'),
('c5bb88d9-b7b0-4c55-a783-91622caf8d70','示吳守','胡寅','宋','宋诗','song-poetry','','[]','汲湔明月泉，散襟清風亭。',216,'全唐诗/poet.song.108000.json','["汲湔明月泉，散襟清風亭。", "秋陽不能暑，宿酒爽以醒。", "佳哉此勝原，歷覽所未經。", "一溪曲折白，萬嶂低昂青。", "上有蟄龍湫，比渭不比涇。", "天邊建河漢，地底奔雷霆。", "物産不儲秀，伊誰當炳靈。", "早負李固笈，夜拾車公螢。", "古學探奧穾，高文掞天庭。", "善刀隨所遇，小試常發硎。", "胡爲嶺南州，尚屈摩霄翎。", "人生多離合，泛泛如流萍。", "忽焉復邂逅，豈辭倒公瓶。", "著身山水窟，已浣埃𡏖形。", "況乃家塾間，美誦盈客聽。", "頎頎兩孫子，玉立此寧馨。", "居然五經笥，問歲纔十齡。", "詩成使之哦，清越公其聆。"]'),
('8ec1b53d-6e91-4abc-bf7c-921a8aa980b5','題泉石軒','胡寅','宋','宋诗','song-poetry','','[]','過橋忽與平疇對，石路鱗鱗蹴蛇背。',96,'全唐诗/poet.song.108000.json','["過橋忽與平疇對，石路鱗鱗蹴蛇背。", "登堂面勢脩竹林，百疊青瑶襯其外。", "就中新著小軒奇，湩乳披崖草樹滋。", "蒼牙砑然如虎飲，一泓寒碧湛琉璃。", "雪花茗盌浮談席，欲去泠然生兩腋。", "留詩聊足記歲年，更寫軒題號泉石。"]'),
('d05ac46d-b990-4ac7-8185-9c3a6367f067','和劉仲固痛飲四疊','胡寅','宋','宋诗','song-poetry','','[]','舊詩未酬新句新，向來毒酲與死濱。',128,'全唐诗/poet.song.108000.json','["舊詩未酬新句新，向來毒酲與死濱。", "頹然一榻誰料理，子思之側知無人。", "華筵再開不辭醉，夜碧千鍾慰愁肺。", "盍簪如霧君不來，豈念清遊後難繼。", "朱唇少罷凌風歌，蓮舟小槳翻青羅。", "笛聲無哀亦無怨，喚取月色今宵多。", "狂時駘蕩醒時恥，情景循環亦何已。", "但愁霜過沾人衣，塒上嘐嘐坐當起。"]'),
('27470aad-da24-4299-89f3-2e63dbee5ab9','曉乘大霧訪仲固','胡寅','宋','宋诗','song-poetry','','[]','稚金不耐老火鑄，有烈秋陽尚驕倨。',320,'全唐诗/poet.song.108000.json','["稚金不耐老火鑄，有烈秋陽尚驕倨。", "汗流亭午憶淒風，氣應佳辰欣白露。", "朝來開窗迷眼界，霧色無邊莽回互。", "誰爲夜半有力者，竊負羣山著何處。", "却驅滄海白潮來，濤浪初平不成怒。", "人家慘淡暗漁浦，水墨微茫認烟樹。", "我行有似江湖雀，彼岸應怪浮杯渡。", "從教弱水三萬里，一棹桃源未迷路。", "忽然五霞漏激射，清飈作陣翻空鶩。", "渤澥盡輸無極底，祖龍枉被徐生誤。", "雲屏儼映蓬嶠矗，鳳翼鶱带瀛洲嫮。", "連蒼接翠層疊青，秀色著絢忘初素。", "前觀象罔非夢迷，後矚離婁豈驚寤。", "真化自然相隠顯，幻士謬爾生智故。", "有真無幻信誕分，此境易透亦難覷。", "要知萬理無不寔，聚散一致此焉悟。", "常記向時聞劇論，知自少年得真趣。", "風雲變態襟抱開，山水之樂仁智具。", "胡爲顰呻不料理，冰炭受坐瘧鬼怖。", "願君讀此一醒然，未負當年少陵句。"]'),
('7b40d717-23ac-47d3-97c2-ef1b776dcc47','題傅氏真意堂','胡寅','宋','宋诗','song-poetry','','[]','高柟落繁蔭，茂竹疏泠風。',216,'全唐诗/poet.song.108000.json','["高柟落繁蔭，茂竹疏泠風。", "小亭尋丈景，已冠一畝宮。", "況復哆北楹，方池渺溶溶。", "遊鯈亦何樂，動影相沖融。", "卉木羅以差，想見芳菲容。", "香枝寒月碎，雪架春雲濃。", "我來秋暮時，山葉般般紅。", "乃眷黄金花，尚閟東籬叢。", "維君抱材氣，志通身則窮。", "和璧獻未售，夜半光騰虹。", "樂歲突尚冷，初筵尊未空。", "恨我早病衰，不能卷千鍾。", "喜聞滌塵話，冰壺瑩心胸。", "又知此勝境，芹溪縈硯峯。", "昔有遺世士，烟霞眇飛蹤。", "先生儻邂逅，問訊爲我通。", "芝苗不足飽，多謝甪里翁。", "相期玉京路，手把青芙蓉。"]'),
('34f3602f-fc49-4dd1-b03a-439247d7c634','和彥沖','胡寅','宋','宋诗','song-poetry','','[]','七載飛電邁，百慮秋水澄。',204,'全唐诗/poet.song.108000.json','["七載飛電邁，百慮秋水澄。", "獨餘故鄉念，居然常兢兢。", "同是幔亭仙，乘風釣湘蒸。", "魚寄水千里，歷傳雲萬層。", "十論賜甚腆，一篇蒙未曾。", "登堂話衮衮，寓寢香凝凝。", "看君道氣充，可仰誰敢朋。", "寸陰謝尺璧，默然耀千燈。", "世路多招呼，掉首未渠譍。", "幽尋嘆川逝，彼寧記雲騰。", "但願我輩人，拳拳知服膺。", "聖門無閡轍，自畫理豈應。", "君子有所病，沒身名莫稱。", "虛生既何補，浪死誠堪懲。", "君仍詩律高，愧我酒量能。", "屬耳風雅頌，因忘斗與升。", "山林足奇觀，朱闌盍時憑。"]'),
('47f48045-1cb0-4dcb-80c4-a8bfbec4c653','和彥沖','胡寅','宋','宋诗','song-poetry','','[]','詩腑五字城，酒腸九曲灣。',144,'全唐诗/poet.song.108000.json','["詩腑五字城，酒腸九曲灣。", "興來摧高堅，觴至輸潺湲。", "眷此山澗曲，素緇邀畿寰。", "人境俱寄陶，陋巷同樂顔。", "新黍釀初熟，小槽泣微潜。", "僅堪代湯茗，敢望頹玉山。", "獨餘要眇音，超然難追攀。", "所頼見寬假，悲嗚三日閒。", "清風又吹句，玉佩崢瑶環。", "使我發深省，迷蕪自除刪。", "得意言語外，放懷天地間。", "人生貴知心，願言長往還。"]'),
('95f74d2e-94fc-413f-8a6e-9061890f20a9','清湖山大火','胡寅','宋','宋诗','song-poetry','','[]','青天露坐月斂昏，忽見山燒明溪村。',384,'全唐诗/poet.song.108000.json','["青天露坐月斂昏，忽見山燒明溪村。", "轉移胡床飽寓目，獵獵變態真難論。", "清湖之山峨帝閽，盤陀四隤如雲屯。", "千章大材翳山黑，忽作秋樹繁鮮縕。", "得非祝融張南軍，周騵漢幟雜邀巡。", "萆山奪壁秣且獵，陳皮較獲羣毛騂。", "又疑棲岩窮道人，鏖砂竈破寶魄淪。", "丹光飛飛弄明滅，怪氣閃閃騰輪囷。", "隨風廓爆聲何喧，遇澗緣絕勢復分。", "金虯赭虺怒鬰律，紫鳳朱鳥驚翔鶱。", "欲尋仙家訪桃源，武陵太守馳雙轓。", "紛敷絳雪土不濕，近遠蒸霞山正燃。", "離離點點羅星垣，燦燦爛爛披纈紋。", "巫陽研朱盡屈曲，盤印繚燼香氤氳。", "山清宛然大裘尊，藻粉之間繡光焞。", "侍官服章畫彤韎，佩玉環玦皆瓊璊。", "誰移太華玉井根，開此翠巘芙蓉園。", "徒勞禪宮詠火傘，豈媿花島歌紅雲。", "連岡槎牙宣空齦，缺壑侈哆呀殷唇。", "眉峰胡爲變賊赤，頂髻何事從僧髠。", "翻思元宵遊端門，巨鼇岌載蓬萊蹲。", "蜿蜒雙銜照天炬，十萬油蠟爭晨暾。", "只今留滯磎河盤，青熒一燈讀書殘。", "野人亦解相暖熱，坐使寒谷驚龍鸞。"]'),
('62363ca2-8df6-4952-b11e-292a922ffd24','遊將軍岩','胡寅','宋','宋诗','song-poetry','','[]','初識後亭山，一賞北岩秀。',192,'全唐诗/poet.song.108000.json','["初識後亭山，一賞北岩秀。", "更聞將軍隠，飛策過雲岫。", "何爲英烈姿，石壁寄門竇。", "得非馬力竭，依險聊自救。", "無乃棄長弓，一念希不漏。", "餘情尚慳滯，嗔客來徑簉。", "唏雲翳凡木，涕雨滑峻甃。", "以君智慧鎧，與我忠信胄。", "才刃及詩鋒，勝客雜前後。", "懸崖雖仡仡，有進寂寞鬭。", "山靈方恫悔，斂迹祈恕宥。", "坐令蒙蔽景，倏變清明晝。", "前峯霄漢近，矗矗駭猱狖。", "絕澗雲練明，宛宛出篆籀。", "奇觀固難值，況復有清酎。", "不須待重九，菊蕊已堪齅。"]'),
('ac0889bc-1e42-44f5-b514-70162e22a475','觀柳源瀑布','胡寅','宋','宋诗','song-poetry','','[]','遐歸獲勝踐，風日清廣宙。',144,'全唐诗/poet.song.108000.json','["遐歸獲勝踐，風日清廣宙。", "途巘意未闌，景絕願初副。", "回巒豁大壑，萬古貯天漏。", "無人識秋河，此地一源透。", "鎔銀誰戲劇，擣玉供噴漱。", "未知三峽橋，與此孰雄陋。", "却來據盤石，雲氣滿襟袖。", "指顧組練軍，洶湧出左右。", "八元坐收功，獨聽九韶奏。", "摧岩决澗手，笑我泫寒溜。", "出入更回頭，雲水莽迷覆。", "歸瓶注小瀑，雪乳尚真鬭。"]'),
('66c125ee-3aae-48e5-a688-0a8f799f1d8f','題棲雲閣','胡寅','宋','宋诗','song-poetry','','[]','青山畫出天台障，溪流宛是桃源漾。',128,'全唐诗/poet.song.108000.json','["青山畫出天台障，溪流宛是桃源漾。", "一菴深著翠微間，高閣更搴雲氣上。", "道人於此幾經春，七閏不作黄楊屯。", "孤標如松自磊砢，爽氣映竹長清真。", "爐中寒灰與心寂，世味只今餘好客。", "橫潭一笑得烹鮮，通道三杯酬蠟屐。", "願君勿羨飛升天，亦莫面壁沉幽禪。", "問雲何心不出岫，歸與吾黨相周旋。"]'),
('80c0b740-35e3-4677-8616-f6f675e872d2','題四畫 清湖驟雨','胡寅','宋','宋诗','song-poetry','','[]','銀竹森空映，湖光莽蒼中。',24,'全唐诗/poet.song.108000.json','["銀竹森空映，湖光莽蒼中。", "不因風捲去，那得見沖融。"]'),
('bf069cbd-6fd5-4385-bb63-2f34da905c87','題四畫 潭溪秋碧','胡寅','宋','宋诗','song-poetry','','[]','秋容何處佳，淡泊寄寒水。',24,'全唐诗/poet.song.108000.json','["秋容何處佳，淡泊寄寒水。", "無滓湛遥天，我心正如此。"]'),
('ab5f75b4-6633-4453-8e4e-cd31aadf7095','題四畫 石峰春靄','胡寅','宋','宋诗','song-poetry','','[]','騰龍紛野馬，非霧亦非烟。',24,'全唐诗/poet.song.108000.json','["騰龍紛野馬，非霧亦非烟。", "心共春山遠，詩憑淡墨傳。"]'),
('0be0bac1-b1e5-4bb2-a608-3ec484e93c31','題四畫 屏山夜雪','胡寅','宋','宋诗','song-poetry','','[]','熟醉蓮蕩風，未賞梅溪勝。',24,'全唐诗/poet.song.108000.json','["熟醉蓮蕩風，未賞梅溪勝。", "踏雪訪屏山，今年得乘興。"]'),
('82dda389-f8ef-4877-a953-60fa9cd35158','陪叔夏遊法輪','胡寅','宋','宋诗','song-poetry','','[]','不雨度十旬，山行尚清美。',168,'全唐诗/poet.song.108000.json','["不雨度十旬，山行尚清美。", "茲晨岣嶁南，昔者紫蓋尾。", "三益伏蒲公，眷我共遊徙。", "晉時雲龍寺，煇煇千柱啟。", "老禪贍幽思，靜室更經始。", "梁橑杉桂馥，窗戶水雲洗。", "況逢月幾望，天宇澹無滓。", "空庭竹柏影，藻荇漾流水。", "散衣捧皤腹，行食躡細履。", "不隨羽人夢，當處廣寒裏。", "何須霓裳曲，梵唄亦不起。", "紛紛共塵世，清絕乃有此。", "又嗟情事隔，不得久棲止。", "人生誰定閒，吾行未云已。"]'),
('a3b24220-c45d-42da-8aef-610749848acd','賦向宣卿有裕堂堂在伊山桓伊舊隠也','胡寅','宋','宋诗','song-poetry','','[]','仕進行所志，退居適吾情。',216,'全唐诗/poet.song.108000.json','["仕進行所志，退居適吾情。", "本無顛瞑患，那有得失驚。", "想彼貪者狼，跋疐不少寧。", "又哀觸藩羝，兩角掛紫荆。", "君子但居易，肯與世轍爭。", "彼以戚戚終，我以坦坦生。", "斯堂誰所築，向公勇且英。", "百鍊見剛質，千尋抵孤清。", "藝蘭畹畹滋，栽竹箇箇成。", "無復笛三弄，只聞絃誦聲。", "客來引壺觴，客去山崢嶸。", "咄哉狙詐兒，夸眩機巧呈。", "揶揄復揶揄，鏡空難遁形。", "天命有通塞，況公負時名。", "唐濟嗣先業，選掄待揚庭。", "一朝看遊刃，光芒發新硎。", "十步即千里，紫氣無留行。", "青蠅失榛棘，周道如砥平。"]'),
('d1a8915c-3958-4ad2-9182-197c34aec621','以墨一品餉叔夏','胡寅','宋','宋诗','song-poetry','','[]','人墨兩相磨，此語昔賢嘆。',228,'全唐诗/poet.song.108000.json','["人墨兩相磨，此語昔賢嘆。", "平生幾兩屐，何用積不散。", "未忘文字耳，四寶且同案。", "陶泓有潤澤，毛穎稱詞翰。", "論交楮先生，相厚不相貫。", "直須造玄默，乃可發三粲。", "南山太古松，盈壑凌霄漢。", "煤珠貴輕遠，膠結要堅捍。", "脩圭及圓餠，脫手千金煥。", "寄君亦何意，往作文房伴。", "君子萬卷讀，胸次春冰泮。", "翻水即千篇，燁若雲錦爛。", "獵華將食實，以道自澡盥。", "當年伏蒲疏，慨欲排世難。", "民瘼今益深，山谷寧可玩。", "請君携此寶，慎勿比醫炭。", "恭惟上隆寬，繕寫臣謹按。", "當從黝然處，凜有光芒觀。", "繼君諸皇祖，勳德侑清祼。"]'),
('f0c4db05-fff7-4e7a-9cf8-4a5701ae57dc','和諸友春雪','胡寅','宋','宋诗','song-poetry','','[]','蟄蟲恰好雷聲發，更聽陽春歌白雪。',160,'全唐诗/poet.song.108000.json','["蟄蟲恰好雷聲發，更聽陽春歌白雪。", "仙葩亂墜絮繽紛，奇韻相高山嶮絕。", "筆尖不爲風力退，酒面肯作冰澌冽。", "千林萬木絢華滋，玉李銀桃幾時結。", "不將瑶草充大藥，獨愛浮筠凜高節。", "天公憫世緇塵土，故使萬穢蒙一潔。", "涵濡之力啟豐登，后稷資爲天下烈。", "手寒固已懶摶玩，齒病那敢夸嚼齧。", "清歡悵然懷舊賞，白戰漫爾踵前哲。", "却欣淑氣掃餘寒，杲日當天不勞揭。"]'),
('d427d1b1-0d65-4b83-9dce-70af0b7d8a3f','上元寄向令豐之','胡寅','宋','宋诗','song-poetry','','[]','雪罷梅殘烟柳浮，上元燈火春風柔。',64,'全唐诗/poet.song.108000.json','["雪罷梅殘烟柳浮，上元燈火春風柔。", "紅蓮萬枝開岳縣，比似河陽花定羞。", "官松有明不敢斫，烏桕作燭供清愁。", "君能分光到蝸舍，爲遣華星三百毬。"]'),
('fb98b0e0-4d67-48d1-beb9-7baff6dbe8f0','贈邢子友','胡寅','宋','宋诗','song-poetry','','[]','憶昔筮仕初，典教洛學省。',264,'全唐诗/poet.song.108000.json','["憶昔筮仕初，典教洛學省。", "故家多遺俗，往叩冠屢整。", "得交邢公子，伯仲皆豪穎。", "湖園萬竿竹，伊水注深靜。", "藤林與花島，轉步即殊景。", "梅臺更稱奇，雲玉粲寒耿。", "官閒日從君，何宴不酩酊。", "每聞魁偉論，雖醉灑然醒。", "尋幽訪古徑，並轡緩無騁。", "向來春風鬢，忽忽雪飄頸。", "三川在何處，會合乃潭永。", "久要見襟抱，意態謝炎冷。", "顧予衰懦質，酬答忘形影。", "泛舟三百里，念我特相省。", "酒酣攄劇論，壯氣尚雄猛。", "樂將高歌發，忠以微語警。", "豈無一可恨，不肯破空境。", "石壇夜焚香，岩寺朝供茗。", "相逢多譏評，墨守卒未領。", "湘流平似席，告別理歸艇。", "願言頻惠音，庶以代咳謦。", "它年當扣門，此話欲重請。"]'),
('c6a6d5c0-d97c-4202-b3a9-419d0625d903','示法輪宗覺','胡寅','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','身如槁木藏春色，眼似澄江映秋碧。',96,'全唐诗/poet.song.108000.json','["身如槁木藏春色，眼似澄江映秋碧。", "洞庭湖上月同圓，石廩峯前人不識。", "從來說法閙雲林，直措人心定難得。", "豈關佛運有窮通，自是擔肩無膂力。", "看君古井直浪盡，閲世空花等塵寂。", "雖然獨飯一盂香，爭似分甘千百億。"]'),
('0b229231-d9fb-431b-b1ef-20ce8c1acc25','仁仲小圃','胡寅','宋','宋诗','song-poetry','','[]','白雲不爲輕風起，閒影融融映秋水。',144,'全唐诗/poet.song.108000.json','["白雲不爲輕風起，閒影融融映秋水。", "靜中觀物萬象呈，借問此心何所始。", "蚊飛蠓過那足問，要識人生行樂耳。", "君開小圃富幽致，自外而觀如畫裏。", "陶公高興只柴桑，晏子之居徒近市。", "春歸森森青竹上，秋盡離離從草靡。", "歲華流轉只常在，月魄盈虧未嘗死。", "經綸胸次自開泰，語笑尊前即傾否。", "君知消息何處來，於穆我師純不已。"]'),
('7874dfdc-3bf9-4101-884f-7106a9a9f29a','人日驚蟄前數日大雪寄孫奇父韓叔夏','胡寅','宋','宋诗','song-poetry','','[]','臘雪不溉旱，天公念嘉生。',288,'全唐诗/poet.song.108000.json','["臘雪不溉旱，天公念嘉生。", "稚春乃祁寒，號令如冬行。", "栗烈鼓噫氣，碎訇動霆聲。", "初疑雨翻盆，旋覺霰灑甍。", "暫止俄并集，中宵遽開明。", "衾裯起稜角，屏幌同戶楹。", "淅淅紙窗戰，鐺鐺銅漏驚。", "雞寒罷曉唱，鴉凍猶晨鳴。", "驚戒臧獲起，吹噓燎爐頳。", "開關醉魂醒，倚杖詩思清。", "便欲披鶴氅，豈思飲銀鐺。", "空濛勢轉盛，飛舞祥爭呈。", "月池方漫汗，潮山正崢嶸。", "詎應柳皆絮，却訝梅始英。", "荆璞羞自獻，藍田遣誰耕。", "塵埃爭受洗，糞壤叨蒙榮。", "幸已陴巘崿，若爲投澗坑。", "分功雨露澤，絢綵冰霜精。", "良足潤麥麰，未能浹粱秔。", "經旬苦料峭，三日觀熒晶。", "恍憶遊汴洛，都忘在湘衡。", "瑶林鄙王衍，冠玉懷陳平。", "亦念袁邵公，長安門自撐。", "更奇李侍中，淮蔡功先成。"]'),
('43aa7c0c-54c8-4921-a043-147d35f8edd8','送智京長老智京普融上足也','胡寅','宋','宋诗','song-poetry','','[]','人生如浮雲，片片隨所起。',192,'全唐诗/poet.song.108000.json','["人生如浮雲，片片隨所起。", "值遇初偶然，解散亦俄爾。", "識君湘水頭，凝袂衡嶽裏。", "十年去何住，新化五百里。", "乘興出山來，相對淡無滓。", "因思相見初，賊幟森未弭。", "世事幾秋葉，壯懷今止水。", "堂堂普融老，鶴瘦松孤峙。", "廣舌浩江輸，迅機無箭擬。", "八請六道場，到處萬人喜。", "一燈千百焰，高第君得髓。", "法席既紹隆，詩鳴亦能似。", "衡門鮮晤語，杖錫盍留止。", "翩然復告辭，母病急甘旨。", "故知秉彝性，誰或外此理。", "爲話本來心，聞聞即彈指。"]'),
('b21c523f-fd18-491e-b153-0702263787e4','示端推單普','胡寅','宋','宋诗','song-poetry','','[]','我是瘴嶺跕，誰爲青田真。',72,'全唐诗/poet.song.108000.json','["我是瘴嶺跕，誰爲青田真。", "若使新羽燕，老鷹安得親。", "君行何方來，袖有三吳雲。", "訪予墮珠玉，蟄戶開青春。", "無以答嘉贈，深衷宜重陳。", "仲尼且待賈，至寶宜貴珍。"]'),
('bead21fc-e4a8-42b2-907f-d97cdbbbbbc6','謝楊珣梅栽','胡寅','宋','宋诗','song-poetry','','[]','南土梅不貴，往往薪槱束。',144,'全唐诗/poet.song.108000.json','["南土梅不貴，往往薪槱束。", "倖然傍寒廳，久亦未見錄。", "牆隈非所恨，自可凌冬發。", "奈何瑶臺伴，辱近紫姑闥。", "佳人雖薄命，時運忽來復。", "一朝蒙閔嘆，移近東家屋。", "孤根便靜深，池上映天碧。", "我爲渠主人，梅是先生客。", "且須創幽榭，賸與種脩竹。", "炎荒無雪片，且對冰花馥。", "西施佩生麝，姑射步微月。", "何當見舊官，應使中腸熱。"]'),
('5af7bc94-74eb-4623-b36d-0ff056cb6917','贈陳生','胡寅','宋','宋诗','song-poetry','','[]','茅容殺一雞，留半置庋板。',240,'全唐诗/poet.song.108000.json','["茅容殺一雞，留半置庋板。", "奉親須肉味，對客但蔬飯。", "仲由身負米，豈顧人嗤莞。", "參乎三釜樂，不羨千金産。", "古今履誠信，薄俗行苟簡。", "競敲聲利關，汲汲組綬綰。", "指茲爲顯榮，于義遑復揀。", "賢如郭林宗，尚負牲牢赧。", "孝衰百行失，豈特厚賓饌。", "爲人在我爾，誰以力自限。", "今君修古道，田土亦未昄。", "带經已能克，扶耒意無撊。", "似聞收一稔，銍艾工日僝。", "茂筠爲載具，泛壑出𡾰嵼。", "歸家魚菽美，愉婉已在眼。", "君非沮溺流，文字富編撰。", "中扃務恬息，外慕正除剗。", "晚交慰荒蕪，切磋兼瑟僩。", "何時還過我，望望車有棧。", "梅花開正繁，飛雪待浮盞。"]'),
('6666da55-d3c0-4c32-8af6-ccedf9f18195','簡黎生生時旅寓郡庠','胡寅','宋','宋诗','song-poetry','','[]','雨多杖藜阻，室邇言少賒。',84,'全唐诗/poet.song.108000.json','["雨多杖藜阻，室邇言少賒。", "示病今如何，起居諒能佳。", "小市禁宰割，每無魚與蛙。", "何以侑旅食，頃當羹莧茄。", "在昔多貧師，況自接東家。", "藥物有所缺，諭我心莫遐。", "明日能相遇，煮茗看荷花。"]'),
('c8529e31-aaa5-4a3f-b9d2-9080e824cc7e','和蔡生','胡寅','宋','宋诗','song-poetry','','[]','吾生慚松獨，天賦比樗散。',144,'全唐诗/poet.song.108000.json','["吾生慚松獨，天賦比樗散。", "學道纔窺藩，聖門未容款。", "老來憂患集，鵻草經濕暵。", "衣带垂有餘，樗腹無可坦。", "跫然喜君至，肯就我乎館。", "一醉老瓦盆，寧用玻璃碗。", "春風正駘蕩，柳暗月欲滿。", "蚩蚩萬物類，混化胎與卵。", "吾儕幸襟靈，詩書足相伴。", "浩然天宇內，未暇論脩短。", "揚雄正希顔，曾子豈顧管。", "希聲非折楊，下士每大莞。"]'),
('c18b92ad-f7e3-42a5-8fed-582831de0a6c','送張倩歸衡嶽','胡寅','宋','宋诗','song-poetry','','[]','鄙人麗丹書，分合墮荒杳。',240,'全唐诗/poet.song.108000.json','["鄙人麗丹書，分合墮荒杳。", "玉郎胡爲來，高誼雲共眇。", "一年常惜日，四序乃過鳥。", "安能久相留，話別情太悄。", "離筵亦何有，瘴雨對蠻醥。", "羞以蛙與蛇，茹以芹及蓼。", "相將丹荔熟，悵望剝絳皎。", "愛君溫克姿，不被歡伯繞。", "緬懷君祖烈，德粹學甚窈。", "乃翁才情富，未試嗟折夭。", "早交論金蘭，晚契託蘿蔦。", "顧慚兼金贈，聊用苦語曉。", "發身在求仁，此理悟者少。", "人雖處塵世，心盍度塵表。", "凌霄而俛睨，萬物孰不小。", "規模要宏廓，聞見忌寡謏。", "南方君子居，吾敢廢强矯。", "勿興兒女戀，後會龜已兆。", "千山空稜層，萬水自漭渺。", "行行得夷路，長轡策騕褭。"]'),
('fba2139a-b0ea-473e-b8f8-c4b749cd1848','邀朱推單令周尉賞西鄰野人屋前梅花次單令韻','胡寅','宋','宋诗','song-poetry','','[]','西崦一株梅，在野何清麗。',132,'全唐诗/poet.song.108000.json','["西崦一株梅，在野何清麗。", "遥知不是雪，香散青林際。", "肆筵賓沓來，秉炬僕相遞。", "幸蒙五字詩，妙敵一言蔽。", "便恐清夜闌，行酒莫濡滯。", "莓苔何必掃，月地作瑶砌。", "細蕊護檀心，已带輕酸味。", "爲語青裙嫗，斤斧煩叱衛。", "會有移根人，趁得春風至。", "顆顆調君羹，年年映塵世。", "來遊者誰子，此興恐難繼。"]'),
('62c59dbb-51f7-4d8d-bb3e-9d7036e256aa','周尉不來用單令韻見寄和之','胡寅','宋','宋诗','song-poetry','','[]','穠李太穠華，夭桃苦夭麗。',132,'全唐诗/poet.song.108000.json','["穠李太穠華，夭桃苦夭麗。", "不如姑射子，仙質淡難際。", "破寒傳芳信，春意豈迢遞。", "亭亭映碧霄，茨屋安得蔽。", "一壺掃花陰，聊散客愁滯。", "千珠聯萬玉，襞積誰所砌。", "飛英時落盃，草木吾臭味。", "頗嫌三弄笛，聲雜鄭和衛。", "二公何惠然，悵望周郎至。", "哦詩要何似，孤絕表一世。", "風吹佳句來，端可使人繼。"]'),
('d04106e2-8427-4ae7-91f5-95cf9666937b','示周尉','胡寅','宋','宋诗','song-poetry','','[]','官酒不可求，村釀不足酤。',96,'全唐诗/poet.song.108000.json','["官酒不可求，村釀不足酤。", "似聞糟床注，滴瀝真珠露。", "載醪欲相過，好語亦已屢。", "梅花雖零落，殘雪尚可顧。", "已捉籠中雞，仍擷園中茹。", "一壺便堪醉，不必更携具。", "數朝風雨濕，兩日已通路。", "行樂貴及時，蟋蟀歲云暮。"]'),
('aa488bc1-3748-4a03-8b35-683f9eccedc9','題單令雙清閣','胡寅','宋','宋诗','song-poetry','','[]','中扃有天遊，一室四海見。',240,'全唐诗/poet.song.108000.json','["中扃有天遊，一室四海見。", "倘無空虛地，六鑿互爭戰。", "琴堂故蕭爽，向也正牆面。", "棘茨莽蒙蔽，鼷鼠紛旋轉。", "剗除資豁達，頓覺雲水眩。", "瞰臨幽閣出，率畧重營繕。", "從容五六客，尚得摇歌扇。", "西山隔雉樓，佛髻三兩現。", "渺然宜北望，深碧湛芳蒨。", "羣峰湧翠浪，遠邇相明絢。", "珍禽知幾種，演漾花雪片。", "有時惠風來，輕皺蹙霜練。", "最憐明月夜，酒渴光可咽。", "主人藹優政，不媿宓子賤。", "撓之莫能濁，聊用青白燕。", "心澄迹自潔，眼靜照還徧。", "他年騰踏去，回觀等郵傳。", "只今簷前淥，但足注詩硯。", "予方混泥塗，每媿陪高宴。", "更書梁棟間，何以賁花縣。"]'),
('6fdf323d-a151-4cd8-b406-74d9ae964f51','贈朱推','胡寅','宋','宋诗','song-poetry','','[]','浄綠環城亦何有，跳錦潜銀不容取。',256,'全唐诗/poet.song.108000.json','["浄綠環城亦何有，跳錦潜銀不容取。", "尚餘翠蓋擁紅粧，兩兩三三早秋後。", "秋官公廨臨池傍，結筠爲筏開軒窗。", "落日輕風泛船好，歡呼取笑徒相望。", "忽聞報予酒初熟，亟往從之傾白玉。", "疎蟬有思曳長繰，寒露無聲洗殘燠。", "君才豈合州縣勞，前雲後暉家世高。", "一經不但有遺訓，千古記注談滔滔。", "新州州土烝嵐瘴，從來只是居流放。", "於今多住四方人，況復爲官氣條暢。", "山肴野蔌應時須，真率相期久已渝。", "君今滿秩稍淹此，牛刀又欲將雞屠。", "嗟予衰謝人所去，晚交幸作年家遇。", "浮生聚首安得常，一笑傾懷亦難屢。", "莫辭瓶罄燭再然，異日重逢歌此篇。", "歲時豈忍無記述，明朝仲朔青龍年。"]'),
('a00a4396-12e5-4049-a4e6-bd0ed0cba6f6','題蔡生竹裏茅簷似野航','胡寅','宋','宋诗','song-poetry','','[]','誅茅自結林中屋，林密先刪百竿竹。',160,'全唐诗/poet.song.108000.json','["誅茅自結林中屋，林密先刪百竿竹。", "南山獻狀漏南亭，北路行歌喧北曲。", "誰知江海蔡中郎，歲晚栖栖泊嶺陽。", "未有浄名方丈室，小齋聊寄錦江航。", "勸君須學逃名隠，題揭徒然絢黛粉。", "請看鄭圃四十年，妙在不知而不慍。", "我今亦住茅竹間，身世渾如繫纜船。", "空洞之中何所有，聖門勳業浩無邊。", "此君且伴幽人趣，時來豈不茅連茹。", "瓶罍果醉兩三人，會約伊渠杖藜去。"]'),
('2a3b2499-d13a-4c85-9559-b5fd28f798fb','求木磑于周尉','胡寅','宋','宋诗','song-poetry','','[]','舂簸精粗期適口，老夫脫粟艱難久。',64,'全唐诗/poet.song.108000.json','["舂簸精粗期適口，老夫脫粟艱難久。", "它山木臼纔百金，四市營求輒無有。", "願惟仁者試咄嗟，要使赤脚治勝斗。", "豈惟軟飯慰無牙，亦冀糠粞及雞狗。"]'),
('d5efa56e-dc68-4f88-a72a-46507f785314','同蔣德施諸人賞簡園梨花','胡寅','宋','宋诗','song-poetry','','[]','君不見韓退之，招喚劉師命。',91,'全唐诗/poet.song.108000.json','["君不見韓退之，招喚劉師命。", "醉賞長安西郭梨，青天白日交相映。", "豈料炎荒中，好事如簡翁。", "彫冰剪玉春不融，二十五樹高籠松。", "風流八仙携草具，輕陰閣雨相隨去。", "朝同去，暮同歸，回頭翠微明日玉花飛。"]'),
('e0fa7f62-fe12-4578-88c4-38aba3be036a','畫馬','胡寅','宋','宋诗','song-poetry','','[]','曹霸丹青徹馬骨，應師伯樂遺毛物。',32,'全唐诗/poet.song.108000.json','["曹霸丹青徹馬骨，應師伯樂遺毛物。", "請看此圖筆外意，萬里人寰定超越。"]'),
('76cc162d-29ea-49f7-9187-da3ed4015c45','畫牛','胡寅','宋','宋诗','song-poetry','','[]','江上春犂雨，當年力共强。',48,'全唐诗/poet.song.108000.json','["江上春犂雨，當年力共强。", "只今對圖畫，臧穀兩亡羊。", "牧子鞭繩急，防渠犯苗稼。", "人人白水牯，豈必溈山下。"]'),
('877dbb5f-7622-4c4d-81d1-56e1fc034a3e','題勝業悅亭','胡寅','宋','宋诗','song-poetry','','["\u8861\u5c71"]','欲結衡山茅，未買脩竹徑。',96,'全唐诗/poet.song.108000.json','["欲結衡山茅，未買脩竹徑。", "杖藜借危亭，面勢五峯正。", "何人縱惡木，牆外巧翳映。", "揮斤快望眼，岳色涵空鏡。", "連岫忽生雲，又厄登臨興。", "吹開指顧間，獨立西風勁。", "天機進人事，衆定兩相勝。", "不競獨此心，萬象同一瑩。"]'),
('9b3434de-c7b6-4134-bc6d-1f08ec287426','古今豪逸自放之士鮮不嗜酒以其類也雖以此致失者不少而清坐不飲醒眼看醉人亦未必盡得蓋可考矣予好飲而嘗患不給二頃種秫之念往來於懷世網嬰之未有其會因作五言酒詩一百韻以寄吾意雖寄古人陳迹并及酒德之大概以爲開闢醉鄉之羽檄參差反復不能論次也同年兄唐仲章聞而悅之因錄以寄庶幾茲鄉他日不乏寶鄰爾','胡寅','宋','宋诗','song-poetry','','[]','美祿無過酒，星泉奠兩儀。',288,'全唐诗/poet.song.108000.json','["美祿無過酒，星泉奠兩儀。", "端由皆作聖，意趣少人知。", "肇命惟元祀，迎春祝壽祺。", "功深資藥石，力厚起疲羸。", "若羨千鍾美，休嫌九醖遲。", "忘情惟大禹，無量乃宣尼。", "抔飲觴初濫，留連禍始基。", "先王防以禮，後世利其資。", "默識人情異，參稽俗習移。", "放懷無事矣，問口縱言之。", "惑溺終長夜，奢殘竟作池。", "包茅齊服楚，奏鼓胤征羲。", "大澤斬蛇後，當爐折券時。", "彭城正高會，睢水已填尸。", "謫去憂占鵩，歸來喜受釐。", "缾盆感田父，餔餟念湘纍。", "壑谷中宵問，糟丘一簣虧。", "怒排樊噲盾，吐卧允之頤。", "擊幘籠錢鳳，爭權殺魏其。", "脫靴慚力士，飛燕忤楊妃。", "司隸要殊切，虞人獵已馳。", "魏文敦信義，王猛用鈐鎚。", "有客言雖吃，何人字識奇。", "裸身荒已甚，滌器事還卑。"]'),
('9b850f74-0c24-4087-b3e8-cbf484b79b91','送黎才翁往荆門','胡寅','宋','宋诗','song-poetry','','[]','聖道原來不易窮，君今何處覓同風。',64,'全唐诗/poet.song.108000.json','["聖道原來不易窮，君今何處覓同風。", "唐虞世遠精神在，鄒魯人歸事業崇。", "德性未尊須强學，道心纔勝即收功。", "他時杯酒論暌闊，應有微言激懦衷。"]'),
('76bfb10f-5dd4-41da-8f74-c91e30e91dd3','文定題范氏壁次韻','胡寅','宋','宋诗','song-poetry','','[]','四海兵戈裏，一家風雨中。',48,'全唐诗/poet.song.108000.json','["四海兵戈裏，一家風雨中。", "逢人問消息，策杖去西東。", "歷數前朝亂，何曾掃地空。", "山居自有樂，時對主人翁。"]'),
('571552fb-d6ec-4fa4-bb86-a7c007f9b726','初至青湘聞安仁帥司爲曹成所襲四首  其一','胡寅','宋','宋诗','song-poetry','','[]','風急灘聲亂，雲紅雪意酣。',48,'全唐诗/poet.song.108000.json','["風急灘聲亂，雲紅雪意酣。", "空庭初霰集，寒硯忽冰涵。", "天造推移密，人情冷煖諳。", "江頭聊問信，春到一枝南。"]'),
('39b2e17b-e915-4b8c-940f-ea22c188482c','初至青湘聞安仁帥司爲曹成所襲四首  其二','胡寅','宋','宋诗','song-poetry','','[]','稅鞅年華暮，圍爐夜飲酣。',48,'全唐诗/poet.song.108000.json','["稅鞅年華暮，圍爐夜飲酣。", "雪梅清共映，沙水凍相涵。", "遠意人誰會，殊方俗未諳。", "前冬發湖北，今日滯湘南。"]'),
('8cba67ff-8a8d-4716-b2ab-2ec36b788021','初至青湘聞安仁帥司爲曹成所襲四首  其三','胡寅','宋','宋诗','song-poetry','','[]','有道持危國，無人識素書。',48,'全唐诗/poet.song.108000.json','["有道持危國，無人識素書。", "屢驚時易失，更覺意難如。", "莽莽旌旗暗，紛紛組綬紆。", "白雲一天地，今日又遷居。"]'),
('a84088ec-22de-46db-95d3-9af460492b57','初至青湘聞安仁帥司爲曹成所襲四首  其四','胡寅','宋','宋诗','song-poetry','','[]','結束趨安地，征營報急書。',48,'全唐诗/poet.song.108000.json','["結束趨安地，征營報急書。", "諸軍聞好在，元帥竟何如。", "歲晏風雲慘，天低嶺海紆。", "悲歌撫長劍，吾道敢懷居。"]'),
('9cba8e96-ef3b-4fad-8e88-78a59ed6cca5','題嶽麓西軒三絕  其一','胡寅','宋','宋诗','song-poetry','','[]','偶向紅塵得此生，歲寒松竹尚多情。',32,'全唐诗/poet.song.108000.json','["偶向紅塵得此生，歲寒松竹尚多情。", "道人亦有生前契，幽處開軒巧見迎。"]'),
('1a215ec8-9166-470d-8324-2ac99a0d0e09','題嶽麓西軒三絕  其二','胡寅','宋','宋诗','song-poetry','','[]','月戶風窗悄不扃，靜中真樂故難名。',32,'全唐诗/poet.song.108000.json','["月戶風窗悄不扃，靜中真樂故難名。", "山泉未識幽人意，自作穿林寫壑聲。"]'),
('11c0ee6d-fa6c-47c9-84c2-b50c04b70a9e','題嶽麓西軒三絕  其三','胡寅','宋','宋诗','song-poetry','','[]','山雨冥濛久未晴，袖中長笛爲君橫。',32,'全唐诗/poet.song.108000.json','["山雨冥濛久未晴，袖中長笛爲君橫。", "一聲吹破浮雲色，歸去呼船載月明。"]'),
('b16a2fa9-d8b0-43c5-b1ee-50a366175ddc','題指南軒二絕  其一','胡寅','宋','宋诗','song-poetry','','[]','老屋蕭疎四五椽，瓦爐香冷斷諸緣。',32,'全唐诗/poet.song.108000.json','["老屋蕭疎四五椽，瓦爐香冷斷諸緣。", "客來若問名軒意，莫似維摩但默然。"]'),
('944b0414-3316-45a6-b9ec-1721222790c8','題指南軒二絕  其二','胡寅','宋','宋诗','song-poetry','','[]','軒轅逸駕已旋歸，赤水玄珠却背馳。',32,'全唐诗/poet.song.108000.json','["軒轅逸駕已旋歸，赤水玄珠却背馳。", "南去北來何處是，坐令楊子泣多岐。"]'),
('b49af3f7-69fc-4c1a-bfa9-960affcad678','和鄧友直','胡寅','宋','宋诗','song-poetry','','[]','坐看嘉樹溢枯流，快作南江汗漫遊。',64,'全唐诗/poet.song.108000.json','["坐看嘉樹溢枯流，快作南江汗漫遊。", "曉岸林巒光寫鏡，夜窗風露冷涵秋。", "謏聞豈解論三豕，澀思真如曳九牛。", "但喜維舟時接席，一篇珠玉勝封侯。"]'),
('371fc50e-509c-48cd-aa41-b10ba8c2494d','示黄岡長老二絕  其一','胡寅','宋','宋诗','song-poetry','','[]','歸興逢山便解頤，上人多思乞留詩。',32,'全唐诗/poet.song.108000.json','["歸興逢山便解頤，上人多思乞留詩。", "千岩萬壑經行處，他日煩師覓舊題。"]'),
('4f941ed5-06cd-41d7-afd9-29b607f3ca45','示黄岡長老二絕  其二','胡寅','宋','宋诗','song-poetry','','[]','落日溪橋佇立時，溪雲歸盡月生遲。',32,'全唐诗/poet.song.108000.json','["落日溪橋佇立時，溪雲歸盡月生遲。", "溪聲漏洩真消息，借問溪翁却不知。"]'),
('80f450de-0177-463e-963a-ec09ceaac54d','題上饒半月岩四絕  其一','胡寅','宋','宋诗','song-poetry','','[]','何年落月掛蒼山，長似瑶梳插翠鬟。',32,'全唐诗/poet.song.108000.json','["何年落月掛蒼山，長似瑶梳插翠鬟。", "擬琢半輪營魄處，莫教如玦只如環。"]'),
('7caaf79b-dc4d-4792-933f-0c5dc0f62bb0','題上饒半月岩四絕  其二','胡寅','宋','宋诗','song-poetry','','[]','瓊樓玉宇匝天開，織女天孫靜往來。',32,'全唐诗/poet.song.108000.json','["瓊樓玉宇匝天開，織女天孫靜往來。", "月姊故應羞老退，譴除私館墮岩隈。"]'),
('2467e056-8229-417c-9d76-3acf7595116a','題上饒半月岩四絕  其三','胡寅','宋','宋诗','song-poetry','','[]','每見雲端上下弦，遥憐破鏡兩娟娟。',32,'全唐诗/poet.song.108000.json','["每見雲端上下弦，遥憐破鏡兩娟娟。", "願移此景蟾宮去，日月當令一再圓。"]'),
('c4e02170-2cbb-4664-9cbc-8ab9744ae8aa','題上饒半月岩四絕  其四','胡寅','宋','宋诗','song-poetry','','[]','非關狡兔月中藏，肯與癡蟆飽寸腸。',32,'全唐诗/poet.song.108000.json','["非關狡兔月中藏，肯與癡蟆飽寸腸。", "只恐世人嫌冷看，故依雲岫掩寒光。"]'),
('ad7ab4d0-a6ca-445f-9d06-6e69b2b362ea','題郭伯成畫竹月岩寺','胡寅','宋','宋诗','song-poetry','','[]','夫君自是雪霜姿，落筆風生更不疑。',32,'全唐诗/poet.song.108000.json','["夫君自是雪霜姿，落筆風生更不疑。", "留向岩前弄明月，桂枝相伴影參差。"]'),
('b973a94d-5be5-484a-b44f-40e8ea4f4466','題郭伯成畫竹道傍人家作雨勢','胡寅','宋','宋诗','song-poetry','','[]','可但文翁會寫真，典型今見一枝新。',32,'全唐诗/poet.song.108000.json','["可但文翁會寫真，典型今見一枝新。", "含風带雨蕭然意，共看林宗墊角巾。"]'),
('9bbc249a-eb56-46b8-a3a3-126202673da5','過疏山題一覽亭梁谿公所書也二首  其一','胡寅','宋','宋诗','song-poetry','','[]','手遮西日到疎山，忽得昏鴉斂翅間。',64,'全唐诗/poet.song.108000.json','["手遮西日到疎山，忽得昏鴉斂翅間。", "未暇拈香參佛祖，且須襆被扣禪關。", "月林散影參差靜，風磬傳音窈渺閒。", "擬買一廛通水竹，杖藜他日寄疎頑。"]'),
('3dfd8823-0ed4-4d5c-b25d-5a9a40803605','過疏山題一覽亭梁谿公所書也二首  其二','胡寅','宋','宋诗','song-poetry','','[]','林梢斜月墮金盆，接影蒼茫白霧翻。',64,'全唐诗/poet.song.108000.json','["林梢斜月墮金盆，接影蒼茫白霧翻。", "欲倚小欄收遁景，試憑長嘯卷遐昏。", "寒山濯濯空堆皺，野水瀰瀰不待源。", "莫道此亭觀覽富，未如賓日上天門。"]'),
('abe158c7-8653-489e-a112-d94990e75377','同余汝霖遊西湖觀天竺觀音永懷林和靖三絕  其一','胡寅','宋','宋诗','song-poetry','','["\u897f\u6e56"]','莫話蔣陵陳迹，青松翠碧躋攀。',28,'全唐诗/poet.song.108000.json','["莫話蔣陵陳迹，青松翠碧躋攀。", "此別再遊何日，夢魂長遶湖山。"]'),
('be431a14-e557-4648-bf26-47faafe27ef2','同余汝霖遊西湖觀天竺觀音永懷林和靖三絕  其二','胡寅','宋','宋诗','song-poetry','','["\u897f\u6e56"]','岩前晴日蔭樹，林下微風采蘭。',28,'全唐诗/poet.song.108000.json','["岩前晴日蔭樹，林下微風采蘭。", "臨水更無塵想，望雲時有遐觀。"]'),
('2d95fcdd-b87b-45b3-b5a5-cfcb18690bc7','同余汝霖遊西湖觀天竺觀音永懷林和靖三絕  其三','胡寅','宋','宋诗','song-poetry','','["\u897f\u6e56"]','劫火不燒大士，寒泉誰薦先生。',28,'全唐诗/poet.song.108000.json','["劫火不燒大士，寒泉誰薦先生。", "跋馬與君弔古，西風落日凄清。"]'),
('d1f633bc-f646-4874-953f-4e5a73e74e9b','初歸范伯達弟相會夜歸有成','胡寅','宋','宋诗','song-poetry','','[]','亂後風塵稍破昏，歸來骨肉喜全存。',64,'全唐诗/poet.song.108000.json','["亂後風塵稍破昏，歸來骨肉喜全存。", "飲君竹葉醉不惜，映我梅花香正繁。", "問學據今宜了了，唱酬從此定源源。", "夜寒踏碎灘頭浪，爲篤平生友弟恩。"]'),
('662dd9bc-f70c-41e6-8982-5a5452397988','癸丑元日文定時留豐城今歸青湘唁家','胡寅','宋','宋诗','song-poetry','','[]','去年已向爆聲殘，曉氣絪縕雨不寒。',64,'全唐诗/poet.song.108000.json','["去年已向爆聲殘，曉氣絪縕雨不寒。", "玉佩想聞趨桂殿，綵衣遥祝獻椒盤。", "千齡帝運方更始，一統王春正履端。", "不與時光共流轉，此心那更覓人安。"]'),
('a9cd8888-a363-4514-91cc-fb5767505076','和仁仲春日十絕  其一','胡寅','宋','宋诗','song-poetry','','[]','雪後雲收萬里天，春從何處著山川。',32,'全唐诗/poet.song.108000.json','["雪後雲收萬里天，春從何處著山川。", "紅邊綠外無窮思，莫道今年似去年。"]'),
('bf79d3ff-8bfb-4561-86b1-f2e6454e9d21','和仁仲春日十絕  其二','胡寅','宋','宋诗','song-poetry','','[]','氣浹高深物物蘇，問言還有欠春無。',32,'全唐诗/poet.song.108000.json','["氣浹高深物物蘇，問言還有欠春無。", "桃紅李白猶閒事，麟鳳應來瑞此都。"]'),
('2f2d91bf-1d65-460b-883b-e1b9dedc736e','和仁仲春日十絕  其三','胡寅','宋','宋诗','song-poetry','','[]','雨細雲輕隠隠雷，東君行樂正徘徊。',32,'全唐诗/poet.song.108000.json','["雨細雲輕隠隠雷，東君行樂正徘徊。", "欲教遊客留連醉，須放名花次第開。"]'),
('4474ce9d-a4e1-4f57-ac23-3415ff288bea','和仁仲春日十絕  其四','胡寅','宋','宋诗','song-poetry','','[]','莫笑遊人冷落時，風光流轉不須疑。',32,'全唐诗/poet.song.108000.json','["莫笑遊人冷落時，風光流轉不須疑。", "去年草色空成恨，今歲花光又滿枝。"]'),
('8a8e1e90-ce3f-4919-9e07-683979b845d1','和仁仲春日十絕  其五','胡寅','宋','宋诗','song-poetry','','[]','燕舞方酣鶑又啼，草堂春睡日平西。',32,'全唐诗/poet.song.108000.json','["燕舞方酣鶑又啼，草堂春睡日平西。", "枝頭有酒尋花去，小雨冥冥漸作泥。"]'),
('250b5568-fb5e-46b4-bb81-e18fb4c21695','和仁仲春日十絕  其六','胡寅','宋','宋诗','song-poetry','','[]','行春對酒滿壺頻，樂此春風自在身。',32,'全唐诗/poet.song.108000.json','["行春對酒滿壺頻，樂此春風自在身。", "須信壺中春不老，何人作計强留春。"]'),
('2d4aae83-7063-49d1-8812-c9a49ab9f16a','和仁仲春日十絕  其七','胡寅','宋','宋诗','song-poetry','','[]','年年綠水送殘紅，不怨東君只怨風。',32,'全唐诗/poet.song.108000.json','["年年綠水送殘紅，不怨東君只怨風。", "芳草連雲愁更遠，勸君當醉萬花中。"]'),
('7d7ec871-f0e0-4deb-99c4-a8c2d913037c','和仁仲春日十絕  其八','胡寅','宋','宋诗','song-poetry','','[]','萬卉千葩自不同，吹開只是一般風。',32,'全唐诗/poet.song.108000.json','["萬卉千葩自不同，吹開只是一般風。", "對花不見花開處，却恐嬉遊興易窮。"]'),
('c2ca781e-1011-463c-a399-0fd6e0895620','和仁仲春日十絕  其九','胡寅','宋','宋诗','song-poetry','','[]','洛陽風俗事栽花，流水園林眇一涯。',32,'全唐诗/poet.song.108000.json','["洛陽風俗事栽花，流水園林眇一涯。", "移得舊根春不老，錯疑蜂蝶過隣家。"]'),
('4e872956-ea4d-4189-9692-41ae18d7773c','和仁仲春日十絕  其一○','胡寅','宋','宋诗','song-poetry','','[]','陋巷當年只屢空，于今還詠舞雩風。',32,'全唐诗/poet.song.108000.json','["陋巷當年只屢空，于今還詠舞雩風。", "已推寶瑟鏗然後，莫認青春醉眼中。"]'),
('1eae457b-544e-4803-892a-d23ba5c95f94','將次鍾鄉先寄處厚唐丈','胡寅','宋','宋诗','song-poetry','','[]','試問雲山數歲華，寒梅吹盡兩年花。',64,'全唐诗/poet.song.108000.json','["試問雲山數歲華，寒梅吹盡兩年花。", "倦遊吳楚六千里，幸脫兵戈三四家。", "那用有田從桀溺，且欣無疾住毗耶。", "欲將別後從頭說，滿眼春酤盡更賒。"]'),
('398897d1-64bd-418d-a456-6578291bcccc','示阮冠','胡寅','宋','宋诗','song-poetry','','[]','一行作吏擲分陰，世路塵勞滿客襟。',64,'全唐诗/poet.song.108000.json','["一行作吏擲分陰，世路塵勞滿客襟。", "三語風流歸夢想，十年書問寄浮沉。", "門前種柳春光好，堂上鳴絃古意深。", "別後新詩都覓取，對哦湘淥醉還斟。"]'),
('c08fd690-952c-4c32-a1b8-d20fd1acb5f2','再遊嶽麓示法光其鄰道林人言陶士衡舊居也五絕  其一','胡寅','宋','宋诗','song-poetry','','[]','雄城千雉壓江橫，倒影蛟龍十里明。',32,'全唐诗/poet.song.108000.json','["雄城千雉壓江橫，倒影蛟龍十里明。", "欲倚危欄舒遠眺，東風無力暮雲平。"]'),
('2215d002-2e2b-4cc0-8c0e-4312477c606c','再遊嶽麓示法光其鄰道林人言陶士衡舊居也五絕  其二','胡寅','宋','宋诗','song-poetry','','[]','火宅清凉定幾時，三車門外世終迷。',32,'全唐诗/poet.song.108000.json','["火宅清凉定幾時，三車門外世終迷。", "青蓮紺宇憑何住，片雪紅爐只自知。"]'),
('848493dd-483a-4388-b4d1-c12345977caf','再遊嶽麓示法光其鄰道林人言陶士衡舊居也五絕  其三','胡寅','宋','宋诗','song-poetry','','[]','樓船東下啟扶桑，千古英明日月光。',32,'全唐诗/poet.song.108000.json','["樓船東下啟扶桑，千古英明日月光。", "未必此心如古井，且應蒼檜比甘棠。"]'),
('5a150aa5-365e-40eb-905d-4ae3083e8996','再遊嶽麓示法光其鄰道林人言陶士衡舊居也五絕  其四','胡寅','宋','宋诗','song-poetry','','[]','舊詩不省作何言，新句無奇墨亂翻。',32,'全唐诗/poet.song.108000.json','["舊詩不省作何言，新句無奇墨亂翻。", "要是雲山通宿契，故將文字寄深論。"]'),
('bccd7e92-2b63-4bc1-a74e-8342e1a92c4a','再遊嶽麓示法光其鄰道林人言陶士衡舊居也五絕  其五','胡寅','宋','宋诗','song-poetry','','[]','草堂何日傍雲根，借問隣家兩足尊。',32,'全唐诗/poet.song.108000.json','["草堂何日傍雲根，借問隣家兩足尊。", "欲買漁舟繫江樹，先憑屐齒記苔痕。"]'),
('8aa449ea-cdbe-4778-80ab-9da1f85ffa45','題湘西小景','胡寅','宋','宋诗','song-poetry','','[]','身在山中不見山，山前行客未能閒。',32,'全唐诗/poet.song.108000.json','["身在山中不見山，山前行客未能閒。", "何人水墨秋毫外，十里湖西尺寸間。"]'),
('c2087ed5-57cf-4ed4-b0c9-1064ba149217','題浯溪小景','胡寅','宋','宋诗','song-poetry','','[]','卜宅元郎豈偶然，江山千古共流傳。',32,'全唐诗/poet.song.108000.json','["卜宅元郎豈偶然，江山千古共流傳。", "乾坤巨石知多少，待看中興第二篇。"]'),
('6f0cc51f-dfda-48f4-9cf1-aadd27f4b1a8','自勝業寺過銓德觀','胡寅','宋','宋诗','song-poetry','','[]','出岫無心倦即還，悠然信馬望南山。',64,'全唐诗/poet.song.108000.json','["出岫無心倦即還，悠然信馬望南山。", "忽驚蓮社青萍合，却到蓬壺白日閒。", "方士內丹論九轉，導師平地設三關。", "不知洙泗真消息，誰可相期一解顔。"]'),
('defce039-3cb7-410e-835b-8060d150fa22','題銓德秋聲堂','胡寅','宋','宋诗','song-poetry','','[]','紫極題詩歲月深，秋風懷感重沉吟。',64,'全唐诗/poet.song.108000.json','["紫極題詩歲月深，秋風懷感重沉吟。", "殷勤種此一庭玉，回薄依然萬古心。", "獨有佳名追綵筆，誰將幽思入瑶琴。", "蕭蕭醉掃筆池石，水月光中覓至音。"]'),
('d2ae7085-04ee-4cd6-9675-cb386cc3a4d0','和鍾漕汝强四首  其一','胡寅','宋','宋诗','song-poetry','','[]','霧豹成文不厭深，喧卑何事競翰音。',64,'全唐诗/poet.song.108000.json','["霧豹成文不厭深，喧卑何事競翰音。", "爲言墨客誇三賦，那似仙翁振八吟。", "欲繼高蹤其敢後，下看浮世豈須臨。", "何時蠟屐携筇杖，來撥衡雲一萬尋。"]'),
('3937a95d-e9a0-433a-891c-ed891513069f','和鍾漕汝强四首  其二','胡寅','宋','宋诗','song-poetry','','[]','丈人愛客酒杯深，更和南山白石音。',64,'全唐诗/poet.song.108000.json','["丈人愛客酒杯深，更和南山白石音。", "大戶不知濡首節，逸才應笑撚髭吟。", "箴規有過風雷益，儆策無窮地澤臨。", "每憶向來談讌處，桃花流水路難尋。"]'),
('05d802e3-734c-4a71-8c9f-d5af535c23fa','和鍾漕汝强四首  其三','胡寅','宋','宋诗','song-poetry','','[]','風日薰薰草樹深，黄鸝遷木送新音。',64,'全唐诗/poet.song.108000.json','["風日薰薰草樹深，黄鸝遷木送新音。", "有懷春服成雩詠，遥想青山伴醉吟。", "詩老幽棲雖地僻，聖君高拱正天臨。", "未須靜處論方藥，會見蒲輪遠訪尋。"]'),
('4f57fb60-d15e-4993-81d1-d23ee4b112c9','和鍾漕汝强四首  其四','胡寅','宋','宋诗','song-poetry','','[]','雲自高閒水自深，此間誰契不傳音。',64,'全唐诗/poet.song.108000.json','["雲自高閒水自深，此間誰契不傳音。", "倦飛偶作歸田賦，高卧時爲梁甫吟。", "爲己宮牆當獨詣，過門車馬肯相臨。", "惟公知我迂愚甚，枉直何曾較尺尋。"]'),
('0a70a394-1557-45be-818d-4f0518158223','和曾漕吉甫','胡寅','宋','宋诗','song-poetry','','[]','本來秋月映澄潭，牆面猶須學二南。',64,'全唐诗/poet.song.108000.json','["本來秋月映澄潭，牆面猶須學二南。", "徑路枉尋難直尺，巵言暮四等朝三。", "文如楮葉何勞刻，道在蒲團恐費參。", "玉帛雍雍王會處，禹宮惆悵一精藍。"]'),
('32e2ab75-07af-4742-9e73-35a1e35e9b2e','題雲峰齊雲閣示住山思達二絕  其一','胡寅','宋','宋诗','song-poetry','','[]','舒捲高低晴復陰，澹然無滓亦無心。',32,'全唐诗/poet.song.108000.json','["舒捲高低晴復陰，澹然無滓亦無心。", "不知底處相齊得，且倚危欄一散襟。"]'),
('99fdc496-c35c-4ae6-b50b-67a3149a6b0f','題雲峰齊雲閣示住山思達二絕  其二','胡寅','宋','宋诗','song-poetry','','[]','秀色參差千萬端，浩然無礙碧天寬。',32,'全唐诗/poet.song.108000.json','["秀色參差千萬端，浩然無礙碧天寬。", "上人若見相齊處，試與憑欄指似看。"]'),
('b2920f1b-9605-4a75-a63d-a3d6ad714d17','題浄明觀','胡寅','宋','宋诗','song-poetry','','[]','長官冰操正飄纓，嘆息東流宰木青。',32,'全唐诗/poet.song.108000.json','["長官冰操正飄纓，嘆息東流宰木青。", "佳句不隨方士化，故應留作換鵝經。"]'),
('f561bdfd-a64d-4927-a9bf-d1908f119925','題劉練師屋壁','胡寅','宋','宋诗','song-poetry','','[]','誰言無路出塵氛，丹竈初聞一語真。',32,'全唐诗/poet.song.108000.json','["誰言無路出塵氛，丹竈初聞一語真。", "窗外未堆千嶂玉，坐中先盎一壺春。"]'),
('50e5b52c-fb99-408d-bd40-b1381d0db1c8','題草衣岩','胡寅','宋','宋诗','song-poetry','','[]','石室流傳一草衣，草衣消息了無違。',32,'全唐诗/poet.song.108000.json','["石室流傳一草衣，草衣消息了無違。", "此山只是如如體，休向山中覓祖師。"]'),
('4d6da1e8-9abe-4d5c-8374-1c0402b8235d','臘雷春雪示吉甫','胡寅','宋','宋诗','song-poetry','','[]','曉色空明衡嶽南，一塵那復隔仙凡。',64,'全唐诗/poet.song.108000.json','["曉色空明衡嶽南，一塵那復隔仙凡。", "貫時松竹色自好，破臘雷霆聲未咸。", "萬里鮫綃開步障，千金火浣試春衫。", "漁舟不與人供畫，獨駕雲濤月滿帆。"]'),
('2cc3f906-87d7-40cd-9e5b-83b9c59457a5','同邢子晉范伯達遊方廣二絕  其一','胡寅','宋','宋诗','song-poetry','','[]','黄梅作雨暗朝曛，山北山南路不分。',32,'全唐诗/poet.song.108000.json','["黄梅作雨暗朝曛，山北山南路不分。", "知我與君非俗駕，曉天收盡五峯雲。"]'),
('6152199a-05bf-4737-9d32-58ff68bd1b13','同邢子晉范伯達遊方廣二絕  其二','胡寅','宋','宋诗','song-poetry','','[]','瑶階金殿湧青蓮，此是南山小有天。',32,'全唐诗/poet.song.108000.json','["瑶階金殿湧青蓮，此是南山小有天。", "詩客若爲深避酒，道人無奈不參禪。"]'),
('3b92d069-85d6-49df-b6ae-46c8e0e98aa0','仲秋赴伯達浴兒會不見月','胡寅','宋','宋诗','song-poetry','','[]','準擬清光滿十分，論文那用醉紅裙。',64,'全唐诗/poet.song.108000.json','["準擬清光滿十分，論文那用醉紅裙。", "天公有意韜陰采，風伯無威掃曳雲。", "東道浴兒方洗腆，南齋留客更殷勤。", "朦朧碧澗三更路，衣袂翛然桂子芬。"]'),
('d32f426f-941f-4c60-aee2-c65c1833bc7c','將遊上封先寄南臺玨老','胡寅','宋','宋诗','song-poetry','','[]','淅淅風摇玉露秋，尚懷分柿半山不。',64,'全唐诗/poet.song.108000.json','["淅淅風摇玉露秋，尚懷分柿半山不。", "衆香肯共維摩飯，元亮聊同惠遠遊。", "薈蔚彫零岩壑露，佩環清越澗泉幽。", "青鞋本自無泥滓，更約諸峯最上頭。"]'),
('69fa621b-54d9-47d6-a8e0-50efaa993c97','登上封三絕  其一','胡寅','宋','宋诗','song-poetry','','[]','仰止高高幾夢思，躋攀乘興遂忘疲。',32,'全唐诗/poet.song.108000.json','["仰止高高幾夢思，躋攀乘興遂忘疲。", "直須駐足青冥上，方信前山次第卑。"]'),
('27eaa3e9-7249-49f9-bad2-1ddc4095a24e','登上封三絕  其二','胡寅','宋','宋诗','song-poetry','','[]','山下陰睛只蔽虧，山中烟靄更迷離。',32,'全唐诗/poet.song.108000.json','["山下陰睛只蔽虧，山中烟靄更迷離。", "天風忽與遊人便，吳楚屯雲萬里披。"]'),
('06f2c8d4-9131-45d2-9643-c729e69d97c5','登上封三絕  其三','胡寅','宋','宋诗','song-poetry','','[]','北斗回杓正指西，丹梯從此與天齊。',32,'全唐诗/poet.song.108000.json','["北斗回杓正指西，丹梯從此與天齊。", "爲君挹注銀潢水，一洗人間火宅迷。"]'),
('71fcc4ad-6a64-43c9-bccf-e7904f4fc4e0','和上封洪辯用明察院韻','胡寅','宋','宋诗','song-poetry','','[]','繡衣御史有前聞，衲子禪師亦好文。',64,'全唐诗/poet.song.108000.json','["繡衣御史有前聞，衲子禪師亦好文。", "出稟聖謨蘇瘵俗，坐持詩律戰魔軍。", "訪尋水石閒招隠，際會風雲偶策勳。", "喧寂兩忘歸一致，此心何處不超羣。"]'),
('0e3c851e-0454-4884-89d6-5428faa3b1d3','同宣卿和仲仲達遊上封值雨而歸時上封辯病南臺玨同行','胡寅','宋','宋诗','song-poetry','','[]','不到峯頭正一年，茲遊新客更超然。',64,'全唐诗/poet.song.108000.json','["不到峯頭正一年，茲遊新客更超然。", "浄名不語元無病，惠遠同行定有緣。", "風雨不期相邂逅，雲山未許獨留連。", "歸途絕景何人見，萬頃銀濤漲楚天。"]'),
('5743fef4-727b-4798-904a-3748d0192c88','酬宣卿見和','胡寅','宋','宋诗','song-poetry','','[]','不向杯中覓聖賢，獨於山水意翛然。',64,'全唐诗/poet.song.108000.json','["不向杯中覓聖賢，獨於山水意翛然。", "相門事業方傳世，官路升沉祗信緣。", "萬卷圖書資博約，九衢車馬任顛連。", "翠微卜宅須相近，且住蓬壺小有天。"]'),
('3ce732ba-321e-40b2-91ff-c3c4528e02b2','謹次家君元日之韻','胡寅','宋','宋诗','song-poetry','','[]','薰然和氣爆聲殘，賀客充庭上慶牋。',64,'全唐诗/poet.song.108000.json','["薰然和氣爆聲殘，賀客充庭上慶牋。", "令節共欣元會日，本朝新數中興年。", "仰觀北斗書王正，合起東山付國權。", "天祐斯文知有在，稱觴還詠福如川。"]'),
('83ba2bd9-40eb-4bcf-a995-0e02129bcf52','和宣風寺壁間韻','胡寅','宋','宋诗','song-poetry','','[]','客夢到何許，南山桃李園。',48,'全唐诗/poet.song.108000.json','["客夢到何許，南山桃李園。", "未能忘蠟屐，何意謁金門。", "願舉漢三傑，盡戡周陸渾。", "虎皮包劍㦸，農務看村村。"]'),
('0d0f27c1-5040-4c03-876e-81bd95a5f49e','遊三角寺','胡寅','宋','宋诗','song-poetry','','[]','再遊三角寺，勝踐十人偕。',48,'全唐诗/poet.song.108000.json','["再遊三角寺，勝踐十人偕。", "雨後林巒媚，心同笑語諧。", "碧蘭初秀畹，紅藥漸翻階。", "若問經行意，春風寫客懷。"]'),
('d1de0929-6286-4322-9f0c-26693c6d38dd','酬邦鑑見和','胡寅','宋','宋诗','song-poetry','','[]','恭誦親征詔，戈矛與子偕。',48,'全唐诗/poet.song.108000.json','["恭誦親征詔，戈矛與子偕。", "叛徒三鼓竭，凱奏八音諧。", "上主開宣室，羣公擁泰階。", "慚無經濟學，感激漫裝懷。"]'),
('d77a183d-7a47-4258-b864-304c7e47294a','和路樞四首  其一','胡寅','宋','宋诗','song-poetry','','[]','圖書雖是舊生涯，翰墨那能掞國華。',64,'全唐诗/poet.song.108000.json','["圖書雖是舊生涯，翰墨那能掞國華。", "戲綵便甘辭五馬，退朝猶想覆千花。", "先民事業高三代，將聖春秋自一家。", "他日登門謝佳句，劇談當許岸烏紗。"]'),
('c567fbb6-6ef3-4b7e-b3c7-4647805d2bc0','和路樞四首  其二','胡寅','宋','宋诗','song-poetry','','[]','前籌初見翊元樞，何事扁舟泛五湖。',64,'全唐诗/poet.song.108000.json','["前籌初見翊元樞，何事扁舟泛五湖。", "脫屣紅塵誰肯辦，挂冠黑髮世應無。", "願陪几杖登南阜，遥想氛埃暗北區。", "晚節功名端不免，雲臺依舊矗天都。"]'),
('87f7aa0f-754d-4b2e-9680-4ce2b566389d','和路樞四首  其三','胡寅','宋','宋诗','song-poetry','','[]','林壑蒼茫渺一涯，辱公詞藻借光華。',64,'全唐诗/poet.song.108000.json','["林壑蒼茫渺一涯，辱公詞藻借光華。", "大聲豈直金投地，清夢懸知筆有花。", "不似罷兵初度嶺，應同奏疏早名家。", "曳裾未愜平生志，常恐追鋒侍絳紗。"]'),
('8f75b60b-c2e7-447a-9e47-2e89c08edfba','和路樞四首  其四','胡寅','宋','宋诗','song-poetry','','[]','進退行藏合道樞，詎分廊廟與江湖。',64,'全唐诗/poet.song.108000.json','["進退行藏合道樞，詎分廊廟與江湖。", "願陪東閣留賓後，定向南山卜宅無。", "不爲避喧隣懶瓚，祗緣嘗藥訪臾區。", "勉搜累句酬高韻，端似無鹽簉子都。"]'),
('9f58dec2-d25e-4d9b-8b47-3d6134dfc2f0','子正生日以黄柑爲壽','胡寅','宋','宋诗','song-poetry','','[]','正論風流不辱親，高文還稱掌絲綸。',64,'全唐诗/poet.song.108000.json','["正論風流不辱親，高文還稱掌絲綸。", "豈惟補衮須詞伯，自是安邦出諍臣。", "歲晚已回松柏操，時來休愛水雲身。", "欲爲公壽倡優拙，戲遣商山四老人。"]'),
('835173c0-27e7-4e25-b45d-ee65458b091e','和余汝霖雪七絕  其一','胡寅','宋','宋诗','song-poetry','','[]','無數天花鬭舞風，迷離玉色映寒空。',32,'全唐诗/poet.song.108000.json','["無數天花鬭舞風，迷離玉色映寒空。", "共誇破臘逾三白，更喜新詩報屢豐。"]'),
('289ebae6-9ccf-49af-963d-d255050ec97e','和余汝霖雪七絕  其二','胡寅','宋','宋诗','song-poetry','','[]','雖無諧謔去相携，且乏輿梁濟涉溪。',32,'全唐诗/poet.song.108000.json','["雖無諧謔去相携，且乏輿梁濟涉溪。", "之子惠然須痛飲，醉眠應夢鎮幃犀。"]'),
('bdb12005-ce3d-4fdc-b0b3-71df45e3e737','和余汝霖雪七絕  其三','胡寅','宋','宋诗','song-poetry','','[]','日日東園探早梅，那知一夕萬林開。',32,'全唐诗/poet.song.108000.json','["日日東園探早梅，那知一夕萬林開。", "君詩還似揚州句，掃盡因風柳絮才。"]'),
('6775cdbc-a9c9-4ccd-83e6-88b18aa4e01b','和余汝霖雪七絕  其四','胡寅','宋','宋诗','song-poetry','','[]','周宣闢國號中宗，六月興師灑汗同。',32,'全唐诗/poet.song.108000.json','["周宣闢國號中宗，六月興師灑汗同。", "莫爲苦寒辭出塞，采薇歸戍亦論功。"]'),
('05dfebff-bbf6-4d61-b5e6-2f5b7f992575','和余汝霖雪七絕  其五','胡寅','宋','宋诗','song-poetry','','[]','燕山大雪暗胡雲，將士何人欲賜勳。',32,'全唐诗/poet.song.108000.json','["燕山大雪暗胡雲，將士何人欲賜勳。", "聞道玉宸溫詔出，絕勝純纊被三軍。"]'),
('8ff9c06e-a35e-41bf-8a43-f19cf5331487','和余汝霖雪七絕  其六','胡寅','宋','宋诗','song-poetry','','[]','低唱誰家有女伶，映窗那用讀書聲。',32,'全唐诗/poet.song.108000.json','["低唱誰家有女伶，映窗那用讀書聲。", "何當翠被同君獵，得獸雄夸得句清。"]'),
('95c77972-6347-48cd-90cb-8c0ac78c397b','和余汝霖雪七絕  其七','胡寅','宋','宋诗','song-poetry','','[]','朱老能詩更謹虔，葉公好學亦窮年。',32,'全唐诗/poet.song.108000.json','["朱老能詩更謹虔，葉公好學亦窮年。", "饑寒共保凌霜操，未羨重裘食萬錢。"]'),
('e1d9d775-889f-45e7-ae18-1b099dfcb6a6','再和  其一','胡寅','宋','宋诗','song-poetry','','[]','紛紛狼籍下天風，萬里寒光鏡色空。',32,'全唐诗/poet.song.108000.json','["紛紛狼籍下天風，萬里寒光鏡色空。", "莫學袁安但高卧，也須斗酒醉新豐。"]'),
('bb4933ec-ce4e-4472-82be-4cc0e4dc3b7c','再和  其二','胡寅','宋','宋诗','song-poetry','','[]','迥眺層臺酒屢携，千峰攢玉映瑶溪。',32,'全唐诗/poet.song.108000.json','["迥眺層臺酒屢携，千峰攢玉映瑶溪。", "南枝更有東風面，未減爭妍燦瓠犀。"]'),
('6f694ce8-908d-4629-a8d3-f53c436f72e0','再和  其三','胡寅','宋','宋诗','song-poetry','','[]','今年花是去年梅，又對春風一笑開。',32,'全唐诗/poet.song.108000.json','["今年花是去年梅，又對春風一笑開。", "不似飛霙能頃刻，香中更有和羹才。"]'),
('2af8d866-c0f8-4c7a-b4ff-b70b641d0df5','再和  其四','胡寅','宋','宋诗','song-poetry','','[]','埋玉腰間覓性宗，儒冠謀道有誰同。',32,'全唐诗/poet.song.108000.json','["埋玉腰間覓性宗，儒冠謀道有誰同。", "筆尖凍折新詩就，但可徒收翰墨功。"]'),
('7513c111-39dc-4de9-b6c8-f010d12e5e78','再和  其五','胡寅','宋','宋诗','song-poetry','','[]','猛將謀臣氣靄雲，興邦雪恥在奇勳。',32,'全唐诗/poet.song.108000.json','["猛將謀臣氣靄雲，興邦雪恥在奇勳。", "因思衛國瓊瑶報，更憶吳人組練軍。"]'),
('0f98cecf-4d61-43fd-88c8-1eb56b9359ea','再和  其六','胡寅','宋','宋诗','song-poetry','','[]','劍峯犀利拙優伶，果聽淮南奏凱聲。',32,'全唐诗/poet.song.108000.json','["劍峯犀利拙優伶，果聽淮南奏凱聲。", "陰翳便隨朝雪盡，東風還放曉光清。"]'),
('0a84dfde-6ae3-4737-bfa3-19216094304e','再和  其七','胡寅','宋','宋诗','song-poetry','','[]','自笑兵厨吏不虔，凍醅如蜜只年年。',32,'全唐诗/poet.song.108000.json','["自笑兵厨吏不虔，凍醅如蜜只年年。", "却思踏雪江頭路，屢費詩人一斗錢。"]'),
('5af049ef-4e24-488f-ac67-a8687adf4fee','歲除示汝霖三絕  其一','胡寅','宋','宋诗','song-poetry','','[]','柏酒椒花又盍簪，莫將談笑枉光陰。',32,'全唐诗/poet.song.108000.json','["柏酒椒花又盍簪，莫將談笑枉光陰。", "自憐四十無聞者，欲問如何不動心。"]'),
('ba1bb55b-d8fc-4e81-ad5e-3902e3e18e61','歲除示汝霖三絕  其二','胡寅','宋','宋诗','song-poetry','','[]','邂逅遮留閲歲寒，山肴溪蔌且同盤。',32,'全唐诗/poet.song.108000.json','["邂逅遮留閲歲寒，山肴溪蔌且同盤。", "不憂絕學商量少，只怕新詩屬和難。"]'),
('d1c4b585-7a0d-4d51-b400-bfc83281d961','歲除示汝霖三絕  其三','胡寅','宋','宋诗','song-poetry','','[]','紫蓋峯前萬壑流，長松脩竹與雲浮。',32,'全唐诗/poet.song.108000.json','["紫蓋峯前萬壑流，長松脩竹與雲浮。", "欲分一半誰人可，子若能來亦易謀。"]'),
('b3bd7b73-dc4c-41cf-be72-a0f16c757a4e','和汝霖三首  其一','胡寅','宋','宋诗','song-poetry','','[]','客思如春日日深，莫令鶗鴂損芳陰。',64,'全唐诗/poet.song.108000.json','["客思如春日日深，莫令鶗鴂損芳陰。", "忽逢佳士能傾蓋，那用高眠有抱衾。", "陌上正歌歸緩緩，尊前聊酌夜沉沉。", "君詩也得池塘夢，沈謝風流尚可尋。"]'),
('012e5718-9e54-4909-83e8-313ebee7e489','和汝霖三首  其二','胡寅','宋','宋诗','song-poetry','','[]','聖門功業海同深，大禹猶曾惜寸陰。',64,'全唐诗/poet.song.108000.json','["聖門功業海同深，大禹猶曾惜寸陰。", "知有詩書消永日，不將狐貉愧寒衾。", "定心應已觀川逝，闊步何須歎陸沉。", "聞道北山蘭正好，果堪紉佩即幽尋。"]'),
('62d501c2-e44a-448c-99e7-cd5c440ffce0','和汝霖三首  其三','胡寅','宋','宋诗','song-poetry','','[]','桃李無言春事深，便看園樹欲交陰。',64,'全唐诗/poet.song.108000.json','["桃李無言春事深，便看園樹欲交陰。", "永懷北固吹長笛，一醉春風典破衾。", "金羽喜從幽谷出，錦鱗貪引翠竿沉。", "好傳消息睎曾點，莫把平生問李尋。"]'),
('3eace8dd-b932-45f4-be95-8653a3e87ec7','和朱成伯  其一','胡寅','宋','宋诗','song-poetry','','[]','劫劫官身未許收，江山到處發詩愁。',64,'全唐诗/poet.song.108000.json','["劫劫官身未許收，江山到處發詩愁。", "棄繻西上今將老，襆被東來又欲秋。", "安得紫簫橫鶴背，漫從清釣覓羊裘。", "黄梅正作冥冥雨，每詠新篇興轉悠。"]'),
('104a4984-b3be-4f04-9f14-4afd4e344706','和朱成伯  其二','胡寅','宋','宋诗','song-poetry','','[]','瀾翻筆墨浩難收，妙處端能浣客愁。',64,'全唐诗/poet.song.108000.json','["瀾翻筆墨浩難收，妙處端能浣客愁。", "落筆千章輕萬戶，思君一日勝三秋。", "持身貴比琥璜爵，得句精如狐白裘。", "應有二南風骨在，令人輾轉更優悠。"]'),
('d9f93be9-46e8-480c-bed5-d76bdd765056','荷花','胡寅','宋','宋诗','song-poetry','','[]','夢到南塘翠蓋稠，姹然得意斂然羞。',64,'全唐诗/poet.song.108000.json','["夢到南塘翠蓋稠，姹然得意斂然羞。", "驚鴻遠映朝霞色，白鷺先窺霽雨秋。", "裊裊芳馨煩折贈，霏霏凉吹想追遊。", "天花欲試維摩病，衣袂何曾一片留。"]'),
('d950a6ae-432b-48cc-bc95-c11670ae11ab','酬諸同官見和三首  其一','胡寅','宋','宋诗','song-poetry','','[]','初看綠浄已紅稠，有艷無情不障羞。',64,'全唐诗/poet.song.108000.json','["初看綠浄已紅稠，有艷無情不障羞。", "依倚鉛華閒寫鏡，霏微風露早涵秋。", "虎溪香社應難入，玉井長梯未許遊。", "同賦諸仙語皆妙，坐令芳色句中留。"]'),
('fa8a7bbe-bdd7-4e95-bcf7-3bbf5789ac8a','酬諸同官見和三首  其二','胡寅','宋','宋诗','song-poetry','','[]','蘭塘清暑瞰稀稠，早見排房結子羞。',64,'全唐诗/poet.song.108000.json','["蘭塘清暑瞰稀稠，早見排房結子羞。", "照水華燈宜獨夜，薰香翠被欲爭秋。", "潜珍不薦霓裳步，凝佇誰同漢女遊。", "欲種此花須摘實，自憐踏藕漫淹留。"]'),
('aece6c2d-f464-44d9-955e-c6cec40cfc4b','酬諸同官見和三首  其三','胡寅','宋','宋诗','song-poetry','','[]','莫道同時岸卉稠，背萱無態側葵羞。',64,'全唐诗/poet.song.108000.json','["莫道同時岸卉稠，背萱無態側葵羞。", "金蓬未實猶韜日，玉節深藏更耐秋。", "肯把仙姿供鷺悅，故標高致待龜遊。", "期君秀色蓮峯似，終古名垂華岳留。"]'),
('95328c31-8407-4999-9a3e-147d03fcc5af','和信仲喜雨二首  其一','胡寅','宋','宋诗','song-poetry','','[]','雲漢吁嗟墮杳冥，德音雷動走羣靈。',64,'全唐诗/poet.song.108000.json','["雲漢吁嗟墮杳冥，德音雷動走羣靈。", "天心自契犠牲禱，田畯先聞黍稷馨。", "簾捲西山增爽氣，水通南澗漫平汀。", "一篇可嗣東坡記，北榭今成喜雨亭。"]'),
('0f03d9d7-bb41-4296-9fee-da670ba8c415','和信仲喜雨二首  其二','胡寅','宋','宋诗','song-poetry','','[]','天公知我亦頑冥，不許山川借寵靈。',64,'全唐诗/poet.song.108000.json','["天公知我亦頑冥，不許山川借寵靈。", "何事民謠爲膏澤，祇因君德薦明馨。", "楩楠未厭雲迷谷，鷗鷺初便水滿汀。", "試攬秋光澄北榭，千峯爭翠岌岩亭。"]'),
('f10724ba-2d92-458f-8bed-b6527b1d7dfe','禱雨','胡寅','宋','宋诗','song-poetry','','[]','久閟天公澤，焦然品彙情。',192,'全唐诗/poet.song.108000.json','["久閟天公澤，焦然品彙情。", "遏雲虹屢飲，擊海電空明。", "禱祀山川遍，薰修道釋并。", "帝心終閔物，國力未休兵。", "帽覆烏龍頂，軍移黑蟻營。", "乍看雲葉密，遥想浪花平。", "早熟攙先刈，高荒趁晚耕。", "歸逋庭少訟，交潤水無爭。", "喜氣連城洽，餘波集澮盈。", "蕉心重自展，荷葉密相傾。", "菊映蘭兼茂，松連竹共清。", "杯觴初料理，書帙尚縱橫。", "欲賦田園樂，猶慚組綬縈。", "隠淪千古重，名利一絲輕。", "釣客風流遠，農師局次生。", "庶幾逃責罰，戶戶有坻京。"]'),
('1e6598c6-c597-4f4e-994d-e10242bf5ce8','酬信仲見和二首  其一','胡寅','宋','宋诗','song-poetry','','[]','數篇新雨意，真見古人情。',192,'全唐诗/poet.song.108000.json','["數篇新雨意，真見古人情。", "當拜王靈及，非關祀事明。", "雷聲空自碾，雲氣不相并。", "試爲驅潜物，安能役鬼兵。", "曉來聞鵲唶，座上掃蠅營。", "地脈沾濡遍，天心賦與平。", "遠慚白水政，坐想有莘耕。", "各競千峯秀，誰平兩港爭。", "稻花重撲撲，蓮臉更盈盈。", "但欲禾麻穟，無令棟宇傾。", "教心蘧叟化，官況伯夷清。", "霽電金蛇掣，晴霞綺鳳橫。", "仙人歸縹緲，詩客思紆縈。", "句屑餘霏妙，人涵晚吹輕。", "故園三徑綠，新水半篙生。", "遂有乘槎興，秋風白玉京。"]'),
('27809a61-a26d-40da-a1cf-98dc923aa777','酬信仲見和二首  其二','胡寅','宋','宋诗','song-poetry','','[]','不作悲秋賦，猶牽夢雨情。',192,'全唐诗/poet.song.108000.json','["不作悲秋賦，猶牽夢雨情。", "人心空懇迫，天聽自昭明。", "驟豈風能靡，和非雹與并。", "霤懸廬阜瀑，山映羽林兵。", "已灑臨菑汗，將漂石勒營。", "循良慚召父，調燮頼陳平。", "方士田俱溉，先生道可耕。", "亂飄絲未理，急點射方爭。", "願補天無漏，誰占坎不盈。", "雲披心屢折，雷屬耳常傾。", "未說千箱滿，聊欣八極清。", "幸令鵝貰死，那恤虹仍橫。", "銀竹森猶亞，簷花落更縈。", "昆陽萬矢盡，滄海幾漚輕。", "反照霞初散，中秋月已生。", "一杯相屬處，憂慮洗京京。"]'),
('fef68fb4-19b8-40fc-9c3b-30cfe116d18b','以崇正辯示新仲','胡寅','宋','宋诗','song-poetry','','[]','不羨飛仙術，仍修謗佛書。',48,'全唐诗/poet.song.108000.json','["不羨飛仙術，仍修謗佛書。", "知音鼓琴後，覆瓿草玄餘。", "龍象空相蹙，鳶魚祗自如。", "更煩君印可，底處認吾廬。"]'),
('f2d951df-c728-44a5-86e2-288da69c4ebe','酬新仲見和二首  其一','胡寅','宋','宋诗','song-poetry','','[]','自喜逢端友，初蒙賞異書。',48,'全唐诗/poet.song.108000.json','["自喜逢端友，初蒙賞異書。", "不譏吾好辯，更請慎其餘。", "術業須三代，宗風謝一如。", "與公俱目擊，紙上亦蘧廬。"]'),
('43029d64-0b76-4e1e-9351-f252b7ebfd2d','酬新仲見和二首  其二','胡寅','宋','宋诗','song-poetry','','[]','蓬蒿翳環堵，左右只圖書。',48,'全唐诗/poet.song.108000.json','["蓬蒿翳環堵，左右只圖書。", "面壁知無累，心齋諒有餘。", "經綸今賈誼，詞賦昔相如。", "莫廣離騷意，行看直禁廬。"]'),
('cb935a59-beb9-4271-84aa-bff14128baf1','賦向伯共五老小山六言五絕  其一','胡寅','宋','宋诗','song-poetry','','[]','奇石來公几案，參差仙掌規模。',28,'全唐诗/poet.song.108000.json','["奇石來公几案，參差仙掌規模。", "遂欲强名五老，逍遥鵬鷃羌廬。"]'),
('3249ed73-057d-4b43-9cef-a7e1e8712e9f','賦向伯共五老小山六言五絕  其二','胡寅','宋','宋诗','song-poetry','','[]','聞說身依蓮社，坐蒙敕賜薌林。',28,'全唐诗/poet.song.108000.json','["聞說身依蓮社，坐蒙敕賜薌林。", "五老與公爲六，何須詩酒棋琴。"]'),
('39348ba8-7f07-4421-9fd7-ab6b0065493f','賦向伯共五老小山六言五絕  其三','胡寅','宋','宋诗','song-poetry','','[]','問法想應得髓，好奇那復忘疲。',28,'全唐诗/poet.song.108000.json','["問法想應得髓，好奇那復忘疲。", "此石未同瓦礫，耆年直是兒嬉。"]'),
('9536c609-9687-4c5d-8489-c7ba68de2f5e','賦向伯共五老小山六言五絕  其四','胡寅','宋','宋诗','song-poetry','','[]','山石詎聞變化，蒼顔能復嬰孩。',28,'全唐诗/poet.song.108000.json','["山石詎聞變化，蒼顔能復嬰孩。", "想見輕葱秀色，正如蘭玉陪階。"]'),
('8e48a388-7414-43b5-bbc7-19c089440846','賦向伯共五老小山六言五絕  其五','胡寅','宋','宋诗','song-poetry','','[]','文簡風流未泯，公孫節氣誰班。',28,'全唐诗/poet.song.108000.json','["文簡風流未泯，公孫節氣誰班。", "當與臯夔佐舜，莫尋黄綺商山。"]'),
('c0b65cc2-04d5-43be-bb80-fd24da64cb91','和錢孫叔委心亭二絕  其一','胡寅','宋','宋诗','song-poetry','','[]','交衢塵霧祗相煎，回首山林去未緣。',32,'全唐诗/poet.song.108000.json','["交衢塵霧祗相煎，回首山林去未緣。", "安得委心無一事，陪公清話許忘年。"]'),
('47adf53f-16c5-4d3f-a51c-432b06fa61a9','和錢孫叔委心亭二絕  其二','胡寅','宋','宋诗','song-poetry','','[]','寄傲羲皇以上人，古今雖隔意常親。',32,'全唐诗/poet.song.108000.json','["寄傲羲皇以上人，古今雖隔意常親。", "聖時方欲詢黄髮，未許公收致主身。"]'),
('967a5383-143d-4c06-9d89-3a4ac0d5240e','奉家君自勝業遷居書堂久雨乍晴道中口占','胡寅','宋','宋诗','song-poetry','','[]','五峯收卷萬層雲，一水流通四海春。',32,'全唐诗/poet.song.108000.json','["五峯收卷萬層雲，一水流通四海春。", "南極有星天地久，東風無際柳梅均。"]'),
('9c9358fc-e054-4f30-b7c1-a1dc0446e02c','謝人惠舂陵石山','胡寅','宋','宋诗','song-poetry','','[]','何人蹙縮九疑山，疊映公家几硯間。',64,'全唐诗/poet.song.108000.json','["何人蹙縮九疑山，疊映公家几硯間。", "欲識神魚閟凝湛，試看雲氣出孱顔。", "新蒲已結根千歲，舊蘚猶窺暈一斑。", "舉餉敢辭歸載重，要將奇絕寄幽閒。"]'),
('5d8e7813-f8a8-4842-8375-4da3bb9d0ffc','和賈陶二老二首  其一','胡寅','宋','宋诗','song-poetry','','[]','已愧名邦忝，仍無秀句傳。',48,'全唐诗/poet.song.108000.json','["已愧名邦忝，仍無秀句傳。", "花光隨處好，草色與愁連。", "訟少庭常寂，心閒地更偏。", "先生肯乘興，一醉賞風烟。"]'),
('cb67d4f0-7b74-49b7-b62d-bbeba7c77883','和賈陶二老二首  其二','胡寅','宋','宋诗','song-poetry','','[]','節物怱怱度，邊烽幸不傳。',48,'全唐诗/poet.song.108000.json','["節物怱怱度，邊烽幸不傳。", "名花空雨墮，秀樹已雲連。", "孤負杯蓮倒，蕭條燭蕊偏。", "但欣民小泰，凝寢有爐烟。"]'),
('11fc7fa6-c388-41b9-985e-5eafa93b697b','和邢子友','胡寅','宋','宋诗','song-poetry','','[]','可憐牒訟汩華年，頼有神交肯惠然。',64,'全唐诗/poet.song.108000.json','["可憐牒訟汩華年，頼有神交肯惠然。", "萬石同登高柳外，一尊相屬晚花前。", "浮雲空解遮人境，止水何曾染世緣。", "安得小舟銜尾去，風檣激箭不須鞭。"]'),
('56640b3a-f32a-4302-86c6-41342f9800e7','和趙生二首  其一','胡寅','宋','宋诗','song-poetry','','[]','徧遊南北與西東，欲訪人間國士風。',64,'全唐诗/poet.song.108000.json','["徧遊南北與西東，欲訪人間國士風。", "處世甚疎皆笑我，宅心無累獨奇公。", "詩才自愧非三上，酒聖相從又一中。", "芍藥待開應且住，莫令清賞轉頭空。"]'),
('ba363232-6b0a-493b-a80a-965e9f892d1d','和趙生二首  其二','胡寅','宋','宋诗','song-poetry','','[]','冠月裾雲佩綠霞，百年將此送生涯。',64,'全唐诗/poet.song.108000.json','["冠月裾雲佩綠霞，百年將此送生涯。", "愁心別後無詩草，病眼燈前有醉花。", "落筆擅場聊寫意，背山臨水遂成家。", "也須南畝多栽秫，休似東陵只種瓜。"]'),
('eb01ec58-12d0-4ca7-8a7e-a4319e821fa7','遊淡竹岩','胡寅','宋','宋诗','song-poetry','','[]','岩好城還近，山南路却西。',48,'全唐诗/poet.song.108000.json','["岩好城還近，山南路却西。", "淡交同魯衛，新釀到青齊。", "桑密家家繭，秧稠處處犂。", "朱陵更清絕，何必此幽棲。"]'),
('09c3bdd2-eb40-4c17-80c6-3943de3a0541','題賈氏超然堂','胡寅','宋','宋诗','song-poetry','','[]','超然華榜照新堂，兀爾忘機入醉鄉。',64,'全唐诗/poet.song.108000.json','["超然華榜照新堂，兀爾忘機入醉鄉。", "城外有山心共遠，壺中無事日偏長。", "月留粉壁檀欒影，欄俯冰池菡萏香。", "最愛南窗通北牖，好風時送一襟凉。"]'),
('98b92cde-16e3-48fa-b7ed-49b1aa8d9a9d','又題迎月亭','胡寅','宋','宋诗','song-poetry','','[]','從來共惜隔年期，剗却東山尚恐遲。',64,'全唐诗/poet.song.108000.json','["從來共惜隔年期，剗却東山尚恐遲。", "欲向塵中先得眼，故應雲表屢揚眉。", "停杯專待寒光舉，起舞還愁素影移。", "常與此亭相照耀，更須佳什煥梁榱。"]'),
('0c7bb215-27d7-4fcd-91c4-d401349e579f','和賈閣老三首  其一','胡寅','宋','宋诗','song-poetry','','[]','新柳逢秋葉尚陰，晚蓮披露色難禁。',64,'全唐诗/poet.song.108000.json','["新柳逢秋葉尚陰，晚蓮披露色難禁。", "坐聽玉屑軒犀麈，靜對山爐颺水沉。", "綠酒淺深皆有味，白雲來去本無心。", "辱公麗藻相留句，且復追隨翰墨林。"]'),
('12fff072-508b-4367-99f8-cbb721144bfe','和賈閣老三首  其二','胡寅','宋','宋诗','song-poetry','','[]','來朝杲日破頑陰，共指秋成喜不禁。',64,'全唐诗/poet.song.108000.json','["來朝杲日破頑陰，共指秋成喜不禁。", "寸碧遥岑供眺望，長空飛鳥自消沉。", "四時景物千鍾酒，萬古功名一寸心。", "尚媿先生遊佛海，兩忘軒冕與山林。"]'),
('c81d934b-e710-4678-9479-7fcf45987cb2','和賈閣老三首  其三','胡寅','宋','宋诗','song-poetry','','[]','西雲十日結重陰，葵箑桃笙自不禁。',64,'全唐诗/poet.song.108000.json','["西雲十日結重陰，葵箑桃笙自不禁。", "書帙有緣燈耿耿，酒杯無伴雨沉沉。", "君恩未報空懷祿，民瘼難醫只媿心。", "爲問野麋何處好，鶑鳴雕檻隔長林。"]'),
('cec163c4-7dd2-4fb8-92f9-3e5aa95072f7','中秋寄賈閣老','胡寅','宋','宋诗','song-poetry','','[]','香霧沉秋氣，迷雲捲暮天。',48,'全唐诗/poet.song.108000.json','["香霧沉秋氣，迷雲捲暮天。", "金篦撩眼浄，玉斧斲冰圓。", "無復霓裳舞，空歌水調篇。", "新亭偏得景，一醉豈無緣。"]'),
('a088dcd5-f209-4138-a687-b91c9525c256','和彥達九日','胡寅','宋','宋诗','song-poetry','','[]','滿頭黄菊鬭芳妍，人與秋光兩靜便。',64,'全唐诗/poet.song.108000.json','["滿頭黄菊鬭芳妍，人與秋光兩靜便。", "試把杯觴論舊日，未須筋力較明年。", "詩慚戲馬臺頭客，目斷歸鴻渚上天。", "更愧白衣能送酒，坐令彭澤意空傳。"]'),
('f407c731-9563-42d7-b1cc-c5b9176f5fe4','和唐壽隆上元五首  其一','胡寅','宋','宋诗','song-poetry','','[]','滿城和氣在春臺，玉漏沉沉鐵鎖開。',64,'全唐诗/poet.song.108000.json','["滿城和氣在春臺，玉漏沉沉鐵鎖開。", "明月誰知千里共，華燈同照萬人來。", "市橋漸漲丰容柳，江路猶殘的皪梅。", "欲與先生拚醉賞，未須歸去隠蒿萊。"]'),
('6ec9428e-f485-4abe-b857-c0d9723d6bcd','和唐壽隆上元五首  其二','胡寅','宋','宋诗','song-poetry','','[]','明月升天鏡上臺，燈如蓮沼萬枝開。',64,'全唐诗/poet.song.108000.json','["明月升天鏡上臺，燈如蓮沼萬枝開。", "恨無立部歌仍舞，空有遊人往更來。", "續法未能窺佛祖，賡歌聊得繼歐梅。", "壯心消盡嬉遊興，矧復斑衣悵老萊。"]'),
('2b901c4d-bc56-40f8-8fbe-953db4605933','和唐壽隆上元五首  其三','胡寅','宋','宋诗','song-poetry','','[]','名章絡繹走陪臺，得對春風一笑開。',64,'全唐诗/poet.song.108000.json','["名章絡繹走陪臺，得對春風一笑開。", "樓外未知明月出，袖中疑有夜光來。", "秀如王子登門竹，味勝曹公止渴梅。", "已向歌謠挹和氣，預知豐稔變汙萊。"]'),
('9fd1dfed-57b3-433c-bd6f-c00fac1d89cb','和唐壽隆上元五首  其四','胡寅','宋','宋诗','song-poetry','','[]','山褰雲色暗陽臺，俄復晨曦萬里開。',64,'全唐诗/poet.song.108000.json','["山褰雲色暗陽臺，俄復晨曦萬里開。", "行雨忽隨新夢斷，春風還似故人來。", "精神總屬陶潜柳，燮理須歸傅說梅。", "已共此邦同樂歲，更須躬稼辟田萊。"]'),
('579b355b-b325-48ea-9701-9b3b46ef3db4','和唐壽隆上元五首  其五','胡寅','宋','宋诗','song-poetry','','[]','幾年蹤跡遠中臺，夢想傳柑宴斚開。',64,'全唐诗/poet.song.108000.json','["幾年蹤跡遠中臺，夢想傳柑宴斚開。", "懶擁牙旗穿市去，縱看玉李墮天來。", "從教獨照青藜炬，莫使輕吹畫角梅。", "也有江風浮綵巘，坐令形勢卷東萊。"]'),
('eab35314-5342-49ba-8aeb-642d0c1a02a2','寄題吳郁養素軒','胡寅','宋','宋诗','song-poetry','','[]','到處風塵染素衣，蜉蝣掘閲尚何知。',64,'全唐诗/poet.song.108000.json','["到處風塵染素衣，蜉蝣掘閲尚何知。", "似聞掃雪開三徑，可但移梅探一枝。", "分我高山彈舊曲，乞君明月斲新詩。", "幾時把酒臨窗檻，借問如何湼不緇。"]'),
('73b7efc1-623b-450d-baf5-c1d6ab771b4f','和次山遊朝陽岩','胡寅','宋','宋诗','song-poetry','','[]','畫船浮客到岩阿，小閣經年又一過。',64,'全唐诗/poet.song.108000.json','["畫船浮客到岩阿，小閣經年又一過。", "天遠恍如開翠幕，江春渾似遶青羅。", "雨晴風日山山麗，花發園林處處多。", "早喜四郊膏澤徧，試從堯壤嗣農歌。"]'),
('2dc42b0e-380a-4f92-a2a0-7e5afcf93f91','和范元作二首  其一','胡寅','宋','宋诗','song-poetry','','[]','江北風塵靜，江南水竹居。',48,'全唐诗/poet.song.108000.json','["江北風塵靜，江南水竹居。", "世交論契厚，歲晚莫情疎。", "斸雪重培菊，臨溪易買魚。", "瀟湘有舊約，相就不投書。"]'),
('07b9e62b-b61c-4859-b812-e86ff9e55ff0','和范元作二首  其二','胡寅','宋','宋诗','song-poetry','','[]','仇虜何須殺，調和乃妙機。',48,'全唐诗/poet.song.108000.json','["仇虜何須殺，調和乃妙機。", "又聞堅誓約，不用講攻圍。", "六月鵬南徙，三春雁北歸。", "自知同斥鷃，蓬艾且卑飛。"]'),
('594199c5-db51-4d58-a827-025803b7746b','和李子揚題龍源田舍','胡寅','宋','宋诗','song-poetry','','[]','舊隠今何許，新宮定幾間。',96,'全唐诗/poet.song.108000.json','["舊隠今何許，新宮定幾間。", "紅塵昏北道，青壁睨南山。", "若擬崧和潁，猶勝蒯與菅。", "君方二頃得，我愛一生閒。", "蔭石多雲樹，行田有翠灣。", "客來那更問，門設不須關。", "世味浮雲薄，顛毛小雪斑。", "功名當未免，亦念早來還。"]'),
('d79b41c0-52b8-4777-af1d-e9741d1c6a62','又和湘濱卜居','胡寅','宋','宋诗','song-poetry','','[]','聞道園池各著名，起予歸夢過臨蒸。',64,'全唐诗/poet.song.108000.json','["聞道園池各著名，起予歸夢過臨蒸。", "已開塵外尋山眼，更曲堂中飲水肱。", "有地且須多種秫，好閒何必苦邀僧。", "杖藜他日端來去，但恐公朝正與能。"]'),
('9531bb10-1ad4-4473-b981-ae78e27f04f0','郭偉求鄙文','胡寅','宋','宋诗','song-poetry','','[]','少時文墨已非工，漸老才情更覺蒙。',64,'全唐诗/poet.song.108000.json','["少時文墨已非工，漸老才情更覺蒙。", "空有簿書相汩沒，了無朋友共磨礲。", "功名也只浮雲似，富貴還應逝水同。", "寄語宅心何處所，晚春沂上舞雩風。"]'),
('38dbe3e8-47ed-454f-8db7-de1849373080','思歸八絕  其一','胡寅','宋','宋诗','song-poetry','','[]','天柱峯前又一區，已聞松菊漸荒蕪。',32,'全唐诗/poet.song.108000.json','["天柱峯前又一區，已聞松菊漸荒蕪。", "近來更草歸田賦，敢以無功戀左符。"]'),
('8cc87751-dbbb-48a6-a45c-b07c656d90fb','思歸八絕  其二','胡寅','宋','宋诗','song-poetry','','[]','昨日春風花滿山，回頭秋葉錦斑斑。',32,'全唐诗/poet.song.108000.json','["昨日春風花滿山，回頭秋葉錦斑斑。", "終年竊祿慚憂寄，何事遲留久未還。"]'),
('69f6c381-a0a5-467e-8c09-ad218285a5db','思歸八絕  其三','胡寅','宋','宋诗','song-poetry','','[]','壯時嘗有意功名，不覺星星白髮生。',32,'全唐诗/poet.song.108000.json','["壯時嘗有意功名，不覺星星白髮生。", "眼亦漸花心更短，歸與猶可事農耕。"]'),
('65fdcea5-3009-475d-9659-fcb20f664f0c','思歸八絕  其四','胡寅','宋','宋诗','song-poetry','','[]','夜夢俞音出帝闈，朝來江雨已生肥。',32,'全唐诗/poet.song.108000.json','["夜夢俞音出帝闈，朝來江雨已生肥。", "扁舟載酒吹長笛，未減遼東獨鶴歸。"]'),
('6ff0ce9e-3f50-4b31-8f1c-10868f39fff6','思歸八絕  其五','胡寅','宋','宋诗','song-poetry','','[]','上聖心唯赤子矜，庶邦可以佐軍興。',32,'全唐诗/poet.song.108000.json','["上聖心唯赤子矜，庶邦可以佐軍興。", "自書政拙催科考，今古舂陵復永陵。"]'),
('96a57571-b7d7-4925-84e6-775407b6c991','思歸八絕  其六','胡寅','宋','宋诗','song-poetry','','[]','屢督平反獄易空，深慚龍斷貨誰籠。',32,'全唐诗/poet.song.108000.json','["屢督平反獄易空，深慚龍斷貨誰籠。", "後來倘念全齊寄，應築虛堂致蓋公。"]'),
('7c2e9e2d-23f4-4f37-84bb-1d6a202b84f2','思歸八絕  其七','胡寅','宋','宋诗','song-poetry','','[]','傳家素業祗圖書，永日沉涵樂有餘。',32,'全唐诗/poet.song.108000.json','["傳家素業祗圖書，永日沉涵樂有餘。", "方信此心無所著，山林鐘鼎一蘧廬。"]'),
('172c22ad-6e35-4cee-adb7-7ecf0d961fef','思歸八絕  其八','胡寅','宋','宋诗','song-poetry','','[]','畫角聲中欵乃歌，野人應未許雲和。',32,'全唐诗/poet.song.108000.json','["畫角聲中欵乃歌，野人應未許雲和。", "扣船我欲賡餘唱，更沐西風雨一蓑。"]'),
('49fe4849-1bc6-43a4-a5a7-14270f4823cd','和孫奇父','胡寅','宋','宋诗','song-poetry','','[]','攬轡丹青久更恬，掛冠高處靜尤厭。',64,'全唐诗/poet.song.108000.json','["攬轡丹青久更恬，掛冠高處靜尤厭。", "情田不是年年熟，世味安能種種廉。", "虎鼠乘時爭用舍，鳶魚適意自飛潜。", "也應及取仙舟下，同向南山看水簾。"]'),
('4b232d7a-566f-469c-b61a-8b7f80d2a80f','留別唐次山','胡寅','宋','宋诗','song-poetry','','[]','占君州土負沉痾，飽聽溪山欵乃歌。',64,'全唐诗/poet.song.108000.json','["占君州土負沉痾，飽聽溪山欵乃歌。", "季路漫傳能折獄，陽城元自拙催科。", "苟逃譴責恩波厚，更喜逢迎廩粟多。", "珍重老人分手意，論文何日再經過。"]'),
('c38e6635-e4ca-44f3-a19c-00514ee926f4','和次山贈別','胡寅','宋','宋诗','song-poetry','','[]','牧養惟聞政失中，茇棠深愧召南風。',64,'全唐诗/poet.song.108000.json','["牧養惟聞政失中，茇棠深愧召南風。", "却歸舊隠三家市，回望耆儒一畝宮。", "蕙帳我今尋怨鶴，蘋洲君復送驚鴻。", "別懷不得同杯酒，西柄居然挹大東。"]'),
('edccb130-a482-4823-83b5-934e774f5c70','留別賈閣老','胡寅','宋','宋诗','song-poetry','','[]','熙朝侍從老堂堂，和氣如春與物昌。',64,'全唐诗/poet.song.108000.json','["熙朝侍從老堂堂，和氣如春與物昌。", "未見峨冠真楚越，思逢傾蓋在瀟湘。", "放懷繾綣情何厚，憂世艱難話更長。", "果有南山求問意，芷蘭猶冀襲清芳。"]'),
('465f1594-f43d-4506-9eef-b02f3689b303','和任大夫贈別','胡寅','宋','宋诗','song-poetry','','[]','未老先衰負疾憂，敢貪榮祿尚爲州。',64,'全唐诗/poet.song.108000.json','["未老先衰負疾憂，敢貪榮祿尚爲州。", "已慚騷客能招隠，更愧疲民欲借留。", "斤斧且應存夜氣，江湖那得獻辰猷。", "新詩滿把珠璣重，歸艇全勝載石舟。"]'),
('4faa2f8d-d899-4008-b7bc-a4bb2745bb07','贈張德餘','胡寅','宋','宋诗','song-poetry','','[]','平生骯髒孰如君，破屋荒山飯煮芹。',64,'全唐诗/poet.song.108000.json','["平生骯髒孰如君，破屋荒山飯煮芹。", "不寐耿懷留落月，有時扶杖看浮雲。", "嚴平推測歸前定，原憲家風飫舊聞。", "欲挽鮒魚無氣力，須知予是故將軍。"]'),
('5d1616da-c8f1-49a5-b9d4-ce529f41d474','觀棋','胡寅','宋','宋诗','song-poetry','','[]','平地縱橫十九條，古今爭向此中消。',64,'全唐诗/poet.song.108000.json','["平地縱橫十九條，古今爭向此中消。", "乾坤二策歸皇極，愚智殊途祖帝堯。", "競勝鮮能思自活，臨機誰肯暫相饒。", "旁觀有著如當局，敢道今無國手超。"]'),
('8d018214-d7cf-4624-9ebe-a8e9ed7534b0','溪旁大楮爲水所浸將蹶有感','胡寅','宋','宋诗','song-poetry','','[]','樹引江流得自滋，不虞波浪齧根基。',32,'全唐诗/poet.song.108000.json','["樹引江流得自滋，不虞波浪齧根基。", "願言捧土加培植，長蔭行人暍暑時。"]'),
('f4139fbe-fa4e-4d94-b913-d51171a4ee3d','楊秀才書屋有墨竹一枝爲其添補數葉五絕  其一','胡寅','宋','宋诗','song-poetry','','[]','老榦枯枝傲雪霜，何人寫影向華堂。',32,'全唐诗/poet.song.108000.json','["老榦枯枝傲雪霜，何人寫影向華堂。", "爲君補綴枝頭葉，坐覺春風細細香。"]'),
('60005f3d-ec9e-4cf5-8371-660495c17a34','楊秀才書屋有墨竹一枝爲其添補數葉五絕  其二','胡寅','宋','宋诗','song-poetry','','[]','葉染青雲節抱霜，一枝聊寄墨君堂。',32,'全唐诗/poet.song.108000.json','["葉染青雲節抱霜，一枝聊寄墨君堂。", "故園根撥依然在，會見龍孫脫籜香。"]'),
('55447dc7-6ed8-484a-b92c-8404fe381116','楊秀才書屋有墨竹一枝爲其添補數葉五絕  其三','胡寅','宋','宋诗','song-poetry','','[]','穿壁扶蘇稍避霜，干霄形勢自堂堂。',32,'全唐诗/poet.song.108000.json','["穿壁扶蘇稍避霜，干霄形勢自堂堂。", "如何耿介琅玕色，也带雙鴉寶墨香。"]'),
('891ab8bd-f1a3-424b-b41b-51631a1cffb0','楊秀才書屋有墨竹一枝爲其添補數葉五絕  其四','胡寅','宋','宋诗','song-poetry','','[]','莫驚綠葉襯玄霜，更上幽人白玉堂。',32,'全唐诗/poet.song.108000.json','["莫驚綠葉襯玄霜，更上幽人白玉堂。", "爲與蒼官論久要，筆端應借遠烟香。"]'),
('ed7bfc1b-5725-4080-b187-f3a4e22a7dcc','楊秀才書屋有墨竹一枝爲其添補數葉五絕  其五','胡寅','宋','宋诗','song-poetry','','[]','掃盡鵝溪匹練霜，未知三尺映茅堂。',32,'全唐诗/poet.song.108000.json','["掃盡鵝溪匹練霜，未知三尺映茅堂。", "此君不是塵中物，何必區區較色香。"]'),
('d6d80687-433f-412d-8c1d-fbbbf6cb9dc4','和叔夏歲除','胡寅','宋','宋诗','song-poetry','','[]','新年節物推排有，舊歲光陰掃蕩無。',64,'全唐诗/poet.song.108000.json','["新年節物推排有，舊歲光陰掃蕩無。", "白髮任教裝鬢換，青春元自與心符。", "茹芝休慕商山老，舍瑟當睎魯國儒。", "三益況逢天下士，夷途從此得歸愚。"]'),
('0326c74f-8cb7-49e6-aa77-e6a1f73d5450','和叔夏水仙時見於宣卿坐上叔夏折一枝以歸八絕  其一','胡寅','宋','宋诗','song-poetry','','[]','玉質檀心翠羽衣，寒梅開後獨當時。',32,'全唐诗/poet.song.108000.json','["玉質檀心翠羽衣，寒梅開後獨當時。", "一枝折得將誰贈，想見花容出霧帷。"]'),
('5acddb9f-bc64-4eee-b5ca-682d9677836b','和叔夏水仙時見於宣卿坐上叔夏折一枝以歸八絕  其二','胡寅','宋','宋诗','song-poetry','','[]','梅後寧知花便無，不從香草寄相如。',32,'全唐诗/poet.song.108000.json','["梅後寧知花便無，不從香草寄相如。", "爲君表出風流冠，只有春蘭僅比渠。"]'),
('e00fd5e6-390c-4d74-a396-bfa749b91f76','和叔夏水仙時見於宣卿坐上叔夏折一枝以歸八絕  其三','胡寅','宋','宋诗','song-poetry','','[]','葉是青霞剪作衣，花如靜女不爭時。',32,'全唐诗/poet.song.108000.json','["葉是青霞剪作衣，花如靜女不爭時。", "豈應更浥薔薇露，撩得窺園不下帷。"]'),
('313df0e1-802e-43a9-8f55-027162e2a94b','和叔夏水仙時見於宣卿坐上叔夏折一枝以歸八絕  其四','胡寅','宋','宋诗','song-poetry','','[]','灑然仙意指虛無，羅襪凌波定不如。',32,'全唐诗/poet.song.108000.json','["灑然仙意指虛無，羅襪凌波定不如。", "織女未忘銀漢會，空煩濁水映清渠。"]'),
('b57df6a8-2046-4ed8-b706-2557802fe238','和叔夏水仙時見於宣卿坐上叔夏折一枝以歸八絕  其五','胡寅','宋','宋诗','song-poetry','','[]','蓀橈蘭楫芰荷衣，嫋娜愁予二八時。',32,'全唐诗/poet.song.108000.json','["蓀橈蘭楫芰荷衣，嫋娜愁予二八時。", "嫁與湘君捐袂褋，玉搔頭映白羅帷。"]'),
('678f6a29-0d71-4f15-b18d-e041701db0d2','和叔夏水仙時見於宣卿坐上叔夏折一枝以歸八絕  其六','胡寅','宋','宋诗','song-poetry','','[]','海岸仙人絕代無，清揚白日坐如如。',32,'全唐诗/poet.song.108000.json','["海岸仙人絕代無，清揚白日坐如如。", "若從妙色光香覓，須信先生未識渠。"]'),
('2d6f8c5e-2271-4b51-8634-142fea0c9735','和叔夏水仙時見於宣卿坐上叔夏折一枝以歸八絕  其七','胡寅','宋','宋诗','song-poetry','','[]','萱草盈階是綠衣，玉簪陪檻敢同時。',32,'全唐诗/poet.song.108000.json','["萱草盈階是綠衣，玉簪陪檻敢同時。", "更餘濺水無聊頼，都向仙姿共一帷。"]'),
('4efb92fb-2fbb-4b57-8507-cd577ec33576','和叔夏水仙時見於宣卿坐上叔夏折一枝以歸八絕  其八','胡寅','宋','宋诗','song-poetry','','[]','爲花求偶豈全無，梅與山礬姊弟如。',32,'全唐诗/poet.song.108000.json','["爲花求偶豈全無，梅與山礬姊弟如。", "我已冥心薌澤觀，何須江水對軒渠。"]'),
('b82b8d85-c4b3-4269-a9cb-ee7c26a98b3c','寄唐堅伯','胡寅','宋','宋诗','song-poetry','','[]','君詩平昔思如泉，無事尋醫孰使然。',64,'全唐诗/poet.song.108000.json','["君詩平昔思如泉，無事尋醫孰使然。", "禮尚往來思報玖，情深汲引屢拋甎。", "豈能遽造忘言地，應有沉吟得意聯。", "待聽鐘聲撼清夜，明朝紙貴萬人傳。"]'),
('b1ab12a4-2c4c-47fa-97d7-e0b2ee70a8f1','遊元陽觀','胡寅','宋','宋诗','song-poetry','','[]','矯首元陽觀，崢嶸度十年。',144,'全唐诗/poet.song.108000.json','["矯首元陽觀，崢嶸度十年。", "忽逢塵外客，因訪洞中仙。", "橫躡脩蛇路，低看破衲田。", "縈紆篁竹嶺，窈窕碧松川。", "撫石齋壇古，圍棋燒劫遷。", "諒無翻榼術，安得遠庖烟。", "擗盡蒼麟脯，彈餘別鶴絃。", "晴香烘拆蕊，暝色繞歸鞭。", "太白浮橋上，孤燈炫馬前。", "黄冠紛雨散，紫蓋杳雲連。", "鳥爪休爬背，鸞驂漫拍肩。", "子真隨處隠，何必大羅天。"]'),
('151b14c7-de01-4a82-8b27-d9d80fcb47e1','早梅','胡寅','宋','宋诗','song-poetry','','[]','何事悲摇落，空林有早春。',72,'全唐诗/poet.song.108000.json','["何事悲摇落，空林有早春。", "光輝一笑粲，領畧萬花新。", "看去疑山雪，攀來效席珍。", "妙香風送遠，秀影月傳真。", "肌冷冰難斲，妝初粉未勻。", "商量開瘦蕊，剩得占芳辰。"]'),
('ec6e23b4-567a-4847-b3af-b023d7eac16c','和堅伯梅六題一孤芳二山間三雪中四水邊五月下六雨後每題二絕禁犯本題及風花雪月天粉玉香山水字十二絕  其一','胡寅','宋','宋诗','song-poetry','','[]','折綿威力漫相侵，根暖怡然獨秀林。',32,'全唐诗/poet.song.108000.json','["折綿威力漫相侵，根暖怡然獨秀林。", "萬紫千紅非我對，爲渠無有歲寒心。"]'),
('bd603233-0b84-4831-bd62-2dacc6464dc0','和堅伯梅六題一孤芳二山間三雪中四水邊五月下六雨後每題二絕禁犯本題及風花雪月天粉玉香山水字十二絕  其二','胡寅','宋','宋诗','song-poetry','','[]','間錯浮筠冷更嚴，長松低顧拂蒼髯。',32,'全唐诗/poet.song.108000.json','["間錯浮筠冷更嚴，長松低顧拂蒼髯。", "清標總是君朋侶，桃李相望幾陛廉。"]'),
('9377c0f6-3301-42b8-bdcf-bc917a29773f','和堅伯梅六題一孤芳二山間三雪中四水邊五月下六雨後每題二絕禁犯本題及風花雪月天粉玉香山水字十二絕  其三','胡寅','宋','宋诗','song-poetry','','[]','欣逢冷艷破冬溫，更待飛霙滌晝昏。',32,'全唐诗/poet.song.108000.json','["欣逢冷艷破冬溫，更待飛霙滌晝昏。", "剩欲約君移酒處，小橋斜過竹邊門。"]'),
('f45fd340-f96b-4498-a42b-54bec566004a','和堅伯梅六題一孤芳二山間三雪中四水邊五月下六雨後每題二絕禁犯本題及風花雪月天粉玉香山水字十二絕  其四','胡寅','宋','宋诗','song-poetry','','[]','未開疎蕊著詩催，依約蜂聲欲隠雷。',32,'全唐诗/poet.song.108000.json','["未開疎蕊著詩催，依約蜂聲欲隠雷。", "姑射坐中親綽約，嶺頭空有路縈迴。"]'),
('920195fa-a550-4302-833b-513634a5b678','和堅伯梅六題一孤芳二山間三雪中四水邊五月下六雨後每題二絕禁犯本題及風花雪月天粉玉香山水字十二絕  其五','胡寅','宋','宋诗','song-poetry','','[]','六出誰人剪刻成，侵凌飄灑正縱橫。',32,'全唐诗/poet.song.108000.json','["六出誰人剪刻成，侵凌飄灑正縱橫。", "仙姿不頼相黏綴，浣盡浮埃艷更明。"]'),
('fcee30b2-76c8-4434-8a99-5333fbfd646b','和堅伯梅六題一孤芳二山間三雪中四水邊五月下六雨後每題二絕禁犯本題及風花雪月天粉玉香山水字十二絕  其六','胡寅','宋','宋诗','song-poetry','','[]','潑落瓊華作雨濛，迷離高樹映寒空。',32,'全唐诗/poet.song.108000.json','["潑落瓊華作雨濛，迷離高樹映寒空。", "莫尋雲外瑶臺侶，且對尊前鶴髮翁。"]'),
('2e2c453e-a7a8-44f0-a65c-c3473aca3041','和堅伯梅六題一孤芳二山間三雪中四水邊五月下六雨後每題二絕禁犯本題及風花雪月天粉玉香山水字十二絕  其七','胡寅','宋','宋诗','song-poetry','','[]','東閣題詩得緒餘，溪頭千樹繞幽居。',32,'全唐诗/poet.song.108000.json','["東閣題詩得緒餘，溪頭千樹繞幽居。", "來禽青李曾何算，底事猶傳逸少書。"]'),
('b3c4e42a-ab14-4703-9130-20b4af87e323','和堅伯梅六題一孤芳二山間三雪中四水邊五月下六雨後每題二絕禁犯本題及風花雪月天粉玉香山水字十二絕  其八','胡寅','宋','宋诗','song-poetry','','[]','清溪練練影全呈，絕勝斜梢出竹橫。',32,'全唐诗/poet.song.108000.json','["清溪練練影全呈，絕勝斜梢出竹橫。", "便是霓裳臨曉鏡，搔頭初插未行行。"]'),
('e065ccd0-a0c1-4167-939d-b0b8e729dd9a','和堅伯梅六題一孤芳二山間三雪中四水邊五月下六雨後每題二絕禁犯本題及風花雪月天粉玉香山水字十二絕  其九','胡寅','宋','宋诗','song-poetry','','[]','意態衝寒不自持，桂華相伴亦多時。',32,'全唐诗/poet.song.108000.json','["意態衝寒不自持，桂華相伴亦多時。", "未須細覩青春面，且看扶疎寫影宜。"]'),
('8a5a9973-a121-452f-a34b-d12234bc9af0','和堅伯梅六題一孤芳二山間三雪中四水邊五月下六雨後每題二絕禁犯本題及風花雪月天粉玉香山水字十二絕  其一○','胡寅','宋','宋诗','song-poetry','','[]','疇昔黄金入漢宮，只今嬌額爲誰容。',32,'全唐诗/poet.song.108000.json','["疇昔黄金入漢宮，只今嬌額爲誰容。", "嫦娥也覓孤棲伴，併照巫陽十二峯。"]'),
('ac702396-11cf-4708-8958-b36a0c967f81','和堅伯梅六題一孤芳二山間三雪中四水邊五月下六雨後每題二絕禁犯本題及風花雪月天粉玉香山水字十二絕  其一一','胡寅','宋','宋诗','song-poetry','','[]','若道殘冬不是春，洗妝那得一枝新。',32,'全唐诗/poet.song.108000.json','["若道殘冬不是春，洗妝那得一枝新。", "杏園芳灑真顦顇，爭似而今斂路塵。"]'),
('26f135ba-35da-455b-9b30-7a78ee897a43','和堅伯梅六題一孤芳二山間三雪中四水邊五月下六雨後每題二絕禁犯本題及風花雪月天粉玉香山水字十二絕  其一二','胡寅','宋','宋诗','song-poetry','','[]','博山湯氣馥籠寒，裛盡啼痕作醉歡。',32,'全唐诗/poet.song.108000.json','["博山湯氣馥籠寒，裛盡啼痕作醉歡。", "賞去角巾從小墊，接䍦何惜一生酸。"]'),
('6eae8493-1b19-4bd1-a34d-f5c283c5581d','馬擴作亭湘江之上來求名以飲江名之','胡寅','宋','宋诗','song-poetry','','[]','疇昔縱橫虎豹韜，旆旌悠緬馬蕭蕭。',64,'全唐诗/poet.song.108000.json','["疇昔縱橫虎豹韜，旆旌悠緬馬蕭蕭。", "飽聞國士無雙譽，今見將軍第五橋。", "秀句自堪消永日，壯懷仍復在中朝。", "樓前拍拍湘江綠，安得從公舉一瓢。"]'),
('be7b57c4-21e7-4333-9537-8d441f17fa56','中秋雨','胡寅','宋','宋诗','song-poetry','','[]','待賞今宵定幾人，豈應於畢遽相親。',64,'全唐诗/poet.song.108000.json','["待賞今宵定幾人，豈應於畢遽相親。", "坐令華燭風頭捲，却喜枯簷雨脚勻。", "拱璧何妨藏韞櫝，湛銅那得蔽遊塵。", "明年記取瞻銀闕，萬里秋光景更新。"]'),
('b78bfc01-d925-4c0a-a732-02760bb72228','憶端子三首  其一','胡寅','宋','宋诗','song-poetry','','[]','當年夢賚見清伊，勁氣全歸目與眉。',64,'全唐诗/poet.song.108000.json','["當年夢賚見清伊，勁氣全歸目與眉。", "髫齓已能莊語笑，嬉遊元只在書詩。", "青松不及明堂用，黄壤空餘白玉悲。", "精爽有無何處去，豈能知我痛心時。"]'),
('888f6aae-5db8-4a35-a0ec-050d8fcc3ea5','憶端子三首  其二','胡寅','宋','宋诗','song-poetry','','[]','不知埋玉已經年，忽值生朝倍黯然。',64,'全唐诗/poet.song.108000.json','["不知埋玉已經年，忽值生朝倍黯然。", "空向夢魂期遠大，謬於方技覓安全。", "翩翩翰墨留身後，炯炯精神在目前。", "桂折蘭摧千古恨，淚痕那得到黄泉。"]'),
('5d24d7ae-5d2b-44bf-85b7-c7a17d7ed832','憶端子三首  其三','胡寅','宋','宋诗','song-poetry','','[]','不見佳兒正一年，鍾情難遣故依然。',64,'全唐诗/poet.song.108000.json','["不見佳兒正一年，鍾情難遣故依然。", "久知朝菌同年壽，終惜童烏早棄捐。", "篋裏詩書迷白日，堂中珠玉墮黄泉。", "汝翁去此知多少，安得忘懷未死前。"]'),
('81378d88-e535-4e3f-902d-144d647dd176','又題草衣岩','胡寅','宋','宋诗','song-poetry','','[]','携手童烏三尺强，已知經術勝文章。',32,'全唐诗/poet.song.108000.json','["携手童烏三尺强，已知經術勝文章。", "可憐不見凌雲日，迸灑西風泪幾行。"]'),
