('55df8701-0caa-4b31-a7fd-8b94f02d056f','初冬快晴陪宣卿叔夏遊石頭菴過三生藏窮深極峻遂登上封却下福嚴最愛廓然亭靜憩久之乘興入後洞置酒雲莊榭徘徊方廣閣山行崎嶇不可以馬雖筍輿傲兀小勞尚勝騎從之煩也既歸山前之翌日復會於堅伯兄小閣同安趙澗看北山餘雪披雲映日翠瑩瓏葱殆難模狀因訪季父廟令歡飲而罷集記所見成十五絕  其一五','胡寅','宋','宋诗','song-poetry','','[]','鞭笞鸞鳳地行仙，變化鵾鵬背負天。',32,'全唐诗/poet.song.108000.json','["鞭笞鸞鳳地行仙，變化鵾鵬背負天。", "他日寓言真十九，只今功行已三千。"]'),
('61f9f0de-4df4-47bf-a5c3-ddd4f0d26370','題叔夏樂谷','胡寅','宋','宋诗','song-poetry','','[]','君知至樂本難名，何事猶令谷應聲。',64,'全唐诗/poet.song.108000.json','["君知至樂本難名，何事猶令谷應聲。", "植杖自鋤園草綠，掛瓢時浥澗泉清。", "了無歌吹娛賓從，只有詩書養性情。", "却恐仁人尚蒿目，又須憑酒破愁城。"]'),
('57c743c8-c046-4fa4-82bb-1d797ee2d05f','和叔夏田舍三絕  其一','胡寅','宋','宋诗','song-poetry','','[]','尚恨山前塵土侵，去耕山後白雲深。',32,'全唐诗/poet.song.108000.json','["尚恨山前塵土侵，去耕山後白雲深。", "下泉不使苞稂秀，夫子寧忘濟物心。"]'),
('ca5e3bc3-31f9-4f86-9a25-a74f27c76546','和叔夏田舍三絕  其二','胡寅','宋','宋诗','song-poetry','','[]','作堨辛勤雨更遲，桔槔誰語漢陰知。',32,'全唐诗/poet.song.108000.json','["作堨辛勤雨更遲，桔槔誰語漢陰知。", "不嫌機事侵純白，一日何妨灌百畦。"]'),
('00c62566-4c4c-4a18-9663-97403988b646','和叔夏田舍三絕  其三','胡寅','宋','宋诗','song-poetry','','[]','日望雲霓手揠苗，何時能和快哉謠。',32,'全唐诗/poet.song.108000.json','["日望雲霓手揠苗，何時能和快哉謠。", "不如且種陶公柳，贏得長饑舞細腰。"]'),
('572e2d9b-0b50-48c5-9ffb-0a38984745ba','又和松碧軒三絕  其一','胡寅','宋','宋诗','song-poetry','','[]','欣此幽居惜未深，時搴芳秀浣塵襟。',32,'全唐诗/poet.song.108000.json','["欣此幽居惜未深，時搴芳秀浣塵襟。", "棟梁自是君材器，鐵石空餘我寸心。"]'),
('35c12323-8d04-4a80-ac90-d9230db58e57','又和松碧軒三絕  其二','胡寅','宋','宋诗','song-poetry','','[]','聞說鋤耰手自持，力耕初不願天知。',32,'全唐诗/poet.song.108000.json','["聞說鋤耰手自持，力耕初不願天知。", "却防有客携壺到，杞菊應添一兩畦。"]'),
('65eac066-f8e7-4060-b0cf-d37a81859419','又和松碧軒三絕  其三','胡寅','宋','宋诗','song-poetry','','[]','新陂剩水沃良苗，想見當時相杵謠。',32,'全唐诗/poet.song.108000.json','["新陂剩水沃良苗，想見當時相杵謠。", "尚有荒餘須快犢，何須塌具更懸腰。"]'),
('1f9d4547-75d6-4e8d-853d-e23e583a5fb7','和奇父壁間留題','胡寅','宋','宋诗','song-poetry','','[]','竹杖輕堅野服寬，歲寒應得見蒼官。',32,'全唐诗/poet.song.108000.json','["竹杖輕堅野服寬，歲寒應得見蒼官。", "世情無限殘霜葉，昨日青青今日丹。"]'),
('a45681a5-df97-4ba2-9808-3c885e35860e','冬至前半月赴季父梅花之集與韓蒲向憲唐幹諸人唱和十首  其一','胡寅','宋','宋诗','song-poetry','','[]','今年共嘆物華遲，春信孤根獨早知。',64,'全唐诗/poet.song.108000.json','["今年共嘆物華遲，春信孤根獨早知。", "未到書雲十五日，已看綴雪兩三枝。", "寒香宛是臨風好，冷艷還於照水宜。", "莫待江頭千樹暗，只今携酒正當時。"]'),
('cdf0197c-154c-4945-8b4c-2aa953cc52e1','冬至前半月赴季父梅花之集與韓蒲向憲唐幹諸人唱和十首  其二','胡寅','宋','宋诗','song-poetry','','[]','天寒袖薄竹光侵，溪轉橋橫草閣深。',64,'全唐诗/poet.song.108000.json','["天寒袖薄竹光侵，溪轉橋橫草閣深。", "妃子定應來月窟，寧馨誰說是瑶林。", "顔開玉色春光滿，香動冰姿冷不禁。", "漫道江南好詩句，只誇紅蠟與黄金。"]'),
('94ece540-6d47-495f-a9e0-1fb73c4a8ed6','冬至前半月赴季父梅花之集與韓蒲向憲唐幹諸人唱和十首  其三','胡寅','宋','宋诗','song-poetry','','[]','南人慣識賞來遲，北客相逢勝舊知。',64,'全唐诗/poet.song.108000.json','["南人慣識賞來遲，北客相逢勝舊知。", "何必粉圖爭畫樣，更勞餳糝亂粘枝。", "天饒絕品千花外，人換新籹一笑宜。", "佳句定非橫笛比，溫存疎蘂半開時。"]'),
('1f150ac0-d5ae-41ab-b404-467500cc6c6c','冬至前半月赴季父梅花之集與韓蒲向憲唐幹諸人唱和十首  其四','胡寅','宋','宋诗','song-poetry','','[]','不管霜威日夜侵，肯教飛蝶到深深。',64,'全唐诗/poet.song.108000.json','["不管霜威日夜侵，肯教飛蝶到深深。", "六花漫爾呈三白，一萼居然映萬林。", "軟玉香冰空自惱，芳心愁思遣誰禁。", "市橋江路風流別，枉費千顰買笑金。"]'),
('6aa73083-b0db-44d5-81c2-6b0c7433ef37','冬至前半月赴季父梅花之集與韓蒲向憲唐幹諸人唱和十首  其五','胡寅','宋','宋诗','song-poetry','','[]','追陪强韻思猶遲，寄語疏林恐未知。',64,'全唐诗/poet.song.108000.json','["追陪强韻思猶遲，寄語疏林恐未知。", "酒半尋香攀近蘂，夜分然燭照高枝。", "莫愁花浪翻天遠，且看鮫鮹剪玉宜。", "冠冕衆芳歸獨步，固應桃李不同時。"]'),
('9d42cc25-9d34-47c7-808a-7df8f80c5647','冬至前半月赴季父梅花之集與韓蒲向憲唐幹諸人唱和十首  其六','胡寅','宋','宋诗','song-poetry','','[]','冰圍風戰雪交侵，方是春工屬意深。',64,'全唐诗/poet.song.108000.json','["冰圍風戰雪交侵，方是春工屬意深。", "綠萼已開栽樂谷，一枝那得寄薌林。", "依然照水如相媚，粲者巡簷也未禁。", "香白檀心誰解賦，頼公戛玉更摐金。"]'),
('cc0cf3df-37ad-4e72-9406-42667d40b8ed','冬至前半月赴季父梅花之集與韓蒲向憲唐幹諸人唱和十首  其七','胡寅','宋','宋诗','song-poetry','','[]','好花不恨好詩遲，國色須蒙國士知。',64,'全唐诗/poet.song.108000.json','["好花不恨好詩遲，國色須蒙國士知。", "漫比玉容歌璧月，空將鷺羽鬭瓊枝。", "旁無綽約天仙對，中有甘酸鼎味宜。", "聞說北枝開亦徧，一尊相屬定何時。"]'),
('a579b4fb-48bb-4a73-8f31-4da5190e282a','冬至前半月赴季父梅花之集與韓蒲向憲唐幹諸人唱和十首  其八','胡寅','宋','宋诗','song-poetry','','[]','愛花從使二毛侵，嘆賞孤高與靚深。',64,'全唐诗/poet.song.108000.json','["愛花從使二毛侵，嘆賞孤高與靚深。", "調護臘前珠結蘂，蕩摇年後玉成林。", "莫教三弄飄飄落，剩把千篇得得禁。", "姑射肌膚最溫潤，夜眠無用辟寒金。"]'),
('56f6aa3b-c8f9-45e4-a2e0-21842fce15a7','冬至前半月赴季父梅花之集與韓蒲向憲唐幹諸人唱和十首  其九','胡寅','宋','宋诗','song-poetry','','[]','的皪凝情開自遲，風亭微馥許君知。',64,'全唐诗/poet.song.108000.json','["的皪凝情開自遲，風亭微馥許君知。", "直須藉草傾松葉，絕勝登樓唱竹枝。", "韓壽香囊難取似，何郎粉面且隨宜。", "豈知萬顆垂黄實，擢秀前村夜雪時。"]'),
('b389e695-f471-4a95-a281-3444a21c89e1','冬至前半月赴季父梅花之集與韓蒲向憲唐幹諸人唱和十首  其一○','胡寅','宋','宋诗','song-poetry','','[]','不辭開後苦寒侵，爲與騷人托契深。',64,'全唐诗/poet.song.108000.json','["不辭開後苦寒侵，爲與騷人托契深。", "可但風光回歲律，更分華色掞儒林。", "欲歌白雪詞難和，試挽幽香力尚禁。", "等是美名無玷染，臘梅何事色如金。"]'),
('fd82cde3-8783-4fad-b629-13e20041fc47','和彥達至日木冰','胡寅','宋','宋诗','song-poetry','','[]','千林木稼苦低垂，惟有長松不受欺。',64,'全唐诗/poet.song.108000.json','["千林木稼苦低垂，惟有長松不受欺。", "蘭雪方懷蕭慤句，河冰還讀鮑昭詩。", "卧聞寫竹驚殘夢，戲折寒枝調小兒。", "寄語達官不須怕，勉旃戈甲渡淮師。"]'),
('052890e6-e99a-490c-be81-6f7eefb52bdd','寧鄉有感與仁仲彥達同行','胡寅','宋','宋诗','song-poetry','','[]','太和薰宇宙，王旅不親征。',48,'全唐诗/poet.song.108000.json','["太和薰宇宙，王旅不親征。", "雁北同兄弟，鶑遷得友生。", "正便春入望，莫厭雨稽程。", "何限山花發，遥看爲擬名。"]'),
('001209f0-489c-4218-b2d4-35e284b828fa','過益陽','胡寅','宋','宋诗','song-poetry','','[]','僑寄家連楚，歸遊嶽背衡。',48,'全唐诗/poet.song.108000.json','["僑寄家連楚，歸遊嶽背衡。", "川原漸舊國，鮭菜愜平生。", "淮海風難定，江湖浪豈平。", "春融一杯酒，下馬且同傾。"]'),
('0953fef3-c08d-484f-ace4-4c2803d93816','和仁仲過濱江','胡寅','宋','宋诗','song-poetry','','[]','溈山未暇往，石磴上雲端。',48,'全唐诗/poet.song.108000.json','["溈山未暇往，石磴上雲端。", "初識清修路，遥憐菡萏寒。", "野寬耕僅有，民殄政猶殘。", "總使林泉穩，那能寢飯安。"]'),
('5a49a7ff-9849-47d1-9ece-4fdbe2b9bc4f','遇雨晚宿和彥達','胡寅','宋','宋诗','song-poetry','','[]','天以春歸野，雲將雨暗山。',48,'全唐诗/poet.song.108000.json','["天以春歸野，雲將雨暗山。", "三人行甚樂，五字句何艱。", "每喜詩償債，還須酒破顔。", "禽聲接芳樹，和氣亦關關。"]'),
('aa9fab4b-769e-4347-80ab-20f0bbcc510e','出益陽和仁仲','胡寅','宋','宋诗','song-poetry','','[]','兀夢三山馬，投鞭四壁家。',48,'全唐诗/poet.song.108000.json','["兀夢三山馬，投鞭四壁家。", "暮天雲潑墨，春樹雪添花。", "遊宦初無補，歸休漸有涯。", "渺然江海興，篷笠釣烟沙。"]'),
('25ebc4a2-3d5c-45bb-8e10-556f1fec8032','夜大風雪次日快晴','胡寅','宋','宋诗','song-poetry','','[]','造物非難料，寒溫本一家。',48,'全唐诗/poet.song.108000.json','["造物非難料，寒溫本一家。", "衝風來雨雪，暖日放鶑花。", "行矣春方嫩，悠哉興未涯。", "蘆蒿媚烟渚，荻筍破江沙。"]'),
('ba439d4f-1e27-4e4a-90b4-d23c71bd4633','過鼎澧','胡寅','宋','宋诗','song-poetry','','[]','沅澧春風拂馬鞭，客愁何事四無邊。',64,'全唐诗/poet.song.108000.json','["沅澧春風拂馬鞭，客愁何事四無邊。", "於今榛棘三州地，自昔坻京百姓天。", "安得鳴雞連比屋，空餘歸雁落平川。", "一觴莫酹懷沙魄，且對桃紅李白傳。"]'),
('696fc1d5-e728-476a-a684-a1db68a2573f','和仁仲過五溪','胡寅','宋','宋诗','song-poetry','','[]','沅水千年非舊波，英風元自振關河。',64,'全唐诗/poet.song.108000.json','["沅水千年非舊波，英風元自振關河。", "本懷國士知心早，豈念檉函挾恨多。", "龜固有神寧豫罔，鴻雖高舉畏虞羅。", "椒蘭從古能如此，何有沉湘作九歌。"]'),
('f8e23aac-35a5-438d-b96f-6a3d20fcd64b','和彥達至公安','胡寅','宋','宋诗','song-poetry','','[]','未識南陽有卧龍，阿瞞先已畏南風。',64,'全唐诗/poet.song.108000.json','["未識南陽有卧龍，阿瞞先已畏南風。", "如何赤壁分三國，不向神州决兩雄。", "營峽晚圖千慮失，截江初意一丸封。", "蒼茫漢日西南落，莫道無由却復中。"]'),
('bfa6145c-5e32-4355-8d81-92bc6375fc94','和仁仲至荆門','胡寅','宋','宋诗','song-poetry','','[]','虞帝當年闢四門，三苗那更蠢迷昏。',64,'全唐诗/poet.song.108000.json','["虞帝當年闢四門，三苗那更蠢迷昏。", "茫茫舊楚祗芳草，處處朱樓空斷垣。", "不願耦耕招素隠，要看良耜接深村。", "韓公守戒誰能用，虎豹難憑折柳樊。"]'),
('0a3e7165-a8c3-4ea1-b4d8-33e7e964dfab','清明風雪小酌莊舍示黎才翁','胡寅','宋','宋诗','song-poetry','','[]','月壓梨花墜，風扶柳絮新。',96,'全唐诗/poet.song.108000.json','["月壓梨花墜，風扶柳絮新。", "故園寒食路，回首踏青人。", "萬竅方號籟，千山忽湧銀。", "擁衾聽窈眇，舉盞寄經綸。", "浩蕩寰中意，逍遥物外身。", "賡歌咸當律，謔浪亦淘真。", "又理沙邊棹，將浮雪後春。", "蘭亭非達者，空嘆迹成陳。"]'),
('ba7c9763-4b00-4a1f-829b-ddacc96a5915','拜大父中大塋和彥達','胡寅','宋','宋诗','song-poetry','','[]','仙翁真氣與神遊，宰樹參天也不樛。',32,'全唐诗/poet.song.108000.json','["仙翁真氣與神遊，宰樹參天也不樛。", "悵念青春家塾日，共聞規訓有源流。"]'),
('ed19da32-bf8d-4a80-993f-cc9fca7ecd90','和彥達過先公舊居有感','胡寅','宋','宋诗','song-poetry','','[]','論文斆學兩髫年，訪舊同來雪上顛。',64,'全唐诗/poet.song.108000.json','["論文斆學兩髫年，訪舊同來雪上顛。", "我步鯉庭心欲折，公登龍坂足何緣。", "後凋尚喜無雙士，不韡真慚大少連。", "桂楫又浮湘水去，家山回首共悽然。"]'),
('9970fa5f-b243-465b-8311-6218056e8f88','和玉泉達老餉笋','胡寅','宋','宋诗','song-poetry','','[]','籜龍孤介亦駢闐，不比花嫣與柳眠。',64,'全唐诗/poet.song.108000.json','["籜龍孤介亦駢闐，不比花嫣與柳眠。", "雪裏頓超千佛地，風來應上四禪天。", "飽參玉版頭頭是，秀出薌林箇箇圓。", "知我遠庖薇蕨少，倒籠登俎共便娟。"]'),
('3788c940-a9f1-4a1c-b7df-414341348a08','留別王元治師中譚純益三首  其一','胡寅','宋','宋诗','song-poetry','','[]','兒釣童遊幾夢思，春風千里恨歸遲。',64,'全唐诗/poet.song.108000.json','["兒釣童遊幾夢思，春風千里恨歸遲。", "君今舊隠治三徑，我尚他州寄一枝。", "載酒猶慚來問字，對花深欲共論詩。", "不堪又聽陽關曲，想見酴醿噴雪時。"]'),
('aef428bd-09f5-4db7-badc-0ac66f4198a5','留別王元治師中譚純益三首  其二','胡寅','宋','宋诗','song-poetry','','[]','幸不當官也去思，春江風日正舒遲。',64,'全唐诗/poet.song.108000.json','["幸不當官也去思，春江風日正舒遲。", "少留畫鷁呼桃葉，捲盡紅螺看柘枝。", "三爵勸酬三益友，四并除掃四愁詩。", "渭城景色朝朝是，不用丹青李伯時。"]'),
('88e9eec4-2c41-460d-bd8c-e78e538275d6','留別王元治師中譚純益三首  其三','胡寅','宋','宋诗','song-poetry','','[]','欲步夷途盍近思，行尋捷徑却成遲。',64,'全唐诗/poet.song.108000.json','["欲步夷途盍近思，行尋捷徑却成遲。", "大弨不必穿楊葉，古樂何曾唱竹枝。", "須信孔門無用賦，也知高叟漫爲詩。", "功名易立書難讀，努力當乘少壯時。"]'),
('9241d5ca-50db-4fcd-bfd6-4cafbb082e78','酬師中見和','胡寅','宋','宋诗','song-poetry','','[]','亂定誰人不土思，如何鄉井尚陵遲。',64,'全唐诗/poet.song.108000.json','["亂定誰人不土思，如何鄉井尚陵遲。", "莫嗟釣艇重湖隔，終待書堂一木枝。", "彼美獨高鸚鵡賦，孔懷均契鶺鴒詩。", "願君再起臨流閣，約我花汀柳岸時。"]'),
('a182748b-ed57-4368-b6dc-27974d234ea8','酬任正叔見和','胡寅','宋','宋诗','song-poetry','','[]','莫嗤文子動三思，我亦今來去魯遲。',64,'全唐诗/poet.song.108000.json','["莫嗤文子動三思，我亦今來去魯遲。", "潦草荷鋤開菊徑，殷勤持酒對花枝。", "韋編舊服精三易，絳帳新開講四詩。", "把釣不須嗟歲久，大魚端有上鈎時。"]'),
('10e26290-625d-4e06-b38c-7fafaa155448','岳陽樓雜詠十二絕  其一','胡寅','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','沅澧澬湘此並行，漲流洄薄又東傾。',32,'全唐诗/poet.song.108000.json','["沅澧澬湘此並行，漲流洄薄又東傾。", "西南或與天爲際，禹貢如何不記名。"]'),
('649a5920-c7e1-400d-89f8-1d2a2ec151d3','岳陽樓雜詠十二絕  其二','胡寅','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','朱樓深穩可憑欄，萬頃波光一目間。',32,'全唐诗/poet.song.108000.json','["朱樓深穩可憑欄，萬頃波光一目間。", "不見驚鴻偏鳳髻，空餘天鑑寫雲鬟。"]'),
('ed9d79a6-b6a7-4483-8bcb-804b12f52596','岳陽樓雜詠十二絕  其三','胡寅','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','黄帝鈞天曲未終，至今烟浪舞魚龍。',32,'全唐诗/poet.song.108000.json','["黄帝鈞天曲未終，至今烟浪舞魚龍。", "臨風更欲吹長笛，摇蕩波心碧玉峯。"]'),
('793f5051-7b5c-4d28-8736-aeaffc3a4ef0','岳陽樓雜詠十二絕  其四','胡寅','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','祖龍遊豫亦荒哉，風折雲颿促駕迴。',32,'全唐诗/poet.song.108000.json','["祖龍遊豫亦荒哉，風折雲颿促駕迴。", "一怒赭山何所損，依然蒼翠似蓬萊。"]'),
('638cb443-5232-4945-b084-70debc5d2da6','岳陽樓雜詠十二絕  其五','胡寅','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','虜馬超江又飲湖，湖中今有卧龍無。',32,'全唐诗/poet.song.108000.json','["虜馬超江又飲湖，湖中今有卧龍無。", "青蛇袖手將何用，漫說飛仙膽氣粗。"]'),
('69671f3e-9727-406a-ab96-123693538a4d','岳陽樓雜詠十二絕  其六','胡寅','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','汨潭桂酒奠三閭，尚想夷猶泛五潴。',32,'全唐诗/poet.song.108000.json','["汨潭桂酒奠三閭，尚想夷猶泛五潴。", "進退存亡皆有義，懷沙處死是何如。"]'),
('95692be9-284d-4dfb-8bd4-82551a4d1e1d','岳陽樓雜詠十二絕  其七','胡寅','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','玄德驍雄世所知，蛟龍寧肯在汙池。',32,'全唐诗/poet.song.108000.json','["玄德驍雄世所知，蛟龍寧肯在汙池。", "館于貳室謀何陋，借與全荆意自奇。"]'),
('29dc38ba-0a22-460e-97a2-162046cffa05','岳陽樓雜詠十二絕  其八','胡寅','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','風烈言言滕子京，豈於荒怪未全明。',32,'全唐诗/poet.song.108000.json','["風烈言言滕子京，豈於荒怪未全明。", "尼姑狡獪遥相幻，雷電那知有姓名。"]'),
('c464fcef-32bc-4e8a-9946-20daa92b5654','岳陽樓雜詠十二絕  其九','胡寅','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','有時風浪戰城西，何啻漁陽萬鼓鼙。',32,'全唐诗/poet.song.108000.json','["有時風浪戰城西，何啻漁陽萬鼓鼙。", "狎水蚩蚩忘墊溺，誰人能續偃虹堤。"]'),
('9f82cee1-c306-46b2-82fd-4dda2e7c14cb','岳陽樓雜詠十二絕  其一○','胡寅','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','大手文章浪得名，佐王功業亦何成。',32,'全唐诗/poet.song.108000.json','["大手文章浪得名，佐王功業亦何成。", "獨餘不證元忠事，努力還因宋廣平。"]'),
('8c40d375-1979-425f-a772-51b53cc35b11','岳陽樓雜詠十二絕  其一一','胡寅','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','李杜詞源廣更深，數篇春漲渺雲岑。',32,'全唐诗/poet.song.108000.json','["李杜詞源廣更深，數篇春漲渺雲岑。", "爭如一首修樓記，妙寫仁人出處心。"]'),
('76fbb167-6172-493d-8d5e-42d40ca23ea1','岳陽樓雜詠十二絕  其一二','胡寅','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','范公才具濟川舟，翰墨居然第一流。',32,'全唐诗/poet.song.108000.json','["范公才具濟川舟，翰墨居然第一流。", "每向遺文窺遠意，願言憂樂繼前修。"]'),
('fa439cbb-3492-4730-8526-fc22e3e77c0d','泝江濡滯','胡寅','宋','宋诗','song-poetry','','[]','何處難忘酒，舟行不進時。',48,'全唐诗/poet.song.108000.json','["何處難忘酒，舟行不進時。", "漫流迷縴道，數日誚篙師。", "近樹久猶見，遠山都未移。", "此時無一盞，吾意亦紓遲。"]'),
('bf9948a2-9500-443e-9478-44c7b0877adb','和仁仲舟中三絕  其一','胡寅','宋','宋诗','song-poetry','','[]','異代紛爭戰伐多，樓船贏負倚蒼波。',32,'全唐诗/poet.song.108000.json','["異代紛爭戰伐多，樓船贏負倚蒼波。", "如今天險如平地，讐虜深謀只用和。"]'),
('edbc7e44-cf54-4c45-9098-7a39bd3c1aa2','和仁仲舟中三絕  其二','胡寅','宋','宋诗','song-poetry','','[]','支川千百欲歸東，不得江湖不會同。',32,'全唐诗/poet.song.108000.json','["支川千百欲歸東，不得江湖不會同。", "可但中流能擊楫，也知高浪要乘風。"]'),
('7f56f30d-72ba-45ee-a895-f67b9f273449','和仁仲舟中三絕  其三','胡寅','宋','宋诗','song-poetry','','[]','湘君誰識是皇英，占得君山冷淡青。',32,'全唐诗/poet.song.108000.json','["湘君誰識是皇英，占得君山冷淡青。", "月滿湖平相照處，姮娥應得見娉婷。"]'),
('2dfe9948-673f-4f09-b236-13e9eb2c6fdf','歸次湘西元作以詩見迎和之','胡寅','宋','宋诗','song-poetry','','[]','十載重湖閲使星，坐令疲瘵灑然醒。',64,'全唐诗/poet.song.108000.json','["十載重湖閲使星，坐令疲瘵灑然醒。", "從來駿足輕千里，豈但詞源蕩四溟。", "笑我林間投倦翼，辱公江上訪歸舲。", "南山幸有爲隣約，何日來分一半青。"]'),
('8957b6a9-26b0-42dd-a893-c40bc70eee8f','賦永寧嚴老幻菴','胡寅','宋','宋诗','song-poetry','','[]','物理初無妄，云何以幻觀。',48,'全唐诗/poet.song.108000.json','["物理初無妄，云何以幻觀。", "得非心有礙，坐使肉生瘢。", "日月當天久，山河著地安。", "波斯不別寶，學道古來難。"]');
